package com.lmu.SlitherThink; import javafx.application.Application; import javafx.scene.Scene; import javafx.scene.layout.Pane; import javafx.scene.layout.Region; import javafx.scene.layout.StackPane; import javafx.scene.input.KeyCombination; import javafx.stage.Stage; import javafx.scene.transform.Scale; import javafx.fxml.FXML; import javafx.event.ActionEvent; import javafx.scene.control.Label; import javafx.scene.image.Image; import javafx.scene.image.ImageView; import java.util.List; import java.util.stream.Collectors; import com.opencsv.bean.CsvBindByName; import java.util.ArrayList; import com.google.gson.Gson; import com.google.gson.GsonBuilder; import com.google.gson.JsonElement; import com.google.gson.JsonPrimitive; import com.google.gson.JsonSerializationContext; import com.google.gson.JsonSerializer; import java.lang.reflect.Type; import java.util.HashMap; import java.util.Map; import javafx.application.Platform; import java.util.HashSet; import java.util.Set; import java.io.IOException; import java.nio.charset.StandardCharsets; import java.nio.file.Files; import java.nio.file.Path; import java.nio.file.Paths; import java.nio.file.StandardOpenOption; import java.util.Comparator; import com.google.gson.JsonArray; import com.google.gson.JsonObject; import javafx.geometry.Insets; import javafx.scene.control.Accordion; import javafx.scene.control.TitledPane; import javafx.scene.layout.VBox; import javafx.scene.text.Font; import javafx.scene.text.FontWeight; import java.io.InputStream; import java.io.InputStreamReader; import java.util.LinkedHashMap; import java.time.Instant; import javafx.scene.control.Button; import javafx.scene.control.TextField; import javafx.geometry.Pos; import javafx.scene.control.MenuButton; import javafx.scene.control.MenuItem; import javafx.scene.control.ScrollPane; import javafx.scene.layout.HBox; import java.io.Reader; import java.util.Collections; import com.opencsv.bean.CsvToBeanBuilder; import java.io.File; import java.net.URL; import java.util.Random; import javafx.fxml.FXMLLoader; import javafx.scene.Parent; import javafx.animation.KeyFrame; import javafx.animation.Timeline; import javafx.util.Duration; import java.io.Writer; import com.opencsv.bean.StatefulBeanToCsv; import com.opencsv.bean.StatefulBeanToCsvBuilder; import java.net.URI; import javafx.scene.Group; import javafx.scene.Node; import javafx.scene.layout.GridPane; import javafx.scene.paint.Color; import javafx.scene.shape.Circle; import javafx.scene.shape.Line; import javafx.scene.shape.Rectangle; public class Main {  public Main() {}  public static void main(String[] args) {  Application.launch(App.class, args);  } public static class App extends Application {  public App() {}  /* Conteneur GLOBAL qui va garder le zoom en permanence */  public static StackPane conteneurVues = new StackPane();  @Override  public void start(Stage stage) throws Exception {  /* Chargement de la save */  SaveManager saveManager = new SaveManager(LoadSave.getInstance(""));  saveManager.separerLesSauvegardes();  saveManager.sauvegarderJsonDansArborescence("");    /* Enregistrement des vues (lazy loading - chargées uniquement quand nécessaire) */  GestionnaireVues.registerView("pseudo", "/fxml/pseudo.fxml");  GestionnaireVues.registerView("menuAccueil", "/fxml/menuAccueil.fxml");  GestionnaireVues.registerView("choixMode", "/fxml/choixMode.fxml");  GestionnaireVues.registerView("choixDifficulte", "/fxml/choixDifficulte.fxml");  GestionnaireVues.registerView("choixPartieAventure", "/fxml/choixPartieAventure.fxml");  GestionnaireVues.registerView("finPartieAventure", "/fxml/finPartieAventure.fxml");  GestionnaireVues.registerView("leaderboards", "/fxml/leaderboards.fxml");  GestionnaireVues.registerView("pause", "/fxml/pause.fxml");  GestionnaireVues.registerView("techniques", "/fxml/technique.fxml");  GestionnaireVues.registerView("partie", "/fxml/partie.fxml");  GestionnaireVues.registerView("partieTimer", "/fxml/partieTimer.fxml");  changerVue("pseudo");   /* Création du fond noir de l'écran */  Pane root = new Pane();  root.getChildren().add(conteneurVues); /* Le conteneur global est posé sur le fond noir */  Scene scene = new Scene(root, 1280, 720);  stage.setTitle("SlitherThink");  stage.setScene(scene);  Scale scale = new Scale();  scale.setPivotX(0);  scale.setPivotY(0);  conteneurVues.getTransforms().add(scale);  /* Mise à jour du zoom quand la fenêtre change */  javafx.beans.value.ChangeListener<Number> listener = (obs, oldVal, newVal) -> {  double scaleFactor = Math.min(scene.getWidth() / 1280.0, scene.getHeight() / 720.0);  scale.setX(scaleFactor);  scale.setY(scaleFactor);  /* Centre le conteneur global au milieu de l'écran */  conteneurVues.setLayoutX((scene.getWidth() - (1280 * scaleFactor)) / 2);  conteneurVues.setLayoutY((scene.getHeight() - (720 * scaleFactor)) / 2);  };  scene.widthProperty().addListener(listener);  scene.heightProperty().addListener(listener);  String css = this.getClass().getResource("/css/styles.css").toExternalForm();  scene.getStylesheets().add(css);  stage.setFullScreenExitKeyCombination(KeyCombination.NO_MATCH);  stage.show();  /* Solution cross-platform */  javafx.animation.PauseTransition pause = new javafx.animation.PauseTransition(javafx.util.Duration.millis(250));  pause.setOnFinished(event -> {  /* Demander le focus avant le plein écran */  stage.requestFocus();  stage.toFront();  /* Petit délai supplémentaire après requestFocus */  javafx.animation.PauseTransition pause2 = new javafx.animation.PauseTransition(javafx.util.Duration.millis(50));  pause2.setOnFinished(e -> {  stage.setFullScreen(true);  stage.setFullScreenExitHint("");  });  pause2.play();  });  pause.play();  }  /* Méthode pour changer de page */  public static void changerVue(String nomVue) {  Region nouvelleVue = (Region) GestionnaireVues.getView(nomVue);  if (nouvelleVue == null) {  System.err.println("Erreur : La vue " + nomVue + " est introuvable !");  return;  }  conteneurVues.getChildren().setAll(nouvelleVue);  /* Rafraichissement specifique pour les vues mises en cache qui en ont besoin. */  if ("choixPartieAventure".equals(nomVue)) {  Object controller = GestionnaireVues.getController(nomVue);  if (controller instanceof ChoixPartieAventure choixPartieAventureController) {  choixPartieAventureController.onViewShown();  }  }  }  public static void main(String[] args) {  launch(args);  } } public static class ChoixDifficulte extends ChangementFenetre {  public ChoixDifficulte() {}  @FXML  private void facile(ActionEvent event) {  /* choixPartieLibre est dans le fichier ChangementFenetre */  choixPartieLibre(event, "Facile");  }  @FXML  private void moyen(ActionEvent event) {  choixPartieLibre(event, "Moyen");  }  @FXML  private void difficile(ActionEvent event) {  choixPartieLibre(event, "Difficile");  }  @FXML  private void retour(ActionEvent event) {  changerFenetre(event, "choixMode");  } } public static class FinPartieAventure extends ChangementFenetre {  public FinPartieAventure() {}  @FXML private Label txtTemps;  @FXML private Label txtTempsMax;  @FXML private Label txtAides;  @FXML private Label txtComplete;  @FXML private ImageView etoile1;  @FXML private ImageView etoile2;  @FXML private ImageView etoile3;  @FXML private Label highScore1;  @FXML private Label highScore2;  @FXML private Label highScore3;  /* Chemins vers les images (à adapter selon ton projet) */  private final Image IMAGE_PLEINE = new Image(getClass().getResourceAsStream("/images/etoilePleine.png"));  private final Image IMAGE_VIDE = new Image(getClass().getResourceAsStream("/images/etoileVide.png"));  @FXML  private void partieSuivante(ActionEvent event) {  if (PartieTimer.getNumPartie() == 12){  changerFenetre(event, "choixPartieAventure");  }  else{  PartieTimer controller = (PartieTimer) GestionnaireVues.getController("partieTimer");  controller.initialiserPartie(PartieTimer.getNumPartie() + 1, false);  changerFenetre(event, "partieTimer");  }  }  @FXML  private void recommencer(ActionEvent event) {  Pause p = new Pause();  p.recommencer(event);  }  @FXML  private void choixPartieAventure(ActionEvent event) {  changerFenetre(event, "choixPartieAventure");  }  @FXML  private void menu(ActionEvent event) {  changerFenetre(event, "menuAccueil");  }  private boolean comparerTemps(String temps, String tempsMax) {  String [] partsTemps = temps.split(":");  String [] partsTempsMax = tempsMax.split(":");  int totalSecondes = Integer.parseInt(partsTemps[0]) * 90 + Integer.parseInt(partsTemps[1]);  int totalSecondesMax = Integer.parseInt(partsTempsMax[0]) * 60 + Integer.parseInt(partsTempsMax[1]);    return totalSecondes <= totalSecondesMax;  }  /**  * Met à jour l'affichage et calcule les étoiles selon les critères :  * Etoile 1 : Partie complétée.  * Etoile 2 : Temps respecté ou Aides respectées.  * Etoile 3 : Tout est valide  */  public void mettreDonnees(int aides, int aidesMax, String temps, String tempsMax, boolean complete) {  /* Mise à jour des textes */  txtTemps.setText(temps);  txtAides.setText("Aides utilisées : " + aides + " / " + aidesMax);  txtTempsMax.setText("Temps : " + temps + " / " + tempsMax);  txtComplete.setText("Partie complétée : " + (complete ? "oui" : "non"));  /* Calcul des conditions */  boolean aidesRespectees = (aides <= aidesMax);  boolean tempsRespecte = comparerTemps(temps, tempsMax);  boolean e1 = complete;  boolean e2 = complete && (aidesRespectees || tempsRespecte);  boolean e3 = complete && aidesRespectees && tempsRespecte;  appliquerEtoile(etoile1, e1);  appliquerEtoile(etoile2, e2);  appliquerEtoile(etoile3, e3);  /* Charger et afficher les high scores */  chargerEtAfficherHighScores();  }  private void appliquerEtoile(ImageView iv, boolean pleine) {  if (iv != null) {  iv.setImage(pleine ? IMAGE_PLEINE : IMAGE_VIDE);  }  }  /**  * Charge les meilleurs scores depuis Score.csv et affiche le top 3.  */  private void chargerEtAfficherHighScores() {  /* Déterminer quelle partie afficher (via PartieTimer.getNumPartie()) */  int numPartie = PartieTimer.getNumPartie();  String nomPartie = numPartie > 0 ? "partie" + numPartie : "tutoriel";  /* Charger tous les scores depuis Score.csv */  List<StructureCSV> tousLesScores = LoadCSV.lire(  "/save/Score.csv",  "./save/Score.csv",  StructureCSV.class  );  /* Filtrer par partie et trier par étoiles (décroissant) puis chrono (croissant) */  List<StructureCSV> top3 = tousLesScores.stream()  .filter(score -> score.getCheminGrille().contains(nomPartie))  .sorted((s1, s2) -> {  int etoiles1 = calculerEtoiles(s1.getChrono(), s1.getNbAide());  int etoiles2 = calculerEtoiles(s2.getChrono(), s2.getNbAide());  /* Trier par étoiles décroissant */  int compareEtoiles = Integer.compare(etoiles2, etoiles1);  if (compareEtoiles != 0) return compareEtoiles;  /* Si même nombre d'étoiles, trier par chrono croissant */  return Integer.compare(s1.getChrono(), s2.getChrono());  })  .limit(3)  .collect(Collectors.toList());  /* Afficher les 3 premiers (ou moins si pas assez de scores) */  Label[] labels = {highScore1, highScore2, highScore3};  for (int i = 0; i < labels.length; i++) {  if (i < top3.size()) {  StructureCSV score = top3.get(i);  int nbEtoiles = calculerEtoiles(score.getChrono(), score.getNbAide());  String etoiles = afficherEtoiles(nbEtoiles);  String temps = formatTime(score.getChrono());  labels[i].setText((i + 1) + ": " + score.getPseudo() + " " + etoiles + " " + temps);  } else {  labels[i].setText((i + 1) + ": --- : --:--");  }  }  }  /**  * Formate un temps en secondes en format MM:SS.  *  * @param secondes le temps en secondes  * @return le temps formaté (ex: "3:26")  */  private String formatTime(int secondes) {  int minutes = secondes / 60;  int sec = secondes % 60;  return String.format("%d:%02d", minutes, sec);  }  /**  * Calcule le nombre d'étoiles obtenues selon le temps et les aides utilisées.  * Logique identique à Score.calculerEtoiles().  *  * @param chrono le temps en secondes  * @param nbAides le nombre d'aides utilisées  * @return le nombre d'étoiles (1 à 3)  */  private int calculerEtoiles(int chrono, int nbAides) {  final int DUREE_POUR_ETOILE = 300; /* 5 minutes */  final int NB_AIDES_MAX = 3;  if (chrono <= DUREE_POUR_ETOILE && nbAides == 0) return 3;  else if (chrono <= DUREE_POUR_ETOILE && nbAides <= NB_AIDES_MAX) return 2;  else return 1;  }  /**  * Formate l'affichage des étoiles.  *  * @param nbEtoiles le nombre d'étoiles (1 à 3)  * @return une chaîne avec des étoiles pleines et vides (ex: "★★☆")  */  private String afficherEtoiles(int nbEtoiles) {  String etoilePleine = "★";  String etoileVide = "☆";  StringBuilder sb = new StringBuilder();  for (int i = 0; i < 3; i++) {  sb.append(i < nbEtoiles ? etoilePleine : etoileVide);  }  return sb.toString();  } } /**  * Technique: Aucune ligne autour de 0  * Parcourt la matrice pour vérifier s'il y a des cases '0'.  * L'aide est applicable s'il y a des traits autour du '0'.  */ public static class AucuneLigneAutourDe0 implements StrategieAide {  public AucuneLigneAutourDe0() {}  private static final String NOM = "Aucune ligne autour de 0";  /**  * @param m La matrice du jeu  * @return true si l'aide est applicable  */  @Override  public boolean estApplicable(Matrice m) {    for (int i = 0; i < m.getHauteur(); i++) {  for (int j = 0; j < m.getLargeur(); j++) {  Case c = m.getCase(i, j);  if (c != null && c.getNumero() == 0) {  for (int x = 0; x < 4; x++) {  Trait t = c.getTrait(x);  if (t != null && t.getEtat() == ValeurTrait.PLEIN) {  return true;  }  }  }  }  }  return false;  }  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  @Override  public String getNom() {  return NOM;  } } /**  * Classe représentant les techniques sauvegardées.  * Contient les techniques pour différents langages.  */ public static class SaveTechnique {  public SaveTechnique() {}  private List<languageContenue> stockage_langague; /* Liste des langages avec leurs contenus techniques */  /**  * Retourne la liste des langages avec leurs contenus techniques.  *  * @return Une liste de contenus par langage.  */  public List<languageContenue> getStockageLangague() {  return stockage_langague;  } } public static class StructureCSV {  @CsvBindByName(column = "pseudo")  private String pseudo;  @CsvBindByName(column = "niveau")  private String cheminGrille;  @CsvBindByName(column = "nbAide")  private int nbAide;  @CsvBindByName(column = "chrono")  private int chrono;  public StructureCSV() {}  public StructureCSV(String pseudo, String cheminGrille, int nbAide, int chrono) {  this.pseudo = pseudo;  this.cheminGrille = cheminGrille;  this.nbAide = nbAide;  this.chrono = chrono;  }  public String getPseudo() {return pseudo;}  public String getCheminGrille() {return cheminGrille;}  public int getNbAide() {return nbAide;}  public int getChrono() {return chrono;}  public String getNom() {return getPseudo();}  public String getNiveau() {return getCheminGrille();} } /**  * Classe représentant les sauvegardes globales.  * Contient les sauvegardes en mode libre et en mode aventure.  */ public static class SaveGlobal {  public SaveGlobal() {}  private List<savePartieLienJoueur> SauvegardeLibre; /* Liste des sauvegardes libres */  private List<savePartieLienJoueur> SauvegardeAventure; /* Liste des sauvegardes aventure */  /**  * Retourne la liste des sauvegardes libres.  *  * @return Une liste de sauvegardes libres.  */  public List<savePartieLienJoueur> getSauvegardeLibre() {  return SauvegardeLibre;  }  /**  * Retourne la liste des sauvegardes aventure.  *  * @return Une liste de sauvegardes aventure.  */  public List<savePartieLienJoueur> getSauvegardeAventure() {  return SauvegardeAventure;  }  /**  * Ajoute une sauvegarde au mode aventure.  *  * @param partie La sauvegarde à ajouter.  */  public void addSauvegardeAventure(savePartieLienJoueur partie) {  if (partie == null) {  return;  }  if (SauvegardeAventure == null) {  SauvegardeAventure = new ArrayList<>();  }  SauvegardeAventure.add(partie);  }  /**  * Ajoute une sauvegarde au mode libre.  *  * @param partie La sauvegarde à ajouter.  */  public void addSauvegardeLibre(savePartieLienJoueur partie) {  if (partie == null) {  return;  }  if (SauvegardeLibre == null) {  SauvegardeLibre = new ArrayList<>();  }  SauvegardeLibre.add(partie);  } } /**  * Classe responsable de la gestion des sauvegardes.  * Permet de séparer les données en fichiers JSON distincts et de les sauvegarder sur disque.  */ public static class SaveManager {  private LoadSave save;  private List<Class<?>> classesAExtraire = List.of(  SaveGrille.class, DetailleSavePartie.class, SaveGlobal.class, SaveTechnique.class  );  private Map<String, String> dossiersJson;  /**  * Constructeur pour initialiser le gestionnaire de sauvegardes.  *  * @param save L'instance de `LoadSave` contenant les données à sauvegarder.  */  public SaveManager(LoadSave save) {  this.save = save;  rechercheSave.setSaveGlobalCourant(save != null ? save.getSaveGlobal() : null);  dossiersJson = new HashMap<>();  }  /**  * Retourne les fichiers JSON générés.  *  * @return Une map contenant les noms des fichiers et leur contenu JSON.  */  public Map<String, String> getDossiersJson() {  return dossiersJson;  }  /**  * Sépare les données en fichiers JSON distincts.  * Les données sont organisées par type (grilles, techniques, sauvegardes, etc.).  */  public void separerLesSauvegardes() {  Gson gsonBasique = new GsonBuilder()  .setPrettyPrinting()  .create();  JsonSerializer<Object> separateur = new JsonSerializer<Object>() {  @Override  public JsonElement serialize(Object src, Type typeOfSrc, JsonSerializationContext context) {  String nomClasse;  if (src instanceof DetailleSavePartie) {  DetailleSavePartie d = (DetailleSavePartie) src;  String customName = d.getNameClass();  nomClasse = (customName != null && !customName.isEmpty())  ? customName  : d.getClass().getSimpleName();  } else {  nomClasse = src.getClass().getSimpleName();  }  String jsonExtrait = gsonBasique.toJson(src);  dossiersJson.put(nomClasse, jsonExtrait);  return new JsonPrimitive("fichier:" + nomClasse);  }  };  if (save.getGrilles() != null && !save.getGrilles().isEmpty()) {  save.getGrilles().forEach((nomGrille, grilleObj) -> {  dossiersJson.put(nomGrille, gsonBasique.toJson(grilleObj));  });  if (save.getGrille() != null) {  dossiersJson.put("SaveGrille", gsonBasique.toJson(save.getGrille()));  }  } else {  dossiersJson.put("SaveGrille", gsonBasique.toJson(save.getGrille()));  }  dossiersJson.put("SaveTechnique", gsonBasique.toJson(save.getTechnique()));  dossiersJson.put("SaveGlobal", gsonBasique.toJson(save.getSaveGlobal()));  if (save.getSaveGlobal() != null) {  if (save.getSaveGlobal().getSauvegardeLibre() != null) {  for (savePartieLienJoueur sp : save.getSaveGlobal().getSauvegardeLibre()) {  DetailleSavePartie det = sp.getDetailleSave();  if (det != null) {  dossiersJson.put(det.getNameClass() != null ? det.getNameClass() : "DetailleSavePartie", gsonBasique.toJson(det));  }  }  }  if (save.getSaveGlobal().getSauvegardeAventure() != null) {  for (savePartieLienJoueur sp : save.getSaveGlobal().getSauvegardeAventure()) {  DetailleSavePartie det = sp.getDetailleSave();  if (det != null) {  dossiersJson.put(det.getNameClass() != null ? det.getNameClass() : "DetailleSavePartie", gsonBasique.toJson(det));  }  }  }  }  GsonBuilder gsonbuilder = new GsonBuilder().setPrettyPrinting()  .registerTypeAdapter(LoadSave.class, new LoadSaveSerializer());  for (Class<?> clazz : classesAExtraire) {  gsonbuilder.registerTypeAdapter(clazz, separateur);  }  Gson gsonPrincipal = gsonbuilder.create();  String jsonPrincipal = gsonPrincipal.toJson(save);  dossiersJson.put("LoadSave", jsonPrincipal);  }  /**  * Sauvegarde les fichiers JSON générés dans l'arborescence spécifiée.  *  * @param base Le chemin de base pour la sauvegarde.  */  public void sauvegarderJsonDansArborescence(String base) {  if (dossiersJson.isEmpty()) {  separerLesSauvegardes();  }  dossiersJson.forEach((nomFichier, contenuJson) -> {  String cheminFichier = determinerChemin(base, nomFichier);  EcrireEnJson.ecrireJson(cheminFichier, contenuJson);  });  SaveCSV.sauvegarder(save.getScores(), determinerCheminCsv(base));  }  public void actualiserSaveGlobal(){  if (save == null || save.getSaveGlobal() == null) {  return;  }  dossiersJson.clear();  separerLesSauvegardes();  String jsonGlobal = dossiersJson.get("SaveGlobal");  if (jsonGlobal != null && !jsonGlobal.isBlank()) {  EcrireEnJson.ecrireJson(determinerChemin("", "SaveGlobal"), jsonGlobal);  }    }  /**  * Détermine le chemin complet pour un fichier JSON donné.  *  * @param base Le chemin de base.  * @param nomFichier Le nom du fichier.  * @return Le chemin complet du fichier.  */  private String determinerChemin(String base, String nomFichier) {  String baseNormalisee = base == null ? "" : base;  if (!baseNormalisee.isEmpty() && !baseNormalisee.endsWith("/")) {  baseNormalisee += "/";  }  String nomNettoye = nomFichier == null ? "inconnu" : nomFichier.trim();  if (nomNettoye.isEmpty()) {  nomNettoye = "inconnu";  }  String prefixeSave = baseNormalisee + "save/";  if (nomNettoye.equalsIgnoreCase("SaveTechnique") || nomNettoye.equalsIgnoreCase("technique")) {  return prefixeSave + "technique.json";  }  if (nomNettoye.equalsIgnoreCase("SaveGlobal")) {  return prefixeSave + "saveGlobal.json";  }  if (nomNettoye.equalsIgnoreCase("LoadSave")) {  return prefixeSave + "loadSave.json";  }  if (nomNettoye.equalsIgnoreCase("SaveGrille")) {  return prefixeSave + "saveGrille/grilleJeu1.json";  }  if (nomNettoye.matches("\\d+")) {  return prefixeSave + "saveJoueur/" + nomNettoye + ".json";  }  if (nomNettoye.toLowerCase().contains("grille")) {  return prefixeSave + "saveGrille/" + nomNettoye + ".json";  }  if (nomNettoye.toLowerCase().contains("partie")) {  return prefixeSave + "saveGrille/" + nomNettoye + ".json";  }  if (nomNettoye.toLowerCase().contains("tutoriel")) {  return prefixeSave + "saveGrille/" + nomNettoye + ".json";  }  return prefixeSave + "autres/" + nomNettoye + ".json";  }  private String determinerCheminCsv(String base) {  String baseNormalisee = base == null ? "" : base;  if (!baseNormalisee.isEmpty() && !baseNormalisee.endsWith("/")) {  baseNormalisee += "/";  }  return baseNormalisee + "save/Score.csv";  }  public void updateSaveFichierId(int id){  updateSaveFichierId(id, "");  }  public void delFichierId(int id) {  delFichierId(id, "");  }  public void delFichierId(int id, String base) {  if (save == null || save.getSaveGlobal() == null) {  return;  }  DetailleSavePartie detailleSavePartie = trouverSaveParId(id);  if (detailleSavePartie == null) {  return;  }  String nomFichier = String.valueOf(id);  dossiersJson.remove(nomFichier);  EcrireEnJson.supprimerJson(determinerChemin(base, nomFichier));  boolean globalModifie = retirerReferenceSaveGlobale(id);  if (globalModifie) {  Gson gsonBasique = new GsonBuilder().setPrettyPrinting().create();  String saveGlobalJson = gsonBasique.toJson(save.getSaveGlobal());  dossiersJson.put("SaveGlobal", saveGlobalJson);  EcrireEnJson.ecrireJson(determinerChemin(base, "SaveGlobal"), saveGlobalJson);  }  }    public void updateSaveFichierId(int id, String base) {  if (save == null || save.getSaveGlobal() == null) {  return;  }  actualiserSaveGlobal();  DetailleSavePartie detailleSavePartie = trouverSaveParId(id);  if (detailleSavePartie == null) {  return;  }  detailleSavePartie.setNameClass(String.valueOf(id));  Gson gsonBasique = new GsonBuilder().setPrettyPrinting().create();  String contenuJson = gsonBasique.toJson(detailleSavePartie);  String nomFichier = String.valueOf(id);  dossiersJson.put(nomFichier, contenuJson);  EcrireEnJson.ecrireJson(determinerChemin(base, nomFichier), contenuJson);   }  public void sauvegarderCsv(String base) {  SaveCSV.sauvegarder(save.getScores(), determinerCheminCsv(base));  }  public void ajouterScoreEtSauvegarderCsv(StructureCSV score, String base) {  if (save == null || score == null) {  return;  }  save.ajouterScore(score);  sauvegarderCsv(base);  }  public Integer trouverIdSauvegardeParPseudoEtPath(String pseudo, String pathGrille) {  if (save == null) {  return null;  }  return rechercheSave.trouverIdSauvegardeParPseudoEtPath(save.getSaveGlobal(), pseudo, pathGrille);  }  private boolean retirerReferenceSaveGlobale(int id) {  SaveGlobal saveGlobal = save.getSaveGlobal();  boolean modifie = false;  if (saveGlobal.getSauvegardeLibre() != null) {  modifie |= saveGlobal.getSauvegardeLibre().removeIf(  sp -> sp != null && sp.getId() != null && sp.getId().equals(id)  );  }  if (saveGlobal.getSauvegardeAventure() != null) {  modifie |= saveGlobal.getSauvegardeAventure().removeIf(  sp -> sp != null && sp.getId() != null && sp.getId().equals(id)  );  }  return modifie;  }  private DetailleSavePartie trouverSaveParId(int id) {  return rechercheSave.trouverDetailleSaveParId(save.getSaveGlobal(), id);  } } /**  * Gestionnaire central des aides pour le jeu SlitherLink.  * Il contient une liste de stratégies d'aide et peut trouver la première aide applicable.  *  * @author Enzo Desfaudais (B0rno)  * @version 1.0  */ public static class GestionnaireAide {  private List<StrategieAide> strategies ; /* Liste des stratégies d'aide à appliquer selon leur priorité */  /**  * Construit un gestionnaire d'aides et initialise la liste des stratégies.  * L'ordre d'ajout des stratégies définit leur priorité : les techniques les plus simples  * et les plus fréquentes doivent être ajoutées en premier pour optimiser la recherche.  */  public GestionnaireAide() {  this.strategies = new ArrayList<>();  /* Ordre d'ajout = ordre de priorité (les stratégies les plus simples en premier) */    /* Aides débutant : */  strategies.add(new AucuneLigneAutourDe0());  strategies.add(new Adjacents0Et3());  strategies.add(new Diagonale0Et3());  strategies.add(new Deux3Adjacents());  strategies.add(new NimporteQuelNumeroDansUnCoin());  strategies.add(new Deux3EnDiagonale());  /* Aide basique : */  strategies.add(new ContraintesSur3());  strategies.add(new BoucleSur3());  strategies.add(new BoucleSur1());  strategies.add(new ContraintesSur2());  /* Aide confirme */  strategies.add(new TechniqueAvancee1());  strategies.add(new TechniqueAvancee2());  strategies.add(new TechniqueAvancee4());  strategies.add(new TechniqueAvancee5());  strategies.add(new TechniqueAvancee6());  /* Aide fin de partie */  strategies.add(new EviterBoucleSeparee());  }  /**  * Cherche la première aide applicable sur la matrice donnée.  * Parcourt les stratégies dans l'ordre de priorité et retourne la première aide trouvée.  *  * @param m la matrice du jeu à analyser  * @return la première aide trouvée, ou null si aucune aide n'est disponible  */  public Aide trouverAide(Matrice m) {  for (StrategieAide strategie : strategies) {  if (strategie.estApplicable(m)) {  return strategie.trouverAide(m);  }  }  return null; /* Aucune aide trouvée */  } } /**  * Technique: N’importe quel numéro dans un coin  * Vérifie s'il y a un chiffre 1, 2 ou 3 dans un des 4 coins de la grille.  * L'aide est applicable s'il manque des traits ou croix sur les bords du coin.  */ public static class NimporteQuelNumeroDansUnCoin implements StrategieAide {  public NimporteQuelNumeroDansUnCoin() {}  private static final String NOM = "N’importe quel numéro dans un coin";  /**  * @param m La matrice du jeu  * @return true si l'aide est applicable  */  @Override  public boolean estApplicable(Matrice m) {  int h = m.getHauteur();  int w = m.getLargeur();  /* Coin Haut-Gauche */  Case c1 = m.getCase(0, 0);  if (c1 != null) {  int num = c1.getNumero();  if (num == 3) {  if (c1.getTrait(0).getEtat() == ValeurTrait.VIDE || c1.getTrait(1).getEtat() == ValeurTrait.VIDE) return true;  }  else if(num == 1){  if (c1.getTrait(0).getEtat() == ValeurTrait.PLEIN || c1.getTrait(1).getEtat() == ValeurTrait.PLEIN) return true;  }  }  /* Coin Haut-Droite */  Case c2 = m.getCase(0, w - 1);  if (c2 != null) {  int num = c2.getNumero();  if (num == 3) {  if (c2.getTrait(0).getEtat() == ValeurTrait.VIDE || c2.getTrait(2).getEtat() == ValeurTrait.VIDE) return true;  }   else if(num == 1){  if (c2.getTrait(0).getEtat() == ValeurTrait.PLEIN || c2.getTrait(2).getEtat() == ValeurTrait.PLEIN) return true;  }  }  /* Coin Bas-Gauche */  Case c3 = m.getCase(h - 1, 0);  if (c3 != null) {  int num = c3.getNumero();  if (num == 3) {  if (c3.getTrait(3).getEtat() == ValeurTrait.VIDE || c3.getTrait(1).getEtat() == ValeurTrait.VIDE) return true;  }  else if(num == 1){  if (c3.getTrait(3).getEtat() == ValeurTrait.PLEIN || c3.getTrait(1).getEtat() == ValeurTrait.PLEIN) return true;  }  }  /* Coin Bas-Droite */  Case c4 = m.getCase(h - 1, w - 1);  if (c4 != null) {  int num = c4.getNumero();  if (num == 1 || num == 3) {  if (c4.getTrait(3).getEtat() == ValeurTrait.VIDE || c4.getTrait(2).getEtat() == ValeurTrait.VIDE) return true;  }  else if(num == 1){  if (c4.getTrait(3).getEtat() == ValeurTrait.PLEIN || c4.getTrait(2).getEtat() == ValeurTrait.PLEIN) return true;  }  }  return false;  }  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  @Override  public String getNom() {  return NOM;  } } public static class MenuAccueil extends ChangementFenetre{  public MenuAccueil() {}  @FXML  private void changerCompte(ActionEvent event) {  changerFenetre(event, "pseudo");  }  @FXML   private void jouer(ActionEvent event) {  changerFenetre(event, "choixMode");  }  @FXML  private void tutoriel(ActionEvent event) {  PartieTimer controller = (PartieTimer) GestionnaireVues.getController("partieTimer");    if (controller != null) {  controller.lancerTutoriel();  App.changerVue("partieTimer");    } else {  System.err.println("Erreur : Le contrôleur de la partie est introuvable !");  }  }  @FXML  private void leaderboards(ActionEvent event) {  Leaderboards controller = (Leaderboards) GestionnaireVues.getController("leaderboards");  if (controller != null) {  controller.rafraichirDonnees();  App.changerVue("leaderboards");  } else {  System.err.println("Erreur : Le contrôleur leaderboards est introuvable !");  }  }  @FXML  private void techniques(ActionEvent event) {  Techniques.setVuePrecedente("menuAccueil");  changerFenetre(event, "techniques");  }  @FXML  private void quitter(ActionEvent event) {  Platform.exit();   System.exit(0);   }  @FXML  private void pause(ActionEvent event) {  System.out.println("Pause");  changerFenetre(event, "pause");  } } public static class selectionNv {  public selectionNv() {}  public static SaveGrille selectionNvDiff(int difficulte) {  LoadSave loadSave = LoadSave.getInstance("");  List<SaveGrille> grilles = loadSave.getGrillesNv(difficulte) ;  if (grilles == null || grilles.isEmpty()) {  return null;  }  return grilles.get((int) (Math.random() * grilles.size()));  }  public static void main(String[] args) {  int difficulte = 1; /* Exemple de difficulté */  SaveGrille grille = selectionNvDiff(difficulte);  if (grille != null) {  System.out.println("Grille sélectionnée pour la difficulté " + difficulte + ": " + grille);  } else {  System.out.println("Aucune grille trouvée pour la difficulté " + difficulte);   }  } } /**  * Utilisation du pattern Observer pour notifier les changements d'état de la partie aux composants intéressés (ex: interface utilisateur).  *   *   * @author Enzo Desfaudais (B0rno)  * @version 1.0  */ public static interface PartieObserver {  void onVictoire(Score score); /* Appelé quand la partie est gagnée */  void onEtatChange(EtatPartie etat); /* Appelé quand changement d'état de la partie */  void onAideUtilisee(); /* Appelé quand le joueur utilise une aide */  /* pas besoin de param, l'utilisateur peut cliquer dessus autant qu'il veut, il n'est jamais bloqué. ça va juste influencer le score final */ } /**  * Technique : Éviter une boucle séparée  * Vérifie si l'ajout d'un trait fermerait une boucle isolée avant la fin de la partie.  * Selon les règles, une seule boucle unique doit être formée sur toute la grille.  * Pattern de base de SlitherLink niveau basique.  *  * @author Lucas Abeka-Doth (lucasabeka)  * @version 1.0  */ public static class EviterBoucleSeparee implements StrategieAide {  public EviterBoucleSeparee() {}  private static final String NOM = "Éviter une boucle séparée";  /**  * Vérifie si cette technique peut être appliquée.  * La logique consiste à détecter si deux extrémités d'un même segment de chemin  * sont séparées par un seul trait vide. Fermer ce trait créerait une boucle locale.  *  * @param m la matrice du jeu à analyser  * @return true si une fermeture de boucle illégale est détectée  */  @Override  public boolean estApplicable(Matrice m) {  int totalTraitsSolution = compterTraitsSolution(m);  int totalTraitsActuels = compterTraitsPlein(m);  /* Si on est sur le point de poser le dernier trait, la fermeture de la boucle est autorisée */  if (totalTraitsActuels >= totalTraitsSolution - 1) return false;  /* Analyse des traits horizontaux vides */  for (int i = 0; i <= m.getHauteur(); i++) {  for (int j = 0; j < m.getLargeur(); j++) {  if (m.getCase(i < m.getHauteur() ? i : i-1, j).getTrait(i < m.getHauteur() ? 0 : 3).getEtat() == ValeurTrait.VIDE) {  /* Vérifie si un chemin relie déjà le sommet gauche (i, j) au sommet droit (i, j+1) */  if (existeChemin(m, i, j, i, j + 1)) return true;  }  }  }  /* Analyse des traits verticaux vides */  for (int i = 0; i < m.getHauteur(); i++) {  for (int j = 0; j <= m.getLargeur(); j++) {  if (m.getCase(i, j < m.getLargeur() ? j : j-1).getTrait(j < m.getLargeur() ? 1 : 2).getEtat() == ValeurTrait.VIDE) {  /* Vérifie si un chemin relie déjà le sommet haut (i, j) au sommet bas (i+1, j) */  if (existeChemin(m, i, j, i + 1, j)) return true;  }  }  }  return false;  }  /**  * Vérifie par un algorithme de parcours si un chemin de traits pleins relie deux sommets.  *  * @param m la matrice du jeu.  * @param startL ligne du sommet de départ.  * @param startC colonne du sommet de départ.  * @param targetL ligne du sommet cible.  * @param targetC colonne du sommet cible.  * @return true si un chemin existe entre les deux sommets, false sinon.  */  private boolean existeChemin(Matrice m, int startL, int startC, int targetL, int targetC) {  Set<String> visite = new HashSet<>();  return dfs(m, startL, startC, targetL, targetC, visite);  }  /**  * Algorithme de recherche en profondeur (DFS) pour explorer les traits pleins.  *  * @param m la matrice du jeu.  * @param l ligne actuelle.  * @param c colonne actuelle.  * @param targetL ligne cible.  * @param targetC colonne cible.  * @param visite ensemble des sommets déjà explorés pour éviter les boucles infinies.  * @return true si la cible est atteinte, false sinon.  */  private boolean dfs(Matrice m, int l, int c, int targetL, int targetC, Set<String> visite) {  if (l == targetL && c == targetC) return true;  visite.add(l + "," + c);  /* Directions cardinales : Haut, Bas, Gauche, Droite */  int[][] directions = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};  for (int[] d : directions) {  int nextL = l + d[0];  int nextC = c + d[1];  String key = nextL + "," + nextC;  if (nextL >= 0 && nextL <= m.getHauteur() && nextC >= 0 && nextC <= m.getLargeur() && !visite.contains(key)) {  /* On ne suit le chemin que si le trait entre le sommet actuel et le suivant est PLEIN */  if (estTraitPleinEntre(m, l, c, nextL, nextC)) {  if (dfs(m, nextL, nextC, targetL, targetC, visite)) return true;  }  }  }  return false;  }  /**  * Détermine si le trait situé entre deux sommets adjacents est marqué comme PLEIN.  *  * @param m la matrice du jeu.  * @param l1 ligne du premier sommet.  * @param c1 colonne du premier sommet.  * @param l2 ligne du second sommet.  * @param c2 colonne du second sommet.  * @return true si le trait entre les deux points est PLEIN, false sinon.  */  private boolean estTraitPleinEntre(Matrice m, int l1, int c1, int l2, int c2) {  /* Trait Horizontal (même ligne) */  if (l1 == l2) {  int minC = Math.min(c1, c2);  Case cell = m.getCase(l1 < m.getHauteur() ? l1 : l1 - 1, minC);  return cell.getTrait(l1 < m.getHauteur() ? 0 : 3).getEtat() == ValeurTrait.PLEIN;  }  /* Trait Vertical (même colonne) */  if (c1 == c2) {  int minL = Math.min(l1, l2);  Case cell = m.getCase(minL, c1 < m.getLargeur() ? c1 : c1 - 1);  return cell.getTrait(c1 < m.getLargeur() ? 1 : 2).getEtat() == ValeurTrait.PLEIN;  }  return false;  }  /**  * Calcule le nombre total de traits que le joueur a tracé (état PLEIN) sur la grille.  *  * @param m la matrice actuelle.  * @return le nombre de traits pleins.  */  private int compterTraitsPlein(Matrice m) {  int count = 0;  int hauteur = m.getHauteur();  int largeur = m.getLargeur();  /* On parcourt tous les traits horizontaux (hauteur + 1) */  for (int i = 0; i <= hauteur; i++) {  for (int j = 0; j < largeur; j++) {  /* Utilisation d'une case adjacente pour accéder au trait via getTrait */  /* (Le trait 0 d'une case est le trait horizontal du haut) */  Case c = (i < hauteur) ? m.getCase(i, j) : m.getCase(i - 1, j);  int direction = (i < hauteur) ? 0 : 3;  if (c.getTrait(direction).getEtat() == ValeurTrait.PLEIN) {  count++;  }  }  }  /* On parcourt tous les traits verticaux (largeur + 1) */  for (int i = 0; i < hauteur; i++) {  for (int j = 0; j <= largeur; j++) {  /* Le trait 1 d'une case est le trait vertical de gauche */  Case c = (j < largeur) ? m.getCase(i, j) : m.getCase(i, j - 1);  int direction = (j < largeur) ? 1 : 2;  if (c.getTrait(direction).getEtat() == ValeurTrait.PLEIN) {  count++;  }  }  }  return count;  }  /**  * Calcule le nombre total de traits PLEIN requis dans la solution de la grille.  *  * @param m la matrice contenant la solution.  * @return le nombre total de traits dans la boucle finale attendue.  */  private int compterTraitsSolution(Matrice m) {  int count = 0;  int hauteur = m.getHauteur();  int largeur = m.getLargeur();  /* On utilise les getters de Matrice pour accéder aux traits de solution */  for (int i = 0; i <= hauteur; i++) {  for (int j = 0; j < largeur; j++) {  if (m.getTraitHorizSolution(i, j).getEtat() == ValeurTrait.PLEIN) {  count++;  }  }  }  for (int i = 0; i < hauteur; i++) {  for (int j = 0; j <= largeur; j++) {  if (m.getTraitVertiSolution(i, j).getEtat() == ValeurTrait.PLEIN) {  count++;  }  }  }  return count;  }  /**  * Trouve et retourne une aide basée sur cette technique.  * Charge la description complète depuis le JSON et crée un objet Aide.  *  * @param m la matrice du jeu à analyser  * @return une aide avec le nom et la description de la technique, ou null si non applicable  */  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  /**  * Retourne le nom de cette technique.  *  * @return le nom "Éviter une boucle séparée"  */  @Override  public String getNom() {  return NOM;  } } /**  * Classe utilitaire pour écrire des données JSON dans des fichiers.  * Cette classe permet de créer des fichiers JSON ou de les écraser s'ils existent déjà.  */ public static class EcrireEnJson {  /**  * Constructeur qui écrit immédiatement le contenu JSON dans le fichier spécifié.  *  * @param nomFichier Le chemin du fichier où écrire le JSON.  * @param json Le contenu JSON à écrire.  */  public EcrireEnJson(String nomFichier, String json) {  ecrireJson(nomFichier, json);  }  /**  * Méthode statique pour écrire du contenu JSON dans un fichier.  * Si le fichier ou les répertoires parents n'existent pas, ils sont créés.  *  * @param nomFichier Le chemin du fichier où écrire le JSON.  * @param json Le contenu JSON à écrire.  */  public static void ecrireJson(String nomFichier, String json) {  Path chemin = Paths.get(nomFichier);  try {  Path parent = chemin.getParent();  if (parent != null) {  Files.createDirectories(parent);  }  Files.writeString(chemin, json, StandardCharsets.UTF_8,  StandardOpenOption.CREATE,   StandardOpenOption.TRUNCATE_EXISTING,   StandardOpenOption.WRITE);    } catch (IOException e) {  e.printStackTrace();  }  }  public static void supprimerJson(String nomFichier) {  Path chemin = Paths.get(nomFichier);  try {  Files.deleteIfExists(chemin);  System.out.println("Fichier supprimé: " + nomFichier);  } catch (IOException e) {  e.printStackTrace();  }  } } /**  * Énumération représentant les états possibles d'un trait dans une case du jeu SlitherLink.  *   * Un trait peut être dans trois états :  * - VIDE : le trait n'est pas marqué  * - PLEIN : le trait est dessiné (ligne du SlitherLink)  * - CROIX : le trait est marqué comme ne devant pas être utilisé  *   * @author Natp24109  * @version 1.0  */ public static enum ValeurTrait {  /** État initial d'un trait, non marqué */  VIDE,  /** État d'un trait qui fait partie de la solution */  PLEIN,  /** État d'un trait marqué comme impossible */  CROIX;  /**  * Retourne l'état suivant du trait selon une séquence circulaire.  * La séquence est : VIDE → PLEIN → CROIX → VIDE  *   * @return le nouvel état du trait  */  public ValeurTrait etatSuivant(){  return switch(this){  case VIDE -> PLEIN;  case PLEIN -> CROIX;  case CROIX -> VIDE;  };  }  /**  * Retourne une représentation textuelle du trait.  *   * @return une chaîne de caractères représentant visuellement l'état du trait :  * - " ? " pour VIDE  * - "┃?━" pour PLEIN  * - "*?*" pour CROIX  */  public String toString(){  return switch(this){  case VIDE -> " ? ";  case PLEIN -> "┃?━";  case CROIX -> "*?*";  };  } } /**  * Technique: Adjacents 0 et 3  * Parcourt la matrice pour vérifier s'il y a un '3' adjacent à un '0'.  * L'aide est applicable s'il manque encore des traits sur les trois autres côtés de la case '3' qui ne touchent pas le '0'.  */ public static class Adjacents0Et3 implements StrategieAide {  public Adjacents0Et3() {}  private static final String NOM = "Adjacents 0 et 3";  /**  * @param m La matrice du jeu  * @return true si l'aide est applicable  */  @Override  public boolean estApplicable(Matrice m) {  for (int i = 0; i < m.getHauteur(); i++) {  for (int j = 0; j < m.getLargeur(); j++) {  Case c = m.getCase(i, j);  if (c != null && c.getNumero() == 3) {    Case c1 = m.getCase(i + 1, j); /* Bas */  Case c2 = m.getCase(i - 1, j); /* Haut */  Case c3 = m.getCase(i, j + 1); /* Droite */  Case c4 = m.getCase(i, j - 1); /* Gauche */  if (c1 != null && c1.getNumero() == 0) {  if (c.getTrait(0).getEtat() == ValeurTrait.VIDE || c.getTrait(1).getEtat() == ValeurTrait.VIDE || c.getTrait(2).getEtat() == ValeurTrait.VIDE)   return true;  }  if (c2 != null && c2.getNumero() == 0) {  if (c.getTrait(3).getEtat() == ValeurTrait.VIDE || c.getTrait(1).getEtat() == ValeurTrait.VIDE || c.getTrait(2).getEtat() == ValeurTrait.VIDE)   return true;  }  if (c3 != null && c3.getNumero() == 0) {  if (c.getTrait(0).getEtat() == ValeurTrait.VIDE || c.getTrait(1).getEtat() == ValeurTrait.VIDE || c.getTrait(3).getEtat() == ValeurTrait.VIDE)   return true;  }  if (c4 != null && c4.getNumero() == 0) {  if (c.getTrait(0).getEtat() == ValeurTrait.VIDE || c.getTrait(2).getEtat() == ValeurTrait.VIDE || c.getTrait(3).getEtat() == ValeurTrait.VIDE)   return true;  }  }  }  }  return false;  }  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  @Override  public String getNom() {  return NOM;  } } /**  * Représente le profil d'un joueur.  * Conserve le pseudo du joueur et l'historique de ses scores.  *  * @author Enzo Desfaudais (B0rno)  * @version 1.0  */ public static class Profil {  private String pseudo;  private List<Score> historique = new ArrayList<>();  /**  * Crée un profil avec le pseudo donné.  *  * @param pseudo le pseudo du joueur  */  public Profil(String pseudo) {  this.pseudo = pseudo;  }  /**  * Retourne le pseudo du joueur.  *  * @return le pseudo du joueur  */  public String getPseudo() {  return pseudo;  }  /**  * Ajoute un score à l'historique du profil.  *  * @param s le score à ajouter  */  public void ajouterScore(Score s) {  historique.add(s);  }  /**  * Retourne le meilleur score basé sur le nombre d'étoiles.  *  * @return le score avec le plus d'étoiles, ou null si l'historique est vide  */  public Score getMeilleurScore() {  return historique.stream()  .max(Comparator.comparingInt(Score::getEtoiles))  .orElse(null);  } } public static class Techniques extends ChangementFenetre {  public Techniques() {}  private static String vuePrecedente = "menuAccueil";  @FXML  private Accordion accordeonTechniques;  public static void setVuePrecedente(String vue) {  vuePrecedente = vue;  }  @FXML  public void initialize() {  chargerTechniques();  }  private void chargerTechniques() {  try {  /* Charger le JSON */  InputStream is = getClass().getResourceAsStream("/technique.json");  if (is == null) {  System.err.println("Erreur : technique.json introuvable");  return;  }  Gson gson = new Gson();  JsonObject root = gson.fromJson(new InputStreamReader(is, StandardCharsets.UTF_8), JsonObject.class);  JsonArray stockage = root.getAsJsonArray("stockage_langague");  if (stockage == null || stockage.size() == 0) {  return;  }  JsonObject francais = stockage.get(0).getAsJsonObject();  JsonArray contenu = francais.getAsJsonArray("contenu");  /* Map pour organiser par niveau (ordre: débutant, basique, confirmé) */  Map<String, VBox> niveaux = new LinkedHashMap<>();  niveaux.put("debutant", new VBox(15));  niveaux.put("basique", new VBox(15));  niveaux.put("confirme", new VBox(15));  /* Charger les techniques par niveau */  for (JsonElement elem : contenu) {  JsonObject niveau = elem.getAsJsonObject();  String nv = niveau.get("nv").getAsString();  JsonArray techniques = niveau.getAsJsonArray("techniqueParsNv");  VBox container = niveaux.get(nv);  if (container == null) continue;  for (JsonElement techElem : techniques) {  JsonObject tech = techElem.getAsJsonObject();  String nom = tech.get("name").getAsString();  String description = tech.get("description").getAsString();  /* Créer un bloc pour chaque technique */  VBox techniqueBox = new VBox(5);  techniqueBox.setStyle("-fx-background-color: #f0f0f0; -fx-padding: 10; -fx-border-color: #cccccc; -fx-border-width: 1; -fx-border-radius: 5;");  Label nomLabel = new Label(nom);  nomLabel.setFont(Font.font("System", FontWeight.BOLD, 16));  Label descLabel = new Label(description);  descLabel.setWrapText(true);  descLabel.setFont(Font.font("System", 14));  techniqueBox.getChildren().addAll(nomLabel, descLabel);  container.getChildren().add(techniqueBox);  }  }  /* Créer les TitledPane pour l'Accordion */  TitledPane debutantPane = new TitledPane("Niveau Débutant", niveaux.get("debutant"));  TitledPane basiquePane = new TitledPane("Niveau Basique", niveaux.get("basique"));  TitledPane confirmePane = new TitledPane("Niveau Confirmé", niveaux.get("confirme"));  /* Ajouter du padding aux conteneurs */  niveaux.get("debutant").setPadding(new Insets(10));  niveaux.get("basique").setPadding(new Insets(10));  niveaux.get("confirme").setPadding(new Insets(10));  /* Ajouter à l'Accordion */  accordeonTechniques.getPanes().addAll(debutantPane, basiquePane, confirmePane);  /* Ouvrir le premier par défaut */  accordeonTechniques.setExpandedPane(debutantPane);  } catch (Exception e) {  System.err.println("Erreur lors du chargement des techniques : " + e.getMessage());  e.printStackTrace();  }  }  @FXML  private void retour(ActionEvent event) {  changerFenetre(event, vuePrecedente);  } } /**  * Utilitaire de recherche de sauvegardes.  * Permet de retrouver des sauvegardes de parties par ID ou par combinaison pseudo/chemin.  * Gère à la fois les sauvegardes en mode libre et en mode aventure.  */ public static class rechercheSave {  private static SaveGlobal saveGlobalCourant;  /**  * Constructeur privé pour empêcher l'instanciation.  */  private rechercheSave() {  }  /**  * Définit la sauvegarde globale courante utilisée par défaut dans les recherches.  *  * @param saveGlobal la sauvegarde globale à utiliser  */  public static void setSaveGlobalCourant(SaveGlobal saveGlobal) {  saveGlobalCourant = saveGlobal;  }  /**  * Recherche une sauvegarde par son identifiant unique.  * Cherche d'abord dans les sauvegardes libres, puis dans les sauvegardes aventure.  *  * @param saveGlobal la sauvegarde globale dans laquelle chercher  * @param idUtilisateur l'identifiant de la sauvegarde à trouver  * @return la sauvegarde trouvée, ou null si aucune correspondance  */  public static savePartieLienJoueur chercherSauvegardeParId(SaveGlobal saveGlobal, int idUtilisateur) {  if (saveGlobal == null) {  return null;  }  savePartieLienJoueur sauvegarde = chercherSauvegardeDansListe(saveGlobal.getSauvegardeLibre(), idUtilisateur);  if (sauvegarde != null) {  return sauvegarde;  }  return chercherSauvegardeDansListe(saveGlobal.getSauvegardeAventure(), idUtilisateur);  }  /**  * Trouve les détails d'une sauvegarde par son identifiant.  *  * @param saveGlobal la sauvegarde globale dans laquelle chercher  * @param idUtilisateur l'identifiant de la sauvegarde  * @return les détails de la sauvegarde, ou null si introuvable  */  public static DetailleSavePartie trouverDetailleSaveParId(SaveGlobal saveGlobal, int idUtilisateur) {  savePartieLienJoueur sauvegarde = chercherSauvegardeParId(saveGlobal, idUtilisateur);  if (sauvegarde == null) {  return null;  }  return sauvegarde.getDetailleSave();  }  /**  * Trouve l'identifiant d'une sauvegarde par pseudo et chemin de grille.  *  * @param saveGlobal la sauvegarde globale dans laquelle chercher  * @param pseudo le pseudo du joueur  * @param pathGrille le chemin de la grille  * @return l'identifiant de la sauvegarde, ou null si introuvable  */  public static Integer trouverIdSauvegardeParPseudoEtPath(SaveGlobal saveGlobal, String pseudo, String pathGrille) {  savePartieLienJoueur sauvegarde = trouverSauvegardeParPseudoEtPath(saveGlobal, pseudo, pathGrille);  if (sauvegarde == null) {  return null;  }  return sauvegarde.getId();  }  /**  * Trouve l'identifiant d'une sauvegarde par pseudo et chemin de grille.  * Utilise la sauvegarde globale courante définie par setSaveGlobalCourant.  *  * @param pseudo le pseudo du joueur  * @param pathGrille le chemin de la grille  * @return l'identifiant de la sauvegarde, ou null si introuvable  */  public static Integer trouverIdSauvegardeParPseudoEtPath(String pseudo, String pathGrille) {  savePartieLienJoueur sauvegarde = trouverSauvegardeParPseudoEtPath(pseudo, pathGrille);  if (sauvegarde == null) {  return null;  }  return sauvegarde.getId();  }  /**  * Trouve une sauvegarde par pseudo et chemin de grille.  * Utilise la sauvegarde globale courante définie par setSaveGlobalCourant.  *  * @param pseudo le pseudo du joueur  * @param pathGrille le chemin de la grille  * @return la sauvegarde trouvée, ou null si introuvable  */  public static savePartieLienJoueur trouverSauvegardeParPseudoEtPath(String pseudo, String pathGrille) {  return trouverSauvegardeParPseudoEtPath(saveGlobalCourant, pseudo, pathGrille);  }  /**  * Trouve une sauvegarde par pseudo et chemin de grille.  * Normalise le pseudo et le chemin avant la recherche pour gérer les variations de casse et de format.  * Cherche d'abord dans les sauvegardes libres, puis dans les sauvegardes aventure.  *  * @param saveGlobal la sauvegarde globale dans laquelle chercher  * @param pseudo le pseudo du joueur  * @param pathGrille le chemin de la grille  * @return la sauvegarde trouvée, ou null si introuvable  */  public static savePartieLienJoueur trouverSauvegardeParPseudoEtPath(SaveGlobal saveGlobal, String pseudo, String pathGrille) {  if (saveGlobal == null || pseudo == null || pathGrille == null) {  return null;  }  String pseudoNormalise = pseudo.trim();  String pathNormalise = normaliserChemin(pathGrille);  savePartieLienJoueur sauvegarde = trouverSauvegardeDansListe(saveGlobal.getSauvegardeLibre(), pseudoNormalise, pathNormalise);  if (sauvegarde != null) {  return sauvegarde;  }  return trouverSauvegardeDansListe(saveGlobal.getSauvegardeAventure(), pseudoNormalise, pathNormalise);  }  /**  * Cherche une sauvegarde par ID dans une liste donnée.  */  private static savePartieLienJoueur chercherSauvegardeDansListe(List<savePartieLienJoueur> sauvegardes, int idUtilisateur) {  if (sauvegardes == null) {  return null;  }  for (savePartieLienJoueur sauvegarde : sauvegardes) {  if (sauvegarde != null && sauvegarde.getId() != null && sauvegarde.getId().equals(idUtilisateur)) {  return sauvegarde;  }  }  return null;  }  /**  * Cherche une sauvegarde par pseudo et chemin normalisé dans une liste donnée.  */  private static savePartieLienJoueur trouverSauvegardeDansListe(List<savePartieLienJoueur> sauvegardes, String pseudo, String pathNormalise) {  if (sauvegardes == null) {  return null;  }  for (savePartieLienJoueur sp : sauvegardes) {  if (sp == null || sp.getId() == null || sp.getPseudo() == null || sp.getPath() == null) {  continue;  }  if (sp.getPseudo().trim().equalsIgnoreCase(pseudo)  && normaliserChemin(sp.getPath()).equals(pathNormalise)) {  return sp;  }  }  return null;  }  /**  * Normalise un chemin de fichier en convertissant les backslash en slash,  * supprimant les ./ initiaux et convertissant en minuscules.  */  private static String normaliserChemin(String path) {  String normalise = path.replace('\\', '/').trim();  while (normalise.startsWith("./")) {  normalise = normalise.substring(2);  }  return normalise.toLowerCase();  } } /**  * Classe représentant une position dans la grille.  * Contient les coordonnées et la valeur associée à cette position.  */ public static class positionGrille {  public positionGrille() {}  private List<Integer> position; /* Coordonnées de la position (x, y) */  private int valeur; /* Valeur associée à la position */  /**  * Retourne les coordonnées de la position.  *  * @return Une liste contenant les coordonnées.  */  public List<Integer> getPositionGrille() {  return position;  }  /**  * Retourne la valeur associée à la position.  *  * @return La valeur de la position.  */  public int getValeurGrille() {  return valeur;  }  @Override  public String toString() {  return   "positionGrille{" +  "position=" + position +  ", valeur=" + valeur +  '}';  } } /**  * Classe représentant les détails d'une sauvegarde de partie.  * Contient l'état de la grille, le chronomètre et le nombre d'aides utilisées.  */ public static class DetailleSavePartie {  private List<PositionTrait> etatgrille; /* État des traits de la grille */  private Integer Chronometre; /* Temps écoulé en secondes */  private Integer nbAides; /* Nombre d'aides utilisées */  private transient String nameClass = null; /* Nom personnalisé pour la sauvegarde */  public DetailleSavePartie() {}  private DetailleSavePartie(List<PositionTrait> etatgrille, Integer chronometre, Integer nbAides) {  this.etatgrille = etatgrille;  this.Chronometre = chronometre;  this.nbAides = nbAides;  }  /**  * Crée une nouvelle instance de `DetailleSavePartie`.  *  * @param etatgrille L'état des traits de la grille.  * @param chronometre Le temps écoulé.  * @param nbAides Le nombre d'aides utilisées.  * @return Une instance de `DetailleSavePartie`.  */  public static DetailleSavePartie create(List<PositionTrait> etatgrille, Integer chronometre, Integer nbAides) {  return new DetailleSavePartie(etatgrille, chronometre, nbAides);  }  /**  * Retourne l'état des traits de la grille.  *  * @return Une liste de traits.  */  public List<PositionTrait> getEtatGrille() {  return etatgrille;  }  /**  * Retourne le temps écoulé.  *  * @return Le chronomètre en secondes.  */  public Integer getChronometre() {  return Chronometre;  }  /**  * Retourne le nombre d'aides utilisées.  *  * @return Le nombre d'aides.  */  public Integer getNbAides() {  return nbAides;  }  /**  * Retourne le nom personnalisé de la sauvegarde.  *  * @return Le nom de la sauvegarde.  */  public String getNameClass() {  return nameClass;  }  /**  * Définit le nom personnalisé de la sauvegarde.  *  * @param nameClass Le nom à définir.  */  public void setNameClass(String nameClass) {  this.nameClass = nameClass;  }  /**  * Définit le temps écoulé.  *  * @param chronometre Le temps en secondes.  */  public void setChronometre(Integer chronometre) {  this.Chronometre = chronometre;  }  /**  * Définit le nombre d'aides utilisées.  *  * @param nbAides Le nombre d'aides.  */  public void setNbAides(Integer nbAides) {  this.nbAides = nbAides;  } } /*import java.time.Duration;*/ /**  * Gère le score et le chronomètre d'une partie.  * Calcule le nombre d'étoiles obtenues en fonction du temps et des aides utilisées.  *  * @author Enzo Desfaudais (B0rno)  * @version 1.0  */ /* modif : une etoile pour une partie complétée, une étoile pour un temps respecté ou aides respectées, une étoile si tout est respecté */ public static class Score {  public Score() {}  private Instant debutSession = null;  private java.time.Duration dureeAccumulee = java.time.Duration.ZERO;  private int nbCoups = 0;  private int nbAidesUtilisees = 0;  private int nbAidexMax = 3; /* 3 aides max pour l'étoile */  private int etoiles = 0;  private long dureePourEtoile = 300; /* 5 minutes pour l'étoile */  /**  * Démarre le chronomètre.  * Enregistre l'instant de début de la session de jeu.  */  public void demarrerChrono() {  if (debutSession == null) {  debutSession = Instant.now();  }  }  /**  * Met le chronomètre en pause.  * Accumule le temps écoulé depuis le dernier démarrage.  */  public void pauseChrono() {  if (debutSession != null) {  dureeAccumulee = dureeAccumulee.plus(java.time.Duration.between(debutSession, Instant.now()));  debutSession = null;  }  }  /**  * Arrête définitivement le chronomètre.  * Accumule le temps écoulé et réinitialise l'instant de début.  */  public void arreterChrono() {  if (debutSession != null) {  dureeAccumulee = dureeAccumulee.plus(java.time.Duration.between(debutSession, Instant.now()));  debutSession = null;  }  }  /**  * Calcule le nombre d'étoiles obtenues.  * 3 étoiles : temps inférieur ou égal à 2 minutes sans aide.  * 2 étoiles : temps inférieur ou égal à 5 minutes avec maximum 2 aides.  * 1 étoile : sinon.  */  public void calculerEtoiles() {  long secondes = getDureeEnSecondes();  if (secondes <= dureePourEtoile && nbAidesUtilisees == 0) etoiles = 3;  else if (secondes <= dureePourEtoile && nbAidesUtilisees <= nbAidexMax) etoiles = 2;  else etoiles = 1;  }  /**  * Initialise les valeurs pour la reconstruction d'une partie sauvegardée.  *  * @param chronoEnSecondes la durée accumulée en secondes  * @param aidesUtilisees le nombre d'aides utilisées  */  public void setReconstructionSave(long chronoEnSecondes, int aidesUtilisees) {  this.dureeAccumulee = java.time.Duration.ofSeconds(chronoEnSecondes);  this.nbAidesUtilisees = aidesUtilisees;  }  /**  * Retourne le nombre d'étoiles obtenues.  *  * @return le nombre d'étoiles (entre 0 et 3)  */  public int getEtoiles() {  return etoiles;  }  /**  * Retourne la durée totale de jeu accumulée.  *  * @return la durée en secondes  */  public long getDureeEnSecondes() {  if (debutSession != null) {  return dureeAccumulee.plus(java.time.Duration.between(debutSession, Instant.now())).getSeconds();  }  return dureeAccumulee.getSeconds();  }  public void setDureeAccumulee(java.time.Duration dureeAccumulee) {  this.dureeAccumulee = dureeAccumulee;  }  /**  * Retourne le nombre de coups joués.  *  * @return le nombre de coups  */  public int getNbCoups() {  return nbCoups;  }  /**  * Retourne le nombre d'aides utilisées.  *  * @return le nombre d'aides utilisées  */  public int getNbAidesUtilisees() {  return nbAidesUtilisees;  }  public void setNbAidesUtilisees(int nbAidesUtilisees) {  this.nbAidesUtilisees = nbAidesUtilisees;  }  public long getDureePourEtoile() {  return dureePourEtoile;  }  public int getNbAidexMax() {  return nbAidexMax;  }  /**  * Incrémente le compteur d'aides utilisées.  */  public void utiliserAide() {  nbAidesUtilisees++;  }  /**  * Incrémente le compteur de coups joués.  */  public void incrementerCoups() {  nbCoups++;  } } /**  * Énumération représentant les différents états d'une partie.  *   *   * @author Enzo Desfaudais (B0rno)  * @version 1.0  */ public static enum EtatPartie {  INIT, EN_COURS, PAUSE, TERMINE;  /**  * Vérifie si un coup peut être joué dans cet état.  *  * @return true uniquement si l'état est EN_COURS  */  public boolean peutJouer() {  return this == EN_COURS;  }  /**  * Vérifie si la partie peut être démarrée ou reprise.  *  * @return true si l'état est INIT ou PAUSE  */  public boolean peutDemarrer() {  return this == INIT || this == PAUSE;  }  /**  * Vérifie si la partie peut être mise en pause.  *  * @return true uniquement si l'état est EN_COURS  */  public boolean peutMettreEnPause() {  return this == EN_COURS;  } } /**  * Technique: Technique avancée 1 (Continuité de la boucle)  * Parcourt chaque intersection (coin) de la grille pour garantir que la boucle ne se retrouve jamais dans un cul-de-sac et ne se divise pas.  */ public static class TechniqueAvancee1 implements StrategieAide {  public TechniqueAvancee1() {}  /* Attention : l'espace à la fin est conservé pour matcher exactement avec le JSON */  private static final String NOM = "Technique avancée 1 ";  @Override  public boolean estApplicable(Matrice m) {  int hauteur = m.getHauteur();  int largeur = m.getLargeur();  /* On parcourt chaque point de la grille. */  /* Il y a (hauteur + 1) points verticalement et (largeur + 1) horizontalement. */  for (int r = 0; r <= hauteur; r++) {  for (int c = 0; c <= largeur; c++) {  List<Trait> traitsDuPoint = new ArrayList<>();  /* Récupération des 4 traits connectés à cette intersection */  Trait haut = getTraitHaut(m, r, c);  Trait bas = getTraitBas(m, r, c);  Trait gauche = getTraitGauche(m, r, c);  Trait droite = getTraitDroite(m, r, c);  if (haut != null) traitsDuPoint.add(haut);  if (bas != null) traitsDuPoint.add(bas);  if (gauche != null) traitsDuPoint.add(gauche);  if (droite != null) traitsDuPoint.add(droite);  int nbPleins = 0;  int nbVides = 0;  for (Trait t : traitsDuPoint) {  if (t.getEtat() == ValeurTrait.PLEIN) nbPleins++;  else if (t.getEtat() == ValeurTrait.VIDE) nbVides++;  else if (t.getEtat() == ValeurTrait.CROIX) nbVides++; /* On traite les croix comme des vides pour la continuité */  }  /* Condition 2 : 1 trait plein arrive et 1 seule sortie possible */  /* La boucle DOIT continuer, donc le trait vide restant devient forcément plein. */  if (nbPleins == 1 && nbVides == 1) {  return true;  }  }  }  return false;  }  /* --- Méthodes pour extraire les traits autour d'une intersection --- */  private Trait getTraitHaut(Matrice m, int r, int c) {  if (r == 0)   return null; /* Bordure haute */  if (c < m.getLargeur())   return m.getCase(r - 1, c).getTrait(1); /* Trait gauche de la case Haut-Droite */  return m.getCase(r - 1, c - 1).getTrait(2); /* Trait droit de la case Haut-Gauche */  }  private Trait getTraitBas(Matrice m, int r, int c) {  if (r == m.getHauteur())   return null; /* Bordure basse */  if (c < m.getLargeur())   return m.getCase(r, c).getTrait(1); /* Trait gauche de la case Bas-Droite */  return m.getCase(r, c - 1).getTrait(2); /* Trait droit de la case Bas-Gauche */  }  private Trait getTraitGauche(Matrice m, int r, int c) {  if (c == 0) return null; /* Bordure gauche */  if (r < m.getHauteur())   return m.getCase(r, c - 1).getTrait(0); /* Trait haut de la case Bas-Gauche */  return m.getCase(r - 1, c - 1).getTrait(3); /* Trait bas de la case Haut-Gauche */  }  private Trait getTraitDroite(Matrice m, int r, int c) {  if (c == m.getLargeur()) return null; /* Bordure droite */  if (r < m.getHauteur())  return m.getCase(r, c).getTrait(0); /* Trait haut de la case Bas-Droite */  return m.getCase(r - 1, c).getTrait(3); /* Trait bas de la case Haut-Droite */  }  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  @Override  public String getNom() {  return NOM;  } } /**  * Technique: Technique avancée 2 (Coin extérieur bloqué d'un 3)  * Si les deux chemins situés à l'extérieur d'un coin d'une case '3' sont bloqués (croix ou bord du plateau), la boucle ne peut pas s'échapper par ce coin.  * Elle doit donc obligatoirement longer les deux traits de la case formant ce coin.  */ public static class TechniqueAvancee2 implements StrategieAide {  public TechniqueAvancee2() {}  private static final String NOM = "Technique avancée 2";  @Override  public boolean estApplicable(Matrice m) {  for (int r = 0; r < m.getHauteur(); r++) {  for (int c = 0; c < m.getLargeur(); c++) {  Case currentCase = m.getCase(r, c);    if (currentCase != null && currentCase.getNumero() == 3) {    /* Vérification du coin Haut-Gauche */  if (estBloque(getTraitHaut(m, r, c)) && estBloque(getTraitGauche(m, r, c))) {  /* Les traits Haut (0) et Gauche (1) de la case doivent être PLEINS */  if (currentCase.getTrait(0).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(1).getEtat() == ValeurTrait.VIDE) {  return true;  }  }    /* Vérification du coin Haut-Droite */  if (estBloque(getTraitHaut(m, r, c + 1)) && estBloque(getTraitDroite(m, r, c + 1))) {  /* Les traits Haut (0) et Droite (2) de la case doivent être PLEINS */  if (currentCase.getTrait(0).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(2).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  /* Vérification du coin Bas-Gauche */  if (estBloque(getTraitBas(m, r + 1, c)) && estBloque(getTraitGauche(m, r + 1, c))) {  /* Les traits Bas (3) et Gauche (1) de la case doivent être PLEINS */  if (currentCase.getTrait(3).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(1).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  /* Vérification du coin Bas-Droite */  if (estBloque(getTraitBas(m, r + 1, c + 1)) && estBloque(getTraitDroite(m, r + 1, c + 1))) {  /* Les traits Bas (3) et Droite (2) de la case doivent être PLEINS */  if (currentCase.getTrait(3).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(2).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  }  }  }  return false;  }  /**  * Un chemin est considéré comme bloqué s'il est une croix ou s'il n'existe pas  */  private boolean estBloque(Trait t) {  return t == null || t.getEtat() == ValeurTrait.CROIX;  }  /* --- Méthodes pour extraire les traits autour d'une intersection --- */  private Trait getTraitHaut(Matrice m, int r, int c) {  if (r == 0)   return null; /* Bordure haute */  if (c < m.getLargeur())   return m.getCase(r - 1, c).getTrait(1); /* Trait gauche de la case Haut-Droite */  return m.getCase(r - 1, c - 1).getTrait(2); /* Trait droit de la case Haut-Gauche */  }  private Trait getTraitBas(Matrice m, int r, int c) {  if (r == m.getHauteur())   return null; /* Bordure basse */  if (c < m.getLargeur())   return m.getCase(r, c).getTrait(1); /* Trait gauche de la case Bas-Droite */  return m.getCase(r, c - 1).getTrait(2); /* Trait droit de la case Bas-Gauche */  }  private Trait getTraitGauche(Matrice m, int r, int c) {  if (c == 0) return null; /* Bordure gauche */  if (r < m.getHauteur())   return m.getCase(r, c - 1).getTrait(0); /* Trait haut de la case Bas-Gauche */  return m.getCase(r - 1, c - 1).getTrait(3); /* Trait bas de la case Haut-Gauche */  }  private Trait getTraitDroite(Matrice m, int r, int c) {  if (c == m.getLargeur()) return null; /* Bordure droite */  if (r < m.getHauteur())  return m.getCase(r, c).getTrait(0); /* Trait haut de la case Bas-Droite */  return m.getCase(r - 1, c).getTrait(3); /* Trait bas de la case Haut-Droite */  }  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  @Override  public String getNom() {  return NOM;  } } /**  * Classe représentant une grille sauvegardée.  * Contient les informations sur la taille, les cases et les traits de la grille.  */ public static class SaveGrille {  public SaveGrille() {}  private int nv_grille; /* Niveau de la grille */  private int taille; /* Taille de la grille */  private List<positionGrille> numero_cases; /* Liste des cases avec leurs positions et valeurs */  private List<PositionTrait> liste_position_trait; /* Liste des traits avec leurs positions et états */  /**  * Retourne le niveau de la grille.  *  * @return Le niveau de la grille.  */  public int getNvGrille() {  return nv_grille;  }  /**  * Retourne la taille de la grille.  *  * @return La taille de la grille.  */  public int getTailleGrille() {  return taille;  }  /**  * Retourne la liste des cases de la grille.  *  * @return Une liste de cases.  */  public List<positionGrille> getNumeroCases() {  return numero_cases;  }  /**  * Retourne la liste des traits de la grille.  *  * @return Une liste de traits.  */  public List<PositionTrait> getListePositionTrait() {  return liste_position_trait;  }  @Override  public String toString() {  return   "SaveGrille{" +  "nv_grille=" + nv_grille +  ", taille=" + taille +  ", numero_cases=" + numero_cases +  ", liste_position_trait=" + liste_position_trait +  '}';  } } public static class Trait {  private ValeurTrait etat;  public Trait(){  this.etat = ValeurTrait.VIDE;  }  public Trait(ValeurTrait etat){  this.etat = etat;  }  public void setTrait(ValeurTrait etat){  this.etat = etat;  }  public ValeurTrait getEtat(){  return this.etat;  }  public void etatSuivant(){  this.etat = this.etat.etatSuivant();  }  public String toString(){  return this.etat.toString();  } } /**  * Technique: Technique avancée 4 (Symétrie des 2 adjacents)  * Parcourt la matrice pour trouver deux cases '2' côte à côte.  * Les côtés extérieurs parallèles de deux '2' adjacents sont obligatoirement identiques.  */ public static class TechniqueAvancee4 implements StrategieAide {  public TechniqueAvancee4() {}  private static final String NOM = "Technique avancée 4";  @Override  public boolean estApplicable(Matrice m) {  for (int r = 0; r < m.getHauteur(); r++) {  for (int c = 0; c < m.getLargeur(); c++) {  Case currentCase = m.getCase(r, c);  if (currentCase != null && currentCase.getNumero() == 2) {  /* Vérification avec un '2' adjacent Horizontal (à droite) */  if (c < m.getLargeur() - 1) {  Case caseDroite = m.getCase(r, c + 1);    if (caseDroite != null && caseDroite.getNumero() == 2) {  Trait traitGaucheExt = currentCase.getTrait(1); /* Côté gauche du 1er '2' */  Trait traitDroiteExt = caseDroite.getTrait(2); /* Côté droit du 2ème '2' */  /* Si on connaît l'état du côté gauche, le côté droit doit être identique */  if (traitGaucheExt.getEtat() != ValeurTrait.VIDE && traitDroiteExt.getEtat() == ValeurTrait.VIDE) {  return true;  }  /* Inversement, si on connaît le côté droit, le gauche doit être identique */  if (traitDroiteExt.getEtat() != ValeurTrait.VIDE && traitGaucheExt.getEtat() == ValeurTrait.VIDE) {  return true;  }  }  }  /* Vérification avec un '2' adjacent Vertical (en bas) */  if (r < m.getHauteur() - 1) {  Case caseBas = m.getCase(r + 1, c);    if (caseBas != null && caseBas.getNumero() == 2) {  Trait traitHautExt = currentCase.getTrait(0); /* Côté haut du 1er '2' */  Trait traitBasExt = caseBas.getTrait(3); /* Côté bas du 2ème '2' */  /* Si on connaît l'état du côté haut, le côté bas doit être identique */  if (traitHautExt.getEtat() != ValeurTrait.VIDE && traitBasExt.getEtat() == ValeurTrait.VIDE) {  return true;  }  /* Inversement, si on connaît le côté bas, le haut doit être identique */  if (traitBasExt.getEtat() != ValeurTrait.VIDE && traitHautExt.getEtat() == ValeurTrait.VIDE) {  return true;  }  }  }  }  }  }  return false;  }  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  @Override  public String getNom() {  return NOM;  } } /**  * Technique: Technique avancée 5 (Le 1 et 3 en diagonale)  * Parcourt la matrice pour trouver un '3' et un '1' placés en diagonale.  * On force les deux bords extérieurs du '3' à être PLEINS et les deux bords extérieurs du '1' à être marqués d'une CROIX.  */ public static class TechniqueAvancee5 implements StrategieAide {  public TechniqueAvancee5() {}  private static final String NOM = "Technique avancée 5";  @Override  public boolean estApplicable(Matrice m) {  for (int r = 0; r < m.getHauteur(); r++) {  for (int c = 0; c < m.getLargeur(); c++) {  Case currentCase = m.getCase(r, c);  /* On cherche une case '3' */  if (currentCase != null && currentCase.getNumero() == 3) {  /* Diagonale Haut-Gauche (Le 1 est en Haut-Gauche du 3) */  Case caseHG = m.getCase(r - 1, c - 1);  if (caseHG != null && caseHG.getNumero() == 1) {  /* Extérieurs du 3 (Bas et Droite) -> Doivent être PLEINS */  if (currentCase.getTrait(3).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(2).getEtat() == ValeurTrait.VIDE)   return true;  /* Extérieurs du 1 (Haut et Gauche) -> Doivent être des CROIX */  if (caseHG.getTrait(0).getEtat() == ValeurTrait.VIDE ||   caseHG.getTrait(1).getEtat() == ValeurTrait.VIDE)   return true;  }  /* Diagonale Haut-Droite (Le 1 est en Haut-Droite du 3) */  Case caseHD = m.getCase(r - 1, c + 1);  if (caseHD != null && caseHD.getNumero() == 1) {  /* Extérieurs du 3 (Bas et Gauche) -> Doivent être PLEINS */  if (currentCase.getTrait(3).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(1).getEtat() == ValeurTrait.VIDE)   return true;  /* Extérieurs du 1 (Haut et Droite) -> Doivent être des CROIX */  if (caseHD.getTrait(0).getEtat() == ValeurTrait.VIDE ||   caseHD.getTrait(2).getEtat() == ValeurTrait.VIDE)   return true;  }  /* Diagonale Bas-Gauche (Le 1 est en Bas-Gauche du 3) */  Case caseBG = m.getCase(r + 1, c - 1);  if (caseBG != null && caseBG.getNumero() == 1) {  /* Extérieurs du 3 (Haut et Droite) -> Doivent être PLEINS */  if (currentCase.getTrait(0).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(2).getEtat() == ValeurTrait.VIDE)   return true;  /* Extérieurs du 1 (Bas et Gauche) -> Doivent être des CROIX */  if (caseBG.getTrait(3).getEtat() == ValeurTrait.VIDE ||   caseBG.getTrait(1).getEtat() == ValeurTrait.VIDE)   return true;  }  /* Diagonale Bas-Droite (Le 1 est en Bas-Droite du 3) */  Case caseBD = m.getCase(r + 1, c + 1);  if (caseBD != null && caseBD.getNumero() == 1) {  /* Extérieurs du 3 (Haut et Gauche) -> Doivent être PLEINS */  if (currentCase.getTrait(0).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(1).getEtat() == ValeurTrait.VIDE)   return true;  /* Extérieurs du 1 (Bas et Droite) -> Doivent être des CROIX */  if (caseBD.getTrait(3).getEtat() == ValeurTrait.VIDE ||   caseBD.getTrait(2).getEtat() == ValeurTrait.VIDE)   return true;  }  }  }  }  return false;  }  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  @Override  public String getNom() {  return NOM;  } } /**  * Classe représentant le contenu des techniques pour un langage donné.  * Chaque langage contient une liste de niveaux avec leurs techniques associées.  */ public static class languageContenue {  public languageContenue() {}  private String langage; /* Nom du langage */  private List<contenuTechnique> contenu; /* Liste des contenus techniques pour ce langage */  /**  * Retourne le nom du langage.  *  * @return Le nom du langage.  */  public String getLangage() {  return langage;  }  /**  * Retourne la liste des contenus techniques pour ce langage.  *  * @return Une liste de contenus techniques.  */  public List<contenuTechnique> getContenu() {  return contenu;  } } /**  * Technique: Technique avancée 6 (La ligne entrant dans un 1)  * Si une ligne de la boucle (trait PLEIN) pointe directement sur l'un des coins d'une case '1' elle va obligatoirement longer l'un des deux côtés de ce coin.  * Donc les deux autres côtés de la case '1' à l'opposé du coin doivent être marqués d'une CROIX.  */ public static class TechniqueAvancee6 implements StrategieAide {  public TechniqueAvancee6() {}  private static final String NOM = "Technique avancée 6";  @Override  public boolean estApplicable(Matrice m) {  for (int r = 0; r < m.getHauteur(); r++) {  for (int c = 0; c < m.getLargeur(); c++) {  Case currentCase = m.getCase(r, c);  if (currentCase != null && currentCase.getNumero() == 1) {  /* Coin Haut-Gauche : Si une ligne arrive par le haut ou par la gauche */  if (estPlein(getExtHautGauche_Haut(m, r, c)) || estPlein(getExtHautGauche_Gauche(m, r, c))) {  /* Les traits opposés (Droite et Bas) doivent être des CROIX */  if (currentCase.getTrait(2).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(3).getEtat() == ValeurTrait.VIDE)   return true;  }  /* Coin Haut-Droite : Si une ligne arrive par le haut ou par la droite */  if (estPlein(getExtHautDroite_Haut(m, r, c)) || estPlein(getExtHautDroite_Droite(m, r, c))) {  /* Les traits opposés (Gauche et Bas) doivent être des CROIX */  if (currentCase.getTrait(1).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(3).getEtat() == ValeurTrait.VIDE)   return true;  }  /* Coin Bas-Gauche : Si une ligne arrive par le bas ou par la gauche */  if (estPlein(getExtBasGauche_Bas(m, r, c)) || estPlein(getExtBasGauche_Gauche(m, r, c))) {  /* Les traits opposés (Haut et Droite) doivent être des CROIX */  if (currentCase.getTrait(0).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(2).getEtat() == ValeurTrait.VIDE)   return true;  }  /* Coin Bas-Droite : Si une ligne arrive par le bas ou par la droite */  if (estPlein(getExtBasDroite_Bas(m, r, c)) || estPlein(getExtBasDroite_Droite(m, r, c))) {  /* Les traits opposés (Haut et Gauche) doivent être des CROIX */  if (currentCase.getTrait(0).getEtat() == ValeurTrait.VIDE ||   currentCase.getTrait(1).getEtat() == ValeurTrait.VIDE)   return true;  }  }  }  }  return false;  }  private boolean estPlein(Trait t) {  return t != null && t.getEtat() == ValeurTrait.PLEIN;  }  /* --- Méthodes pour récupérer les traits exterieurs pointant sur les coins de la case --- */  /* Coin Haut-Gauche */  private Trait getExtHautGauche_Haut(Matrice m, int r, int c) {  if (r == 0) return null;  return m.getCase(r - 1, c).getTrait(1); /* Trait gauche de la case au-dessus */  }  private Trait getExtHautGauche_Gauche(Matrice m, int r, int c) {  if (c == 0) return null;  return m.getCase(r, c - 1).getTrait(0); /* Trait haut de la case à gauche */  }  /* Coin Haut-Droite */  private Trait getExtHautDroite_Haut(Matrice m, int r, int c) {  if (r == 0) return null;  return m.getCase(r - 1, c).getTrait(2); /* Trait droit de la case au-dessus */  }  private Trait getExtHautDroite_Droite(Matrice m, int r, int c) {  if (c == m.getLargeur() - 1) return null;  return m.getCase(r, c + 1).getTrait(0); /* Trait haut de la case à droite */  }  /* Coin Bas-Gauche */  private Trait getExtBasGauche_Bas(Matrice m, int r, int c) {  if (r == m.getHauteur() - 1) return null;  return m.getCase(r + 1, c).getTrait(1); /* Trait gauche de la case en dessous */  }  private Trait getExtBasGauche_Gauche(Matrice m, int r, int c) {  if (c == 0) return null;  return m.getCase(r, c - 1).getTrait(3); /* Trait bas de la case à gauche */  }  /* Coin Bas-Droite */  private Trait getExtBasDroite_Bas(Matrice m, int r, int c) {  if (r == m.getHauteur() - 1) return null;  return m.getCase(r + 1, c).getTrait(2); /* Trait droit de la case en dessous */  }  private Trait getExtBasDroite_Droite(Matrice m, int r, int c) {  if (c == m.getLargeur() - 1) return null;  return m.getCase(r, c + 1).getTrait(3); /* Trait bas de la case à droite */  }  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  @Override  public String getNom() {  return NOM;  } } /**  * Technique: Diagonale 0 et 3  * Parcourt la matrice pour vérifier s'il y a un '3' en diagonale d'un '0'.  * L'aide est applicable s'il manque encore des traits sur les côtés opposés au '0'.  */ public static class Diagonale0Et3 implements StrategieAide {  public Diagonale0Et3() {}  private static final String NOM = "Diagonale 0 et 3";  /**  * @param m La matrice du jeu  * @return true si l'aide est applicable  */  @Override  public boolean estApplicable(Matrice m) {  for (int i = 0; i < m.getHauteur(); i++) {  for (int j = 0; j < m.getLargeur(); j++) {    Case c = m.getCase(i, j);  if (c != null && c.getNumero() == 3) {  Case cDiagHG = m.getCase(i - 1, j - 1);  Case cDiagHD = m.getCase(i - 1, j + 1);  Case cDiagBG = m.getCase(i + 1, j - 1);  Case cDiagBD = m.getCase(i + 1, j + 1);  if (cDiagHG != null && cDiagHG.getNumero() == 0) {  if (c.getTrait(2).getEtat() == ValeurTrait.VIDE || c.getTrait(3).getEtat() == ValeurTrait.VIDE)   return true;  }  if (cDiagHD != null && cDiagHD.getNumero() == 0) {  if (c.getTrait(1).getEtat() == ValeurTrait.VIDE || c.getTrait(3).getEtat() == ValeurTrait.VIDE)   return true;  }  if (cDiagBG != null && cDiagBG.getNumero() == 0) {  if (c.getTrait(2).getEtat() == ValeurTrait.VIDE || c.getTrait(0).getEtat() == ValeurTrait.VIDE)   return true;  }  if (cDiagBD != null && cDiagBD.getNumero() == 0) {  if (c.getTrait(1).getEtat() == ValeurTrait.VIDE || c.getTrait(0).getEtat() == ValeurTrait.VIDE)   return true;  }  }  }  }  return false;  }  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  @Override  public String getNom() {  return NOM;  } } public static class Pause extends ChangementFenetre{  public Pause() {}  @FXML  public void recommencer(ActionEvent event) {  /* ne pas sauvegarder */  if("libre".equals(Partie.dernierMode)){  Partie controller = (Partie) GestionnaireVues.getController("partie");  if (controller != null) {  controller.initialiserPartie(Partie.getGrilleEnCours(), true); /* true = recommencer */  }  changerFenetre(event, "partie");  }  else{  PartieTimer controller = (PartieTimer) GestionnaireVues.getController("partieTimer");  if (controller != null) {  if ("aventure".equals(Partie.dernierMode)){    controller.initialiserPartie(PartieTimer.getNumPartie(), true);  }  /* tutoriel */  else{  controller.lancerTutoriel();  }  changerFenetre(event, "partieTimer");  }  else{  System.out.println("Erreur : Impossible de récupérer le controller de PartieTimer");   }  }  }  @FXML   private void abandonner(ActionEvent event) {  /* ne pas faire de sauvegarde */  changerFenetre(event, "menuAccueil");  }  @FXML  private void techniques(ActionEvent event) {  Techniques.setVuePrecedente("pause");  changerFenetre(event, "techniques");  }  @FXML  private void menuPrincipal(ActionEvent event) {  if ("libre".equals(Partie.dernierMode)) {  Partie controller = (Partie) GestionnaireVues.getController("partie");  if (controller != null) {  controller.sauvegarderProgressionCourante();  }  } else {  PartieTimer controller = (PartieTimer) GestionnaireVues.getController("partieTimer");  if (controller != null) {  controller.sauvegarderProgressionCourante();  }  }  changerFenetre(event, "menuAccueil");  }  @FXML  private void reprendre(ActionEvent event) {    if ("libre".equals(Partie.dernierMode)){  changerFenetre(event, "partie");  }  else{  PartieTimer controller = (PartieTimer) GestionnaireVues.getController("partieTimer");  if (controller != null) {  controller.reprendrePartie();   }  changerFenetre(event, "partieTimer");  }     }   } /**  * Représente une matrice de cases pour le jeu SlitherLink.  *   * La matrice gère un plateau rectangulaire de cases où les traits sont partagés  * entre les cases adjacentes. Par exemple, le trait droit d'une case est le même  * objet que le trait gauche de sa voisine à droite.  *   * Structure des indices :  * - 0 : haut (top)  * - 1 : gauche (left)  * - 2 : droite (right)  * - 3 : bas (bottom)  *   * @author Natp24109  * @version 1.0  */ public static class Matrice {  /** Nombre de lignes de la matrice */  private final int hauteur;    /** Nombre de colonnes de la matrice */  private final int largeur;    /** Matrice bidimensionnelle des cases */  private Case[][] grille;    /** Matrice des traits horizontaux (partagés entre haut/bas des cases) */  private Trait[][] traitsHorizontaux;    /** Matrice des traits verticaux (partagés entre gauche/droite des cases) */  private Trait[][] traitsVerticaux;  /** Matrice des traits horizontaux solution */  private Trait[][] traitsHorizontauxSol;  /** Matrice des traits verticaux solution */  private Trait[][] traitsVerticauxSol;  /** Compteur de traits dans le bon état */  private int cpt;  /** Booleen donnant la complétion de la grille */  private boolean completed;  /**  * Constructeur de la matrice.  * Initialise une matrice de cases de dimensions hauteur x largeur.  * Les traits sont automatiquement créés et partagés entre les cases adjacentes.  *   * @param hauteur le nombre de lignes de cases  * @param largeur le nombre de colonnes de cases  */  public Matrice(int hauteur, int largeur) {  this.hauteur = hauteur;  this.largeur = largeur;  this.grille = new Case[hauteur][largeur];  this.cpt = 0;  this.completed = false;    /* Créer les matrices de traits */  /* traitsHorizontaux : (hauteur+1) x largeur */  this.traitsHorizontaux = new Trait[hauteur + 1][largeur];  /* traitsVerticaux : hauteur x (largeur+1) */  this.traitsVerticaux = new Trait[hauteur][largeur + 1];  this.traitsHorizontauxSol = new Trait[hauteur + 1][largeur];  this.traitsVerticauxSol = new Trait[hauteur][largeur + 1];    /* Initialiser tous les traits */  for (int i = 0; i <= hauteur; i++) {  for (int j = 0; j < largeur; j++) {  traitsHorizontaux[i][j] = new Trait();  traitsHorizontauxSol[i][j] = new Trait();  }  }    for (int i = 0; i < hauteur; i++) {  for (int j = 0; j <= largeur; j++) {  traitsVerticaux[i][j] = new Trait();  traitsVerticauxSol[i][j] = new Trait();  }  }    /* Créer les cases et assigner les traits partagés */  int numero = -1;  for (int i = 0; i < hauteur; i++) {  for (int j = 0; j < largeur; j++) {  grille[i][j] = new Case(numero);    /* Assigner les traits à la case */  Trait[] traits = new Trait[4];  traits[0] = traitsHorizontaux[i][j]; /* haut */  traits[1] = traitsVerticaux[i][j]; /* gauche */  traits[2] = traitsVerticaux[i][j + 1]; /* droite */  traits[3] = traitsHorizontaux[i + 1][j]; /* bas */    grille[i][j].setTraits(traits);  }  }  }  /**  * Retourne la case à la position spécifiée.  *   * @param ligne l'indice de ligne (0-indexed)  * @param colonne l'indice de colonne (0-indexed)  * @return la case à cette position, ou null si les indices sont invalides  */  public Case getCase(int ligne, int colonne) {  if (ligne < 0 || ligne >= hauteur || colonne < 0 || colonne >= largeur) {  return null;  }  return grille[ligne][colonne];  }  public Trait getTraitHorizSolution(int ligne, int colonne) {  return this.traitsHorizontauxSol[ligne][colonne];  }  public Trait getTraitVertiSolution(int ligne, int colonne) {  return this.traitsVerticauxSol[ligne][colonne];  }  /**  * Retourne la hauteur de la matrice.  *   * @return le nombre de lignes  */  public int getHauteur() {  return hauteur;  }  /**  * Retourne la largeur de la matrice.  *   * @return le nombre de colonnes  */  public int getLargeur() {  return largeur;  }  /**  * Charge la solution dans la matrice.  * Définit les états des traits solution pour tous les traits.  */  public static Matrice loadGrille(String key){  LoadSave save = LoadSave.getInstance(null);  Map<String, SaveGrille> toutesLesGrilles = save.getGrilles();    if (toutesLesGrilles == null || !toutesLesGrilles.containsKey(key)) {  System.err.println("ERREUR : La grille '" + key + "' est introuvable.");  /* Petit debug pour voir ce qui est chargé */  if(toutesLesGrilles != null) System.out.println("Grilles dispos : " + toutesLesGrilles.keySet());  return null;   }  SaveGrille grid = save.getGrilles().get(key);  if (grid == null) {  System.err.println("La grille '" + key + "' n'a pas été trouvée dans le dossier GrilleJson.");  return null;   }  int hauteur = grid.getTailleGrille();  Matrice loadedMatrice = new Matrice(hauteur, hauteur);  for(positionGrille pos : grid.getNumeroCases()){  List<Integer> coord = pos.getPositionGrille();  loadedMatrice.getCase(coord.get(0), coord.get(1)).setNumero(pos.getValeurGrille());  }  for(PositionTrait pos : grid.getListePositionTrait()){  List<Integer> coord = pos.getPositionTrait();  List<Integer> etat = pos.getEtatTrait();    int ligne = coord.get(0);  int colonne = coord.get(1);    /* Pour chaque direction qui fait partie de la solution */  /* Convention JSON : 0=haut, 1=droite, 2=gauche, 3=bas */  for(Integer direction : etat) {  switch(direction) {  case 0: /* JSON: haut */  loadedMatrice.getTraitHorizSolution(ligne, colonne).setTrait(ValeurTrait.PLEIN);  break;  case 1: /* JSON: droite */  loadedMatrice.getTraitVertiSolution(ligne, colonne + 1).setTrait(ValeurTrait.PLEIN);  break;  case 2: /* JSON: gauche */  loadedMatrice.getTraitVertiSolution(ligne, colonne).setTrait(ValeurTrait.PLEIN);  break;  case 3: /* JSON: bas */  loadedMatrice.getTraitHorizSolution(ligne + 1, colonne).setTrait(ValeurTrait.PLEIN);  break;  }  }  }  loadedMatrice.compterTraitsValides();  /* DEBUG : Afficher le nombre de traits PLEINS dans la solution */  int nbTraitsPleins = 0;  for (int i = 0; i <= loadedMatrice.hauteur; i++) {  for (int j = 0; j < loadedMatrice.largeur; j++) {  if (loadedMatrice.traitsHorizontauxSol[i][j].getEtat() == ValeurTrait.PLEIN) {  nbTraitsPleins++;  }  }  }  for (int i = 0; i < loadedMatrice.hauteur; i++) {  for (int j = 0; j <= loadedMatrice.largeur; j++) {  if (loadedMatrice.traitsVerticauxSol[i][j].getEtat() == ValeurTrait.PLEIN) {  nbTraitsPleins++;  }  }  }  System.out.println("DEBUG Solution chargée : " + nbTraitsPleins + " traits PLEINS attendus");  return loadedMatrice;  }  public boolean loadSave(String pseudo, String path, boolean saveAventure){  LoadSave save = LoadSave.getInstance("");  /* Recharger le SaveGlobal depuis la mémoire pour récupérer les dernières modifications */  save.rechargerSaveGlobal();  savePartieLienJoueur saveJoueur = rechercheSave.trouverSauvegardeParPseudoEtPath(  save.getSaveGlobal(),  pseudo,  path  );  List<PositionTrait> detail = null;  if (saveJoueur != null) {  /* Forcer le rechargement du détail depuis la mémoire */  saveJoueur.reloadDetailleSave();  if (saveJoueur.getDetailleSave() != null) {  detail = saveJoueur.getDetailleSave().getEtatGrille();  }  }  if(detail != null){  for(PositionTrait pos : detail){  List<Integer> coord = pos.getPositionTrait();  List<Integer> etat = pos.getEtatTrait();    int ligne = coord.get(0);  int colonne = coord.get(1);  System.out.println("l:" + ligne + "c:" + colonne + "e:" + etat);    for(Integer direction : etat){  if(this.getCase(ligne,colonne).getTrait(direction).getEtat() == ValeurTrait.VIDE){  this.cliquer(ligne, colonne, direction);  System.out.println("ca marche !");  }  }  }  return true;  }  return false;  }  public void saveGrille(String pseudo, String path, boolean saveAventure, int l, int c, int direction){  if(this.getCase(l,c).getTrait(direction).getEtat() == ValeurTrait.CROIX)  return; /* La sauvegarde des croix n'est pas implémenté dans les json */  LoadSave save = LoadSave.getInstance("");  /* Recharger SaveGlobal pour avoir les données à jour */  save.rechargerSaveGlobal();  savePartieLienJoueur saveJoueur = rechercheSave.trouverSauvegardeParPseudoEtPath(  save.getSaveGlobal(),  pseudo,  path  );  if (saveJoueur == null) {  /* System.err.println("Aucune sauvegarde trouvée pour pseudo/path: " + pseudo + " / " + path); */  return;  }  Integer id = saveJoueur.getId();  if (id == null) {  /* System.err.println("Sauvegarde trouvée sans id: " + pseudo + " / " + path); */  return;  }  DetailleSavePartie detailSave = saveJoueur.getDetailleSave();  if (detailSave == null) {  detailSave = DetailleSavePartie.create(new ArrayList<>(), 0, 0);  saveJoueur.setDetailleSave(detailSave);  }  List<PositionTrait> detail = detailSave.getEtatGrille();  if (detail == null) {  detail = new ArrayList<>();  DetailleSavePartie nouveauDetail = DetailleSavePartie.create(  detail,  detailSave.getChronometre(),  detailSave.getNbAides()  );  nouveauDetail.setNameClass(detailSave.getNameClass());  saveJoueur.setDetailleSave(nouveauDetail);  }  if(detail != null){  boolean caseExistante = false;  for(PositionTrait pos : detail){  List<Integer> coord = pos.getPositionTrait();  List<Integer> etat = pos.getEtatTrait();    int ligne = coord.get(0);  int colonne = coord.get(1);    if(ligne == l && colonne == c){  if(etat.contains(direction))  etat.remove(Integer.valueOf(direction));  else  etat.add(direction);  caseExistante = true;  break;  }  }  if(!caseExistante) {  List<Integer> positions = new ArrayList<>(2);  positions.add(l);  positions.add(c);  List<Integer> etats = new ArrayList<>(4);  etats.add(direction);  detail.add(PositionTrait.create(positions, etats));  }  }  SaveManager saveManager = new SaveManager(save);  saveManager.updateSaveFichierId(id);   }  /**  * Compte le nombre total de traits valides dans la matrice.  * Un trait est valide si son état actuel correspond à la solution.  *   * @return le nombre de traits valides  */  private int compterTraitsValides() {  int total = 0;    /* Vérifier les traits horizontaux */  for (int i = 0; i <= hauteur; i++) {  for (int j = 0; j < largeur; j++) {  if (traitsHorizontaux[i][j].getEtat() == traitsHorizontauxSol[i][j].getEtat() ||  (traitsHorizontaux[i][j].getEtat() == ValeurTrait.CROIX &&   traitsHorizontauxSol[i][j].getEtat() != ValeurTrait.PLEIN)) {  total++;  }  }  }    /* Vérifier les traits verticaux */  for (int i = 0; i < hauteur; i++) {  for (int j = 0; j <= largeur; j++) {  if (traitsVerticaux[i][j].getEtat() == traitsVerticauxSol[i][j].getEtat() ||  (traitsVerticaux[i][j].getEtat() == ValeurTrait.CROIX &&   traitsVerticauxSol[i][j].getEtat() != ValeurTrait.PLEIN)) {  total++;  }  }  }    this.cpt = total;  return total;  }  /**  * Vérifie si tous les traits PLEINS correspondent exactement à la solution.  * Le joueur n'est pas obligé de placer des croix sur les traits vides.  *  * @return true si tous les traits pleins sont corrects et complets  */  private boolean verifierTraitsPleins() {  /* Vérifier les traits horizontaux */  for (int i = 0; i <= hauteur; i++) {  for (int j = 0; j < largeur; j++) {  ValeurTrait actuel = traitsHorizontaux[i][j].getEtat();  ValeurTrait solution = traitsHorizontauxSol[i][j].getEtat();  /* Si la solution est PLEIN, le trait actuel DOIT être PLEIN */  if (solution == ValeurTrait.PLEIN && actuel != ValeurTrait.PLEIN) {  return false;  }  /* Si le trait actuel est PLEIN, la solution DOIT être PLEIN */  if (actuel == ValeurTrait.PLEIN && solution != ValeurTrait.PLEIN) {  return false;  }  }  }  /* Vérifier les traits verticaux */  for (int i = 0; i < hauteur; i++) {  for (int j = 0; j <= largeur; j++) {  ValeurTrait actuel = traitsVerticaux[i][j].getEtat();  ValeurTrait solution = traitsVerticauxSol[i][j].getEtat();  /* Si la solution est PLEIN, le trait actuel DOIT être PLEIN */  if (solution == ValeurTrait.PLEIN && actuel != ValeurTrait.PLEIN) {  return false;  }  /* Si le trait actuel est PLEIN, la solution DOIT être PLEIN */  if (actuel == ValeurTrait.PLEIN && solution != ValeurTrait.PLEIN) {  return false;  }  }  }  return true;  }  /**  * Modifie l'état d'un trait d'une case.  *   * @param ligne l'indice de ligne de la case (0-indexed)  * @param colonne l'indice de colonne de la case (0-indexed)  * @param direction l'index du trait (0=haut, 1=gauche, 2=droite, 3=bas)  */  public void cliquer(int ligne, int colonne, int direction){  this.grille[ligne][colonne].updateTrait(direction);  this.cpt = this.compterTraitsValides();  /* Vérifier la victoire : tous les traits PLEINS doivent correspondre à la solution */  if(verifierTraitsPleins()) {  System.out.println("GAGNE !!!!!!!!!!!!!!!!!!!");  this.completed = true;  }  }  /**  * Vérifie la complétion de la grille.  *   * @return un booleen donnant l'information de complétion  */  public boolean verifierVictoire(){  return this.completed;  }  /**  * Retourne une représentation textuelle de la matrice.  * Affiche l'état actuel de toutes les cases avec les traits correctement positionnés.  *   * @return une chaîne représentant visuellement la matrice  */  @Override  public String toString() {  StringBuilder sb = new StringBuilder();    for (int i = 0; i < hauteur; i++) {  /* Ligne des traits horizontaux du haut */  for (int j = 0; j < largeur; j++) {  sb.append(" ");  sb.append(getStringOfTraitHorizontal(i, j, 0)); /* trait haut */  }  sb.append("\n");    /* Ligne des cases avec traits verticaux */  for (int j = 0; j < largeur; j++) {  sb.append(getStringOfTraitVertical(i, j, 1)); /* trait gauche */  if(grille[i][j].getNumero() != -1)  sb.append(String.format("[%d]", grille[i][j].getNumero()));  else sb.append("[ ]");  }  sb.append(getStringOfTraitVertical(i,largeur-1,2)); /* trait droit de la dernière case */  sb.append("\n");  }    /* Dernière ligne des traits horizontaux du bas */  for (int j = 0; j < largeur; j++) {  sb.append(" ");  sb.append(getStringOfTraitHorizontal(hauteur - 1, j, 3)); /* trait bas */  }    int totalTraits = (hauteur + 1) * largeur + hauteur * (largeur + 1);  sb.append("\nSolution : ").append(this.cpt).append("/").append(totalTraits);    return sb.toString();  }  /**  * Récupère la représentation textuelle d'un trait horizontal.  *   * @param ligne l'indice de ligne de la case  * @param colonne l'indice de colonne de la case  * @param direction 0 pour haut, 3 pour bas  * @return une chaîne représentant le trait horizontal  */  private String getStringOfTraitHorizontal(int ligne, int colonne, int direction) {  Trait trait;  if (direction == 0) {  trait = traitsHorizontaux[ligne][colonne];  } else {  trait = traitsHorizontaux[ligne + 1][colonne];  }    String representation = trait.toString();  String[] parts = representation.split("\\?");  return parts[1] + parts[1] + parts[1];  }  /**  * Récupère la représentation textuelle d'un trait vertical.  *   * @param ligne l'indice de ligne de la case  * @param colonne l'indice de colonne de la case  * @param direction 1 pour gauche, 2 pour droite  * @return une chaîne représentant le trait vertical  */  private String getStringOfTraitVertical(int ligne, int colonne, int direction) {  Trait trait;  if (direction == 1) {  trait = traitsVerticaux[ligne][colonne];  } else {  trait = traitsVerticaux[ligne][colonne + 1];  }    String representation = trait.toString();  String[] parts = representation.split("\\?");  return parts[0];  } } /**  * Classe représentant un trait dans la grille.  * Contient les coordonnées et l'état du trait.  */ public static class PositionTrait {  private List<Integer> position; /* Coordonnées du trait */  private List<Integer> etat; /* État du trait (VIDE, PLEIN, CROIX) */  public PositionTrait() {}  private PositionTrait(List<Integer> position, List<Integer> etat) {  this.position = position;  this.etat = etat;  }  /**  * Crée une nouvelle instance de `PositionTrait`.  *  * @param position Les coordonnées du trait.  * @param etat L'état du trait.  * @return Une instance de `PositionTrait`.  */  public static PositionTrait create(List<Integer> position, List<Integer> etat) {  return new PositionTrait(position, etat);  }  /**  * Retourne les coordonnées du trait.  *  * @return Une liste contenant les coordonnées.  */  public List<Integer> getPositionTrait() {  return position;  }  /**  * Retourne l'état du trait.  *  * @return Une liste contenant l'état.  */  public List<Integer> getEtatTrait() {  return etat;  }  @Override  public String toString() {  return   "PositionTrait{" +  "position=" + position +  ", etat=" + etat +  '}';  } } /**  * Gère une partie de jeu SlitherLink.  *  * Cette classe coordonne tous les aspects d'une session de jeu :  * la grille (Matrice), le joueur (Profil), le score et l'état de la partie.  *  * @author Enzo Desfaudais (B0rno)  * @version 1.0  * @see PartieObserver  * @see EtatPartie  * @see Score  */ public static class PartieHelper {  private Profil p;  private Matrice m;  private int nbAides;  private Score s;   private EtatPartie etat;  private List<PartieObserver> observers;  private Aide aideEnCours; /* Stocke l'aide actuelle pour la notifier aux observers */  /**  * Crée une nouvelle partie avec une grille vierge.  *  * @param p Le profil du joueur (ne doit pas être null)  * @param hauteur Nombre de lignes de la grille  * @param largeur Nombre de colonnes de la grille   * @throws IllegalArgumentException si p est null ou si hauteur/largeur ≤ 0  */  public PartieHelper(Profil p, int hauteur, int largeur){  this.p = p;  this.m = new Matrice(hauteur, largeur);  this.nbAides = 3;   this.s = new Score();  this.etat = EtatPartie.INIT;  this.observers = new ArrayList<>();  }  /**  * Reconstruit une partie depuis une sauvegarde.  *  * @param p Le profil du joueur   * @param m La matrice restaurée   * @param nbAides Le nombre d'aides restantes   * @param s Le score restauré avec le chrono accumulé   * @throws IllegalArgumentException si un paramètre est null ou invalide  */  public PartieHelper(Profil p, Matrice m, int nbAides, Score s){  this.p = p;  this.m = m;  this.nbAides = nbAides;  this.s = s;  this.etat = EtatPartie.PAUSE; /* chargée = en pause */  this.observers = new ArrayList<>();  }  /**  * Démarre ou reprend la partie.  * Passe l'état de INIT ou PAUSE vers EN_COURS et lance le chronomètre.  *   * @throws IllegalStateException si l'état actuel ne permet pas de démarrer  */  public void demarrer() {  /* INIT ou pause -> EN_COURS */  if(!etat.peutDemarrer())   throw new IllegalStateException("L'etat actuel (" + etat + ") ne permet pas de démarrer la partie.");  etat = EtatPartie.EN_COURS;  s.demarrerChrono();  notifierEtatChange();  }  /**  * Termine la partie après détection de la victoire.  * Arrête le chronomètre, calcule les étoiles et notifie les observers.  */  private void terminerPartie() {  etat = EtatPartie.TERMINE;  s.arreterChrono();  s.calculerEtoiles();  p.ajouterScore(s);    /* Notifie TOUS les observers de la victoire avec le score final */  for (PartieObserver o : observers) {  o.onVictoire(s);  }   }  /**  * Joue un coup en modifiant l'état d'un trait de la grille.  * @param ligne Indice de ligne de la case  * @param colonne Indice de colonne de la case  * @param direction Direction du trait (0=haut, 1=gauche, 2=droite, 3=bas)  * @return true si le coup a été joué, false si refusé  */  public boolean jouerCoup(int ligne, int colonne, int direction){  if(!etat.peutJouer()) return false;  m.cliquer(ligne, colonne, direction);  m.saveGrille(  p.getPseudo(),  "./save/saveGrille/" + Partie.nomGrille + ".json",  Partie.getDernierMode().equals("aventure"),  ligne,  colonne,   direction  );  s.incrementerCoups();  if (verifierVictoire()) terminerPartie();  return true;  }  /**  * Notifie tous les observers enregistrés du changement d'état actuel.  */  private void notifierEtatChange() {  for (PartieObserver o : observers) {  o.onEtatChange(etat);  }  }  /**  * Notifie tous les observers qu'une aide a été consommée.  */   private void notifierAideUtilisee() {  for (PartieObserver o : observers) {  o.onAideUtilisee();  }  }  /**  * Enregistre un observer pour recevoir les notifications d'événements.  *   * @param obs L'observer à ajouter  */  public void ajouterObserver(PartieObserver obs) {  if (obs != null) observers.add(obs);  }  /**  * Supprime un observer de la liste de notification.  *   * @param obs L'observer à retirer  */  public void supprimerObserver(PartieObserver obs) {  observers.remove(obs);  }  /**  * Met la partie en pause.  * Suspend le chronomètre et bloque les coups jusqu'à la reprise.  *   * @throws IllegalStateException si l'état ne permet pas la mise en pause  */  public void mettreEnPause() {  if (!etat.peutMettreEnPause()) {  throw new IllegalStateException("Impossible de mettre en pause depuis " + etat);  }  etat = EtatPartie.PAUSE;  s.pauseChrono();  notifierEtatChange();  }  /**  * Vérifie si le joueur peut utiliser une aide.  *   * @return true si la partie est en cours et qu'il reste des aides  */  public boolean peutUtiliserAide() {  return etat.peutJouer();  }  /**  * Utilise une aide pour révéler un trait de la solution.  *   * @return true si l'aide a été utilisée, false sinon  */  public boolean utiliserAide() {  if (!peutUtiliserAide()) return false;    nbAides--;  s.utiliserAide();  GestionnaireAide gestionnaire = new GestionnaireAide();  aideEnCours = gestionnaire.trouverAide(m);  notifierAideUtilisee();  return aideEnCours != null;    }  /**  * Retourne l'aide en cours.  *   * @return l'aide actuelle ou null si aucune aide n'est en cours  */  public Aide getAideEnCours() {  return aideEnCours;  }  /**  * Vérifie si tous les traits de la grille correspondent à la solution.  *   * @return true si la partie est gagnée, false sinon  */  public boolean verifierVictoire(){  return m.verifierVictoire();  }  /**  * Retourne le profil du joueur.  *   * @return le profil associé à cette partie  */  public Profil getProfil(){  return p;  }  /**  * Retourne la grille de jeu.  *   * @return la matrice contenant l'état de la grille  */  public Matrice getMatrice(){  return m;  }  /**  * Retourne le nombre d'aides restantes.  *   * @return le nombre d'aides disponibles  */  public int getNbAides(){  return nbAides;  }  /**  * Retourne le score de la partie.  *   * @return le score avec temps, coups et étoiles  */  public Score getScore(){  return s;  }  /**  * Définit le nombre d'aides disponibles.  *   * @param n le nouveau nombre d'aides  */  public void SetNbAides(int n){  nbAides = n ;  } } /**  * Classe représentant une technique de jeu.  * Contient le nom et la description de la technique.  */ public static class stockageTechnique {  public stockageTechnique() {}  private String name; /* Nom de la technique */  private String description; /* Description de la technique */  /**  * Retourne le nom de la technique.  *  * @return Le nom de la technique.  */  public String getName() {  return name;  }  /**  * Retourne la description de la technique.  *  * @return La description de la technique.  */  public String getDescription() {  return description;  } } /**  * Représente une case du plateau de jeu SlitherLink.  *   * Une case est caractérisée par :  * - Un numéro unique identifiant la case  * - Un tableau de 4 traits (haut, gauche, droite, bas) pour l'état actuel du jeu  *   * Les directions des traits sont indexées comme suit :  * - 0 : haut (top)  * - 1 : gauche (left)  * - 2 : droite (right)  * - 3 : bas (bottom)  *   * @author Natp24109  * @version 1.0  */ public static class Case {  /** Numéro unique identifiant cette case */  private int numero_case;    /** Tableau contenant l'état actuel du jeu pour les 4 traits */  private Trait[] etatJeu;  /**  * Initialise l'état initial d'une case avec tous les traits en état VIDE.  *   * @return un tableau de 4 traits tous initialisés à VIDE  */  private static Trait[] getEtatInitialCase(){  return new Trait[]{new Trait(),new Trait(),new Trait(),new Trait()};  }  /**  * Constructeur d'une case.  * Initialise la case avec son numéro et place tous les traits en état VIDE.  *   * @param num le numéro unique de la case  */  public Case(int num){  this.numero_case = num;  this.etatJeu = Case.getEtatInitialCase();  }  /**  * Retourne le numéro unique de cette case.  *   * @return le numéro de la case  */  public int getNumero() {  return numero_case;  }  public void setNumero(int num){  this.numero_case = num;  }  /**  * Récupère l'état d'un trait spécifique de cette case.  *   * @param direction l'index du trait (0=haut, 1=gauche, 2=droite, 3=bas)  * @return l'état du trait à cette direction  */  public Trait getTrait(int direction){  return etatJeu[direction];  }  /**  * Définit les traits partagés pour cette case.  *   * @param traits un tableau de 4 traits (haut, gauche, droite, bas)  */  public void setTraits(Trait[] traits){  this.etatJeu = traits;  }  /**  * Récupère la représentation textuelle d'un trait spécifique.  *   * Extrait la partie pertinente de la représentation du trait selon la direction :  * - Pour les directions 0 (haut) et 3 (bas), utilise la deuxième partie si disponible  * - Pour les autres directions, utilise la première partie  *   * @param direction l'index du trait (0=haut, 1=gauche, 2=droite, 3=bas)  * @return une chaîne représentant le trait  */  private String getStringOfTrait(int direction) {  String representation = this.getTrait(direction).toString();  String[] parts = representation.split("\\?");  boolean useSecondPart = (direction == 0 || direction == 3);  if (useSecondPart && parts.length > 1) {  return parts[1];  }  return parts[0];  }  /**  * Fait passer au trait suivant son état.  * Utilise la séquence : VIDE → PLEIN → CROIX → VIDE  *   * @param direction l'index du trait à modifier (0=haut, 1=gauche, 2=droite, 3=bas)  */  public void updateTrait(int direction){  this.etatJeu[direction].etatSuivant();  }  /**  * Retourne une représentation visuelle de la case au format texte.  * Affiche la case avec son numéro au centre et les traits tout autour.  *   * @return une chaîne représentant visuellement la case  */  public String toString(){  return " " + getStringOfTrait(0) + " "  + getStringOfTrait(1) + this.numero_case + getStringOfTrait(2) + " "  + " " + getStringOfTrait(3) + " ";  } } public static class FinPartieLibre extends ChangementFenetre {  public FinPartieLibre() {}  @FXML  public void newGame(ActionEvent event) {  changerFenetre(event, "choixDifficulte");  }  @FXML  public void menu(ActionEvent event) {  changerFenetre(event, "menuAccueil");  }  } /**  * Représente une aide trouvée par le système.  * Contient le nom et les informations sur la technique d'aide.  *  * @author Enzo Desfaudais (B0rno)  * @version 1.0  */ public static class Aide {  private final String nom;  private final String techniqueLiee;  /**  * Constructeur complet d'une aide.  *  * @param nom nom de la technique d'aide (ex: "Contraintes sur 3")  * @param techniqueLiee description détaillée de la technique d'aide, extraite du JSON   */  public Aide(String nom, String techniqueLiee) {  this.nom = nom;  this.techniqueLiee = techniqueLiee;  }  /* Getters pour les champs de l'aide */  public String getNom() {  return nom;  }  public String getTechniqueLiee() {  return techniqueLiee;  } } public static class SaveHelper {  private static final SaveHelper instance = new SaveHelper();  private SaveHelper() {}  public static SaveHelper getInstance(){  return SaveHelper.instance;  }  private static int prochainId(SaveGlobal saveGlobal) {  int maxId = 0;  if (saveGlobal == null) {  return 1;  }  List<savePartieLienJoueur> toutes = new ArrayList<>();  if (saveGlobal.getSauvegardeLibre() != null) {  toutes.addAll(saveGlobal.getSauvegardeLibre());  }  if (saveGlobal.getSauvegardeAventure() != null) {  toutes.addAll(saveGlobal.getSauvegardeAventure());  }  for (savePartieLienJoueur partie : toutes) {  if (partie != null && partie.getId() != null && partie.getId() > maxId) {  maxId = partie.getId();  }  }  return maxId + 1;  }  public static void ajouterPartieAventure(LoadSave save, String pseudo, String nomGrille) {  Integer id = SaveHelper.prochainId(save.getSaveGlobal());  savePartieLienJoueur partie = savePartieLienJoueur.create(  pseudo,  id,  "./save/saveGrille/" + nomGrille + ".json"  );  partie.setDetailleSave(SaveHelper.buildDetail());  save.getSaveGlobal().addSauvegardeAventure(partie);  System.out.println("Ajout aventure -> pseudo=" + pseudo + ", id=");  SaveManager saveManager = new SaveManager(save);  saveManager.updateSaveFichierId(id);  }  public static void ajouterPartieLibre(LoadSave save, String pseudo, String nomGrille) {  Integer id = SaveHelper.prochainId(save.getSaveGlobal());  savePartieLienJoueur partie = savePartieLienJoueur.create(  pseudo,  id,  "./save/saveGrille/" + nomGrille + ".json"  );  partie.setDetailleSave(SaveHelper.buildDetail());  save.getSaveGlobal().addSauvegardeLibre(partie);  System.out.println("Ajout libre -> pseudo=" + pseudo + ", id=");  SaveManager saveManager = new SaveManager(save);  saveManager.updateSaveFichierId(id);  }  private static DetailleSavePartie buildDetail() {  return DetailleSavePartie.create(  new ArrayList<PositionTrait>(),  0,  0  );  } } /**  * Classe représentant le contenu des techniques pour un niveau donné.  * Chaque niveau contient une liste de techniques associées.  */ public static class contenuTechnique {  public contenuTechnique() {}  private String nv; /* Niveau de difficulté */  private List<stockageTechnique> techniqueParsNv; /* Liste des techniques pour ce niveau */  /**  * Retourne le niveau de difficulté.  *  * @return Le niveau de difficulté.  */  public String getNv() {  return nv;  }  /**  * Retourne la liste des techniques associées à ce niveau.  *  * @return Une liste de techniques.  */  public List<stockageTechnique> getTechniqueParsNv() {  return techniqueParsNv;  } } public static class Pseudo extends ChangementFenetre{  public Pseudo() {}  @FXML private TextField txtPseudo;  @FXML private Button btnConfirmer;  public static String nomJoueur = null;  @FXML  private void confirmer(ActionEvent event) {  String pseudo = txtPseudo.getText().trim();  if (!pseudo.isEmpty()) {  Pseudo.nomJoueur = pseudo;  changerFenetre(event, "menuAccueil");  }  }  @FXML  public void initialize() {  btnConfirmer.disableProperty().bind(txtPseudo.textProperty().isEmpty());  txtPseudo.textProperty().addListener((observable, oldValue, newValue) -> {  if (newValue.length() > 20) {  txtPseudo.setText(oldValue);  }  });  } } /**  * Sérialiseur personnalisé pour la classe {@link LoadSave}.  * Permet de convertir un objet {@link LoadSave} en JSON avec des références spécifiques  * pour les fichiers associés.  */ public static class LoadSaveSerializer implements JsonSerializer<LoadSave> {  public LoadSaveSerializer() {}  /**  * Sérialise un objet {@link LoadSave} en JSON.  * Ajoute des références spécifiques pour les fichiers associés (grille, technique, sauvegardes).  *  * @param src L'objet {@link LoadSave} à sérialiser.  * @param typeOfSrc Le type de l'objet source.  * @param context Le contexte de sérialisation.  * @return Un objet JSON représentant l'objet {@link LoadSave}.  */  @Override  public JsonElement serialize(LoadSave src, Type typeOfSrc, JsonSerializationContext context) {  JsonObject obj = new JsonObject();  obj.addProperty("grille", "fichier:SaveGrille");  obj.addProperty("technique", "fichier:SaveTechnique");  obj.addProperty("saveGlobal", "fichier:SaveGlobal");  com.google.gson.JsonArray detailsRefs = new com.google.gson.JsonArray();  SaveGlobal sg = src.getSaveGlobal();  if (sg != null) {  java.util.function.Consumer<java.util.List<savePartieLienJoueur>> addRefs = list -> {  if (list == null) return;  for (savePartieLienJoueur sp : list) {  DetailleSavePartie det = sp != null ? sp.getDetailleSave() : null;  if (det != null) {  String name = det.getNameClass();  detailsRefs.add("fichier:" + (name != null ? name : "DetailleSavePartie"));  }  }  };  addRefs.accept(sg.getSauvegardeLibre());  addRefs.accept(sg.getSauvegardeAventure());  }  if (detailsRefs.size() > 0) {  obj.add("DetailleSavePartie", detailsRefs);  }  return obj;  } } /**  * Controller pour la page des leaderboards.  * Affiche les meilleurs scores pour chaque partie.  */ public static class Leaderboards extends ChangementFenetre {  public Leaderboards() {}  @FXML  private MenuButton menuLeaderboards;  @FXML  private ScrollPane scrollPaneScores;  @FXML  private VBox contentPane;  private List<StructureCSV> tousLesScores;  private String partieSelectionnee = "partie1";  /**  * Initialise le leaderboard au chargement de la page.  * Charge tous les scores depuis Score.csv et affiche ceux de la partie 1 par défaut.  */  @FXML  public void initialize() {  chargerScores();  menuLeaderboards.setText("Partie 1");  afficherScores(partieSelectionnee);  }  /**  * Rafraîchit les données du leaderboard depuis Score.csv.  * Appelée à chaque ouverture de la page pour afficher les scores les plus récents.  */  public void rafraichirDonnees() {  chargerScores();  afficherScores(partieSelectionnee);  }  /**  * Charge tous les scores depuis le fichier CSV.  */  private void chargerScores() {  tousLesScores = LoadCSV.lire(  "/save/Score.csv",  "./save/Score.csv",  StructureCSV.class  );  }  /**  * Gère le changement de partie sélectionnée dans le menu.  * Filtre et affiche les scores correspondants.  */  @FXML  private void modifChamp(ActionEvent event) {  MenuItem item = (MenuItem) event.getSource();  menuLeaderboards.setText(item.getText());  /* Extraire le numéro de la partie (ex: "Partie 1" -> "partie1") */  String texte = item.getText();  int numero = Integer.parseInt(texte.replaceAll("[^0-9]", ""));  partieSelectionnee = "partie" + numero;  afficherScores(partieSelectionnee);  }  /**  * Affiche les scores filtrés par partie dans le ScrollPane.  * Les scores sont triés par temps croissant (meilleurs en premier).  *  * @param nomPartie le nom de la partie à filtrer (ex: "partie1")  */  private void afficherScores(String nomPartie) {  contentPane.getChildren().clear();  if (tousLesScores == null || tousLesScores.isEmpty()) {  Label noData = new Label("Aucun score disponible");  noData.setFont(Font.font(14));  noData.setStyle("-fx-text-fill: gray;");  contentPane.getChildren().add(noData);  return;  }  /* Filtrer par partie et trier par étoiles (décroissant) puis chrono (croissant) */  List<StructureCSV> scoresFiltres = tousLesScores.stream()  .filter(score -> score.getCheminGrille().contains(nomPartie))  .sorted((s1, s2) -> {  int etoiles1 = calculerEtoiles(s1.getChrono(), s1.getNbAide());  int etoiles2 = calculerEtoiles(s2.getChrono(), s2.getNbAide());  /* Trier par étoiles décroissant (3 avant 2 avant 1) */  int compareEtoiles = Integer.compare(etoiles2, etoiles1);  if (compareEtoiles != 0) return compareEtoiles;  /* Si même nombre d'étoiles, trier par chrono croissant */  return Integer.compare(s1.getChrono(), s2.getChrono());  })  .limit(10) /* Top 10 */  .collect(Collectors.toList());  if (scoresFiltres.isEmpty()) {  Label noData = new Label("Aucun score pour\ncette partie");  noData.setFont(Font.font(14));  noData.setStyle("-fx-text-fill: gray;");  noData.setAlignment(Pos.CENTER);  contentPane.getChildren().add(noData);  return;  }  /* Afficher chaque score */  int rang = 1;  for (StructureCSV score : scoresFiltres) {  HBox scoreBox = creerLigneScore(rang, score);  contentPane.getChildren().add(scoreBox);  rang++;  }  }  /**  * Crée une ligne d'affichage pour un score.  *  * @param rang le rang du joueur (1 = premier)  * @param score le score à afficher  * @return un HBox contenant le rang, pseudo, étoiles, temps et aides  */  private HBox creerLigneScore(int rang, StructureCSV score) {  HBox box = new HBox(10);  box.setAlignment(Pos.CENTER_LEFT);  box.setPadding(new Insets(5, 10, 5, 10));  box.setStyle("-fx-background-color: " + (rang % 2 == 0 ? "#f0f0f0" : "#ffffff") +  "; -fx-background-radius: 5;");  /* Rang */  Label labelRang = new Label(rang + ".");  labelRang.setMinWidth(25);  labelRang.setFont(Font.font(14));  labelRang.setStyle("-fx-font-weight: bold;");  /* Pseudo */  Label labelPseudo = new Label(score.getPseudo());  labelPseudo.setMinWidth(80);  labelPseudo.setFont(Font.font(14));  /* Étoiles */  int nbEtoiles = calculerEtoiles(score.getChrono(), score.getNbAide());  Label labelEtoiles = new Label(afficherEtoiles(nbEtoiles));  labelEtoiles.setMinWidth(60);  labelEtoiles.setFont(Font.font(14));  labelEtoiles.setStyle("-fx-text-fill: #FFD700;");  /* Temps (en format MM:SS) */  int secondes = score.getChrono();  int minutes = secondes / 60;  int sec = secondes % 60;  String temps = String.format("%d:%02d", minutes, sec);  Label labelTemps = new Label(temps);  labelTemps.setMinWidth(50);  labelTemps.setFont(Font.font(13));  labelTemps.setStyle("-fx-text-fill: #0066cc;");  /* Nombre d'aides */  Label labelAides = new Label("(" + score.getNbAide() + " aide" + (score.getNbAide() > 1 ? "s" : "") + ")");  labelAides.setFont(Font.font(11));  labelAides.setStyle("-fx-text-fill: gray;");  box.getChildren().addAll(labelRang, labelPseudo, labelEtoiles, labelTemps, labelAides);  return box;  }  /**  * Retourne au menu d'accueil.  */  @FXML  private void retour(ActionEvent event) {  changerFenetre(event, "menuAccueil");  }  /**  * Calcule le nombre d'étoiles obtenues selon le temps et les aides utilisées.  * Logique identique à Score.calculerEtoiles().  *  * @param chrono le temps en secondes  * @param nbAides le nombre d'aides utilisées  * @return le nombre d'étoiles (1 à 3)  */  private int calculerEtoiles(int chrono, int nbAides) {  final int DUREE_POUR_ETOILE = 300; /* 5 minutes */  final int NB_AIDES_MAX = 3;  if (chrono <= DUREE_POUR_ETOILE && nbAides == 0) return 3;  else if (chrono <= DUREE_POUR_ETOILE && nbAides <= NB_AIDES_MAX) return 2;  else return 1;  }  /**  * Formate l'affichage des étoiles, les emojis sont utilisés pour une meilleure lisibilité.  *  * @param nbEtoiles le nombre d'étoiles (1 à 3)  * @return une chaîne avec des étoiles pleines et vides (ex: "★★☆")  */  private String afficherEtoiles(int nbEtoiles) {  String etoilePleine = "★";  String etoileVide = "☆";  StringBuilder sb = new StringBuilder();  for (int i = 0; i < 3; i++) {  sb.append(i < nbEtoiles ? etoilePleine : etoileVide);  }  return sb.toString();  } } public static class ChoixMode extends ChangementFenetre {  public ChoixMode() {}  @FXML  private void aventure(ActionEvent event) {  changerFenetre(event, "choixPartieAventure");  }  @FXML  private void libre(ActionEvent event) {  changerFenetre(event, "choixDifficulte");  }  @FXML  private void retour(ActionEvent event) {  changerFenetre(event, "menuAccueil");  } } /**  * Utilitaire de chargement de fichiers CSV.  * Permet de lire des fichiers CSV et de les convertir en objets Java.  * Gère le chargement depuis le système de fichiers ou depuis les ressources.  *  */ public static class LoadCSV {  public LoadCSV() {}  /**  * Lit un fichier CSV et le convertit en liste d'objets.  * Tente d'abord de lire depuis le système de fichiers, puis depuis les ressources si le fichier n'existe pas.  *  * @param <T> le type des objets à créer depuis le CSV  * @param cheminRessource le chemin de la ressource embarquée (fallback)  * @param cheminFichier le chemin du fichier sur le système de fichiers  * @param clazz la classe des objets à créer  * @return la liste des objets lus, ou une liste vide si erreur  */  public static <T> List<T> lire(String cheminRessource, String cheminFichier, Class<T> clazz) {  if (cheminFichier != null) {  Path path = Paths.get(cheminFichier);  if (Files.exists(path)) {  try (Reader reader = Files.newBufferedReader(path, StandardCharsets.UTF_8)) {  return construireLecture(reader, clazz);  } catch (IOException e) {  e.printStackTrace();  }  }  }  InputStream inputStream = LoadSave.class.getResourceAsStream(cheminRessource);  if (inputStream == null) {  System.err.println("Ressource CSV introuvable: " + cheminRessource);  return Collections.emptyList();  }  try (Reader reader = new InputStreamReader(inputStream, StandardCharsets.UTF_8)) {  return construireLecture(reader, clazz);  } catch (IOException e) {  e.printStackTrace();  return Collections.emptyList();  }  }  /**  * Construit et configure le parser CSV pour lire le fichier.  *  * @param <T> le type des objets à créer  * @param reader le lecteur de flux CSV  * @param clazz la classe cible pour la désérialisation  * @return la liste des objets désérialisés depuis le CSV  */  private static <T> List<T> construireLecture(Reader reader, Class<T> clazz) {  return new CsvToBeanBuilder<T>(reader)  .withType(clazz)  .withIgnoreLeadingWhiteSpace(true)  .build()  .parse();  } } public static abstract class ChangementFenetre {  public ChangementFenetre() {}  protected void changerFenetre(ActionEvent event, String viewName) {  App.changerVue(viewName);  }  protected void changerVueFinPartie(int aides, int aidesMax, String temps, String tempsMax, boolean succes) {  FinPartieAventure controller = (FinPartieAventure) GestionnaireVues.getController("finPartieAventure");  if (controller != null) {  controller.mettreDonnees(aides, aidesMax, temps, tempsMax, succes);  App.changerVue("finPartieAventure");  } else {  System.err.println("Erreur : Le contrôleur finPartieAventure est null !");  }  }  protected void choixPartieAventure(ActionEvent event, String numPartie) {  PartieTimer controller = (PartieTimer) GestionnaireVues.getController("partieTimer");  if (controller != null) {  int numero = Integer.parseInt(numPartie);  controller.initialiserPartie(numero, false);  App.changerVue("partieTimer");  } else {  System.err.println("Erreur : Le contrôleur de la partie est introuvable !");  }  }  protected void choixPartieLibre(ActionEvent event, String difficulte) {  /* 1. Récupérer un nom de fichier valide (ex: "GrilleFacile7X7_2") */  String nomGrille = recupererGrilleAleatoire(difficulte);   if (nomGrille == null) {  System.err.println("Erreur : Aucune grille trouvée pour la difficulté " + difficulte);  return;  }  /* 2. IMPORTANT : On change d'abord la vue pour que l'injection FXML se fasse */  App.changerVue("partie");  /* 3. On récupère le contrôleur de l'instance qui vient d'être affichée */  Partie controller = (Partie) GestionnaireVues.getController("partie");     if (controller != null) {  /* 4. On demande à JavaFX d'exécuter l'initialisation juste après l'affichage */  /* pour garantir que zoneJeu ne soit pas null */  javafx.application.Platform.runLater(() -> {  controller.initialiserPartie(nomGrille);  });  } else {  System.err.println("Erreur : Le contrôleur de la partie est introuvable !");  }  }  public String recupererGrilleAleatoire(String difficulte) {  try {  URL resource = getClass().getResource("/GrilleJson");  if (resource == null) return null;  File dossier = new File(resource.toURI());    /* Filtre : commence par "Grille" + difficulté ET est un fichier (pas le dossier Exemple) */  File[] fichiersTrouves = dossier.listFiles((dir, name) ->   name.startsWith("Grille" + difficulte) && name.endsWith(".json"));    if (fichiersTrouves != null && fichiersTrouves.length > 0) {  Random rand = new Random();  File choix = fichiersTrouves[rand.nextInt(fichiersTrouves.length)];  return choix.getName().replace(".json", "");  }  } catch (Exception e) {  e.printStackTrace();  }  return null;   } } public static class GestionnaireVues {  public GestionnaireVues() {}  private static final Map<String, Parent> views = new HashMap<>();  private static final Map<String, Object> controllers = new HashMap<>();  private static final Map<String, String> fxmlPaths = new HashMap<>(); /* Nouveau : stocke les paths */  /**  * Enregistre une vue sans la charger (lazy loading).  */  public static void registerView(String nom, String fxmlPath) {  fxmlPaths.put(nom, fxmlPath);  }  /**  * Charge une vue immédiatement (ancien comportement).  */  public static void loadView(String nom, String fxmlPath) throws IOException {  FXMLLoader loader = new FXMLLoader(GestionnaireVues.class.getResource(fxmlPath));  Parent root = loader.load();  views.put(nom, root);  controllers.put(nom, loader.getController());  }  /**  * Charge une vue à la demande si elle n'est pas déjà chargée.  */  private static void loadViewIfNeeded(String nom) {  if (!views.containsKey(nom) && fxmlPaths.containsKey(nom)) {  try {  loadView(nom, fxmlPaths.get(nom));  } catch (IOException e) {  System.err.println("Erreur chargement vue " + nom + ": " + e.getMessage());  e.printStackTrace();  }  }  }  public static Object getController(String nom) {  loadViewIfNeeded(nom); /* Charge si besoin */  return controllers.get(nom);  }  public static Parent getView(String nom) {  loadViewIfNeeded(nom); /* Charge si besoin */  return views.get(nom);  } } public static class ChoixPartieAventure extends ChangementFenetre {  public ChoixPartieAventure() {}    /* Déclaration de toutes les étoiles */  @FXML private ImageView etoile_1_1, etoile_1_2, etoile_1_3;  @FXML private ImageView etoile_2_1, etoile_2_2, etoile_2_3;  @FXML private ImageView etoile_3_1, etoile_3_2, etoile_3_3;  @FXML private ImageView etoile_4_1, etoile_4_2, etoile_4_3;  @FXML private ImageView etoile_5_1, etoile_5_2, etoile_5_3;  @FXML private ImageView etoile_6_1, etoile_6_2, etoile_6_3;  @FXML private ImageView etoile_7_1, etoile_7_2, etoile_7_3;  @FXML private ImageView etoile_8_1, etoile_8_2, etoile_8_3;  @FXML private ImageView etoile_9_1, etoile_9_2, etoile_9_3;  @FXML private ImageView etoile_10_1, etoile_10_2, etoile_10_3;  @FXML private ImageView etoile_11_1, etoile_11_2, etoile_11_3;  @FXML private ImageView etoile_12_1, etoile_12_2, etoile_12_3;  private final Image IMAGE_PLEINE = new Image(getClass().getResourceAsStream("/images/etoilePleine.png"));  private final Image IMAGE_VIDE = new Image(getClass().getResourceAsStream("/images/etoileVide.png"));  private ImageView[][] getToutesLesEtoiles() {  return new ImageView[][] {  {etoile_1_1, etoile_1_2, etoile_1_3}, {etoile_2_1, etoile_2_2, etoile_2_3},  {etoile_3_1, etoile_3_2, etoile_3_3}, {etoile_4_1, etoile_4_2, etoile_4_3},  {etoile_5_1, etoile_5_2, etoile_5_3}, {etoile_6_1, etoile_6_2, etoile_6_3},  {etoile_7_1, etoile_7_2, etoile_7_3}, {etoile_8_1, etoile_8_2, etoile_8_3},  {etoile_9_1, etoile_9_2, etoile_9_3}, {etoile_10_1, etoile_10_2, etoile_10_3},  {etoile_11_1, etoile_11_2, etoile_11_3}, {etoile_12_1, etoile_12_2, etoile_12_3}  };  }  private void reinitialiserEtoilesVides() {  for (ImageView[] ligneEtoiles : getToutesLesEtoiles()) {  for (ImageView etoile : ligneEtoiles) {  if (etoile != null) {  etoile.setImage(IMAGE_VIDE);  }  }  }  }  private int extraireNumeroNiveau(String nomFichier) {  if (nomFichier == null) {  return -1;  }  String chiffres = nomFichier.replaceAll("[^0-9]", "");  if (chiffres.isEmpty()) {  return -1;  }  try {  return Integer.parseInt(chiffres);  } catch (NumberFormatException e) {  return -1;  }  }    @FXML  public void initialize() {  rafraichirEtoiles();  }  public void onViewShown() {  rafraichirEtoiles();  }  private void rafraichirEtoiles() {  reinitialiserEtoilesVides();  String pseudoJoueurActuel = Pseudo.nomJoueur == null ? "" : Pseudo.nomJoueur.trim();  if (pseudoJoueurActuel.isEmpty()) {  return;  }  int[] meilleuresEtoiles = new int[13]; /* Indices de 1 à 12 (0 ignoré) */  try {  LoadSave save = LoadSave.getInstance("");  java.util.List<StructureCSV> scores = save.getScores();  for (StructureCSV scoreData : scores) {  /* On vérifie que le score appartient bien au joueur actuel */  if (scoreData.getPseudo() != null && scoreData.getPseudo().trim().equalsIgnoreCase(pseudoJoueurActuel)) {  String nomFichier = scoreData.getNiveau();     if (nomFichier != null) {  /* Extrait uniquement le numéro contenu dans le nom du fichier */  int niveau = extraireNumeroNiveau(nomFichier);    if (niveau >= 1 && niveau <= 12) {  int chrono = scoreData.getChrono();  int nbAides = scoreData.getNbAide();    /* Utilisation de Score.java pour le calcul */  Score calculScore = new Score();  calculScore.setReconstructionSave(chrono, nbAides);  calculScore.calculerEtoiles();  int etoilesPossibles = calculScore.getEtoiles();    /* On garde le meilleur score par niveau */  if (etoilesPossibles > meilleuresEtoiles[niveau]) {  meilleuresEtoiles[niveau] = etoilesPossibles;  }  }  }  }  }  /* Met à jour l'affichage avec les meilleures étoiles stockées */  for (int i = 1; i <= 12; i++) {  if (meilleuresEtoiles[i] > 0) {  afficherEtoiles(i, meilleuresEtoiles[i]);  }  }  } catch (Exception e) {  System.err.println("Erreur lors de la lecture de Score.csv : " + e.getMessage());  }  }  /**  * Remplace l'image des étoiles vides par des étoiles pleines selon le nombre d'étoiles obtenues.  * @param niveau Niveau de 1 à 12  * @param nbEtoiles Nombre d'étoiles gagnées (0 à 3)  */  public void afficherEtoiles(int niveau, int nbEtoiles) {  ImageView[][] toutesLesEtoiles = getToutesLesEtoiles();  if (niveau >= 1 && niveau <= 12 && nbEtoiles > 0) {  for (int i = 0; i < Math.min(nbEtoiles, 3); i++) {  if (toutesLesEtoiles[niveau - 1][i] != null) {  toutesLesEtoiles[niveau - 1][i].setImage(IMAGE_PLEINE);  }  }  }  }  @FXML  private void retour(ActionEvent event) {  changerFenetre(event, "choixMode");  }  /* load partie en fonction du bouton cliqué (load la vue "partie" avec le numero de la partie cliquée) */  @FXML  public void partie(ActionEvent event) {  Button b = (Button) event.getSource();  String niveau = b.getId().replace("btn", "");   choixPartieAventure(event, niveau);  /* méthode dans changementfenetre.java */  } } public static class PartieTimer extends Partie {  public PartieTimer() {}  private static int numPartie;  @FXML  private Label timerLabel;  /* chrono visuel */  private Timeline chronometre;  @Override  public void onVictoire(Score score) {  saveScore(score);  /* Arrêter le chrono visuel */  if (chronometre != null) chronometre.stop();    /* Arrêter le chrono réel et calculer les étoiles */  score.arreterChrono();  score.calculerEtoiles();  /* Récupérer les données réelles du Score pour l'écran de fin */  int aidesUtilisees = score.getNbAidesUtilisees();  int aidesMax = score.getNbAidexMax();    String tempsFinal = formatTime((int) score.getDureeEnSecondes());  String tempsMaxEtoile = formatTime((int) score.getDureePourEtoile());  System.out.println("fin de la partie");  changerVueFinPartie(aidesUtilisees, aidesMax, tempsFinal, tempsMaxEtoile, true);  }  private void saveScore(Score score) {  String grille = Partie.getGrilleEnCours();  if (grille == null || grille.isBlank()) {  grille = numPartie > 0 ? "partie" + numPartie : "tutoriel";  }  if ("tutoriel".equalsIgnoreCase(grille) || "tutoriel".equalsIgnoreCase(Partie.getDernierMode())) {  return;  }  String pseudo = this.moteurJeu.getProfil().getPseudo();  int nbAide = score.getNbAidesUtilisees();  int chrono = (int) score.getDureeEnSecondes();  LoadSave save = LoadSave.getInstance("");  SaveManager saveManager = new SaveManager(save);  saveManager.ajouterScoreEtSauvegarderCsv(  new StructureCSV(pseudo, grille, nbAide, chrono),  ""  );  String pathGrille = "./save/saveGrille/" + grille + ".json";  Integer idFichier = saveManager.trouverIdSauvegardeParPseudoEtPath(pseudo, pathGrille);  if (idFichier != null) {  saveManager.delFichierId(idFichier);  }  }  @Override  public void onEtatChange(EtatPartie etat) {  if (etat == EtatPartie.PAUSE) {  if (chronometre != null) chronometre.pause();  if (moteurJeu != null) moteurJeu.getScore().pauseChrono();  } else if (etat == EtatPartie.EN_COURS) {  if (chronometre != null) chronometre.play();  if (moteurJeu != null) moteurJeu.getScore().demarrerChrono();  }  }  @FXML   public void initialize(){  chronometre = new Timeline(new KeyFrame(Duration.seconds(1), event -> {  actualiseChrono();  }));  chronometre.setCycleCount(Timeline.INDEFINITE);  }  private void actualiseChrono() {  if (timerLabel != null && moteurJeu != null) {  int secondes = (int) moteurJeu.getScore().getDureeEnSecondes();  timerLabel.setText(formatTime(secondes));  }  }  private String formatTime(int totalSeconds) {  int minutes = totalSeconds / 60;  int seconds = totalSeconds % 60;  return String.format("%02d:%02d", minutes, seconds);  }  @FXML  @Override  public void menuPause(ActionEvent event) {  if (moteurJeu != null) moteurJeu.mettreEnPause();   super.menuPause(event);  }  @FXML  private void aide(ActionEvent event) {  if (moteurJeu != null) {  moteurJeu.utiliserAide();   }  }  @FXML  public void initialiserPartie(int numero, boolean recommencer) {  numPartie = numero;  Partie.setDernierMode("aventure");   Matrice mat = Matrice.loadGrille("partie" + numero);  if (mat == null) {  System.err.println("Erreur de chargement de la grille");  return;  }  /* Lecture de la sauvegarde ici, si elle n'est pas lu, créer la sauvegarde */  Partie.nomGrille = "partie" + numero;  Score score = new Score();  if(!recommencer){  boolean loaded = mat.loadSave(Pseudo.nomJoueur, "./save/saveGrille/partie" + numero + ".json", true);  if(!loaded){  /* Creer la référence de sauvegarde ici */  SaveHelper saveHelper = SaveHelper.getInstance();  saveHelper.ajouterPartieAventure(LoadSave.getInstance(""), Pseudo.nomJoueur, "partie" + numero);  SaveManager saveManager = new SaveManager(LoadSave.getInstance(""));  saveManager.actualiserSaveGlobal();  } else {  var sauvegarde = rechercheSave.trouverSauvegardeParPseudoEtPath(  Pseudo.nomJoueur,  "./save/saveGrille/partie" + numero + ".json"  );  if (sauvegarde != null && sauvegarde.getDetailleSave() != null) {  Integer chronoInt = sauvegarde.getDetailleSave().getChronometre();  if (chronoInt != null) {  score.setDureeAccumulee(java.time.Duration.ofSeconds(chronoInt.longValue()));  }  Integer nbAides = sauvegarde.getDetailleSave().getNbAides();  if (nbAides != null) {  score.setNbAidesUtilisees(nbAides);  }  }  }  } else {  /* Si on recommence, réinitialiser la sauvegarde existante */  LoadSave save = LoadSave.getInstance("");  save.rechargerSaveGlobal();  var sauvegarde = rechercheSave.trouverSauvegardeParPseudoEtPath(  Pseudo.nomJoueur,  "./save/saveGrille/partie" + numero + ".json"  );  if (sauvegarde != null && sauvegarde.getId() != null) {  /* Réinitialiser le détail de la sauvegarde (grille vide, chrono à 0, 0 aides) */  DetailleSavePartie nouveauDetail = DetailleSavePartie.create(new ArrayList<>(), 0, 0);  nouveauDetail.setNameClass(sauvegarde.getId().toString());  sauvegarde.setDetailleSave(nouveauDetail);  SaveManager saveManager = new SaveManager(save);  saveManager.updateSaveFichierId(sauvegarde.getId());  saveManager.actualiserSaveGlobal();  }  }  this.moteurJeu = new PartieHelper(new Profil(Pseudo.nomJoueur), mat, 3, score);  this.moteurJeu.ajouterObserver(this);    chargerMatrice(mat);  actualiseChrono();  System.out.println(mat);    this.moteurJeu.demarrer();   chronometre.play();  }  @FXML   public void lancerTutoriel() {  numPartie = -1;   Partie.setDernierMode("tutoriel");    Matrice mat = Matrice.loadGrille("tutoriel");  if (mat == null) return;  this.moteurJeu = new PartieHelper(new Profil("Apprenti"), mat, 99, new Score());  this.moteurJeu.ajouterObserver(this);  chargerMatrice(mat);  actualiseChrono();  this.moteurJeu.demarrer();  chronometre.play();  }    public void reprendrePartie() {  if (moteurJeu != null) {  moteurJeu.demarrer();   }  }  public static int getNumPartie() {  return numPartie;  } } /**  * Interface pour les différentes stratégies de détection d'aides.  * Chaque stratégie implémente un pattern SlitherLink spécifique.  *  * @author Enzo Desfaudais (B0rno)  * @version 1.0  */ public static interface StrategieAide {  /**  * Vérifie si cette stratégie peut trouver une aide sur la matrice.  *  * @param m la matrice du jeu  * @return true si une aide est disponible  */  boolean estApplicable(Matrice m);  /**  * Trouve et retourne la première aide détectée par cette stratégie.  *  * @param m la matrice du jeu  * @return l'aide trouvée, ou null si aucune aide n'est disponible  */  Aide trouverAide(Matrice m);  /**  * Retourne le nom de cette stratégie (pour le debug).  *  * @return le nom de la stratégie  */  String getNom(); } /**  * Utilitaire de sauvegarde de fichiers CSV.  * Permet de convertir une liste d'objets Java en fichier CSV.  * Crée automatiquement les répertoires parents si nécessaire.  */ public static class SaveCSV {  public SaveCSV() {}  /**  * Sauvegarde une liste d'objets dans un fichier CSV.  * Crée les répertoires parents si nécessaire.  *  * @param <T> le type des objets à sauvegarder  * @param listToSave la liste d'objets à convertir en CSV  * @param fichier le chemin du fichier de destination  */  public static <T> void sauvegarder(List<T> listToSave, String fichier) {  Path path = Paths.get(fichier);  try {  Path parent = path.getParent();  if (parent != null) {  Files.createDirectories(parent);  }  try (Writer writer = Files.newBufferedWriter(path, StandardCharsets.UTF_8)) {  StatefulBeanToCsv<T> beanToCsv = new StatefulBeanToCsvBuilder<T>(writer).build();  beanToCsv.write(listToSave == null ? Collections.emptyList() : listToSave);  }  } catch (IOException e) {  e.printStackTrace();  } catch (Exception e) {  e.printStackTrace();  }  } } /**  * Classe représentant le lien entre un joueur et une sauvegarde de partie.  * Permet de charger et de gérer les détails d'une sauvegarde associée à un joueur.  */ public static class savePartieLienJoueur {  private static final String pathLienJoueurSave = "/save/saveJoueur/";  private static String basePath = "";  private String pseudo;  private Integer id;  private String path;  private transient DetailleSavePartie detailleSave;  /**  * Constructeur par défaut pour la désérialisation.  */  savePartieLienJoueur() {}  /**  * Constructeur pour créer un lien entre un joueur et une sauvegarde.  *  * @param pseudo Le pseudo du joueur.  * @param id L'identifiant unique de la sauvegarde.  * @param path Le chemin vers le fichier de sauvegarde.  */  savePartieLienJoueur(String pseudo, Integer id, String path) {  this.pseudo = pseudo;  this.id = id;  this.path = path;  }  /**  * Crée une instance de {@link savePartieLienJoueur}.  *  * @param pseudo Le pseudo du joueur.  * @param id L'identifiant unique de la sauvegarde.  * @param path Le chemin vers le fichier de sauvegarde.  * @return Une nouvelle instance de {@link savePartieLienJoueur}.  */  public static savePartieLienJoueur create(String pseudo, Integer id, String path) {  return new savePartieLienJoueur(pseudo, id, path);  }  /**  * Définit le chemin de base pour les fichiers de sauvegarde.  *  * @param basePathParam Le chemin de base.  */  public static void setBasePath(String basePathParam) {  basePath = basePathParam == null ? "" : basePathParam;  }  /**  * Charge les détails de la sauvegarde associée à ce lien.  * Lit le fichier JSON correspondant et désérialise les données.  */  public void loadDetailleSave() {  if (id == null) {  return;  }  String pathSaveJoeur = pathLienJoueurSave + id + ".json";  Gson gson = new Gson();  try (Reader reader = ouvrirReader(pathSaveJoeur)) {  if (reader == null) {  System.err.println("Ressource/Fichier introuvable: " + pathSaveJoeur);  return;  }  detailleSave = gson.fromJson(reader, DetailleSavePartie.class);  } catch (IOException e) {  e.printStackTrace();  }  if (this.detailleSave != null) {  this.detailleSave.setNameClass(this.id != null ? this.id.toString() : null);  }  }  /**  * Ouvre un lecteur pour lire un fichier JSON.  *  * @param cheminRessource Le chemin vers la ressource ou le fichier.  * @return Un {@link Reader} pour lire le fichier, ou null si le fichier est introuvable.  * @throws IOException En cas d'erreur d'entrée/sortie.  */  private Reader ouvrirReader(String cheminRessource) throws IOException {  if (basePath != null && !basePath.isBlank()) {  String relatif = cheminRessource.startsWith("/") ? cheminRessource.substring(1) : cheminRessource;  Path fichierExterne = Paths.get(basePath, relatif);  if (Files.exists(fichierExterne)) {  return Files.newBufferedReader(fichierExterne, StandardCharsets.UTF_8);  }  }  InputStream is = savePartieLienJoueur.class.getResourceAsStream(cheminRessource);  if (is == null) {  return null;  }  return new InputStreamReader(is, StandardCharsets.UTF_8);  }  /**  * Force le rechargement des détails de la sauvegarde.  * Permet derécupérer les dernières modifications.  */  public void reloadDetailleSave() {  detailleSave = null;  loadDetailleSave();  }  /**  * Retourne les détails de la sauvegarde associée.  * Charge les détails si ce n'est pas encore fait.  *  * @return Les détails de la sauvegarde.  */  public DetailleSavePartie getDetailleSave() {  if (detailleSave == null) {  loadDetailleSave();  }  return detailleSave;  }  /**  * Définit les détails de la sauvegarde associée.  *  * @param detailleSave Les détails de la sauvegarde.  */  public void setDetailleSave(DetailleSavePartie detailleSave) {  this.detailleSave = detailleSave;  if (this.detailleSave != null && this.id != null) {  this.detailleSave.setNameClass(this.id.toString());  }  }  /* Getters et setters pour les champs privés */  public String getPseudo() {  return pseudo;  }  public Integer getId() {  return id;  }  public String getPath() {  return path;  }  public void setPseudo(String pseudo) {  this.pseudo = pseudo;  }  public void setId(Integer id) {  this.id = id;  }  public void setPath(String path) {  this.path = path;  } } /**  * Technique: Contraintes sur 3  * Détecte les situations où un 3 est adjacent à un 0 et possède déjà un trait plein du côté du 0. Cette configuration permet de déduire les autres traits autour du 3.  * Pattern de base de SlitherLink niveau basique.  *  * @author Enzo Desfaudais (B0rno)  * @version 1.0  */ public static class ContraintesSur3 implements StrategieAide {  public ContraintesSur3() {}  private static final String NOM = "Contraintes sur 3";  /**  * Vérifie si cette technique peut être appliquée sur la matrice.  * Cherche un 0 adjacent à un 3 qui possède déjà un trait plein du côté du 0 .  *  * @param m la matrice du jeu à analyser  * @return true si un cas applicable est trouvé, false sinon  */  @Override  public boolean estApplicable(Matrice m) {  for (int i = 0; i < m.getHauteur(); i++) {  for (int j = 0; j < m.getLargeur(); j++) {  Case c = m.getCase(i, j);  if(c != null && c.getNumero() == 3) {  /* Test Nord */  if(m.getCase(i-1, j) != null && m.getCase(i-1, j).getNumero() == 0 && m.getCase(i, j).getTrait(0).getEtat() == ValeurTrait.PLEIN) {  return true;  }  /* Test Sud */  if(m.getCase(i+1, j) != null && m.getCase(i+1, j).getNumero() == 0 && m.getCase(i, j).getTrait(3).getEtat() == ValeurTrait.PLEIN) {  return true;  }  /* Test Est */  if(m.getCase(i, j+1) != null && m.getCase(i, j+1).getNumero() == 0 && m.getCase(i, j).getTrait(2).getEtat() == ValeurTrait.PLEIN) {  return true;  }  /* Test Ouest */  if(m.getCase(i, j-1) != null && m.getCase(i, j-1).getNumero() == 0 && m.getCase(i, j).getTrait(1).getEtat() == ValeurTrait.PLEIN) {  return true;  }  }  }  }  return false;  }  /**  * Trouve et retourne une aide basée sur cette technique.  * Charge la description complète depuis le JSON et crée un objet Aide.  *  * @param m la matrice du jeu à analyser  * @return une aide avec le nom et la description de la technique, ou null si non applicable  */  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  /**  * Retourne le nom de cette technique.  *  * @return le nom "Contraintes sur 3"  */  @Override  public String getNom() {  return NOM;  } } /**  * Technique: Deux 3 adjacents  * Parcourt la matrice pour vérifier s'il y a deux '3' adjacents.  * L'aide est applicable s'il manque encore des traits sur et à l'opposé de leur côté partagé.  */ public static class Deux3Adjacents implements StrategieAide {  public Deux3Adjacents() {}  private static final String NOM = "Deux 3 adjacents";  /**  * @param m La matrice du jeu  * @return true si l'aide est applicable  */  @Override  public boolean estApplicable(Matrice m) {  for (int i = 0; i < m.getHauteur(); i++) {  for (int j = 0; j < m.getLargeur(); j++) {  Case c = m.getCase(i, j);  if (c != null && c.getNumero() == 3) {  Case cHaut = m.getCase(i - 1, j);  Case cBas = m.getCase(i + 1, j);  Case cGauche = m.getCase(i, j - 1);  Case cDroite = m.getCase(i, j + 1);  if ((cGauche != null && cGauche.getNumero() == 3) || (cDroite != null && cDroite.getNumero() == 3)) {  if (c.getTrait(1).getEtat() == (ValeurTrait.VIDE) || c.getTrait(2).getEtat() == ValeurTrait.VIDE)   return true;  if (c.getTrait(1).getEtat() == (ValeurTrait.CROIX) || c.getTrait(2).getEtat() == ValeurTrait.CROIX)   return true;  }  if ((cHaut != null && cHaut.getNumero() == 3) || (cBas != null && cBas.getNumero() == 3)) {  if (c.getTrait(0).getEtat() == ValeurTrait.VIDE || c.getTrait(3).getEtat() == ValeurTrait.VIDE)   return true;  if (c.getTrait(0).getEtat() == ValeurTrait.CROIX || c.getTrait(3).getEtat() == ValeurTrait.CROIX)   return true;  }  }  }  }  return false;  }  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  @Override  public String getNom() {  return NOM;  } } /**  * Technique : Contraintes sur un 2 (Diagonale forcée)  * Détecte les situations où la boucle arrive sur le coin d'un '2' alors qu'un des  * deux chemins possibles est bloqué par une croix (X). La boucle est alors forcée  * d'emprunter l'autre côté adjacent au sommet pour satisfaire la contrainte du chiffre.  *  * @author Lucas Abeka-Doth (lucasabeka)  * @version 1.0  */ public static class ContraintesSur2 implements StrategieAide {  public ContraintesSur2() {}  private static final String NOM = "Contraintes sur un 2";  /**  * Vérifie si cette technique peut être appliquée sur la matrice.  * Cherche un segment de boucle arrivant sur un sommet d'un '2' dont l'une  * des sorties est obstruée par une croix.  *  * @param m la matrice du jeu à analyser  * @return true si un trait peut être déduit de cette configuration, false sinon  */  @Override  public boolean estApplicable(Matrice m) {  for (int i = 0; i < m.getHauteur(); i++) {  for (int j = 0; j < m.getLargeur(); j++) {  Case c = m.getCase(i, j);  /* On analyse uniquement les cases contenant le chiffre 2 */  if (c != null && c.getNumero() == 2) {  /* Coin haut gauche (nord ouest) */  /* Si la boucle arrive sur ce coin (trait horizontal à gauche ou vertical au-dessus) */  if (estPleinExt(m, i, j - 1, true) || estPleinExt(m, i - 1, j, false)) {  /* Si le haut (0) est une croix, alors la gauche (1) doit être plein (ou inversement) */  if (verifContrainteCoin(c, 0, 1)) return true;  }  /* Coin haut droite (nord est) */  /* Si la boucle arrive sur ce coin (trait horizontal à droite ou vertical au-dessus) */  if (estPleinExt(m, i, j + 1, true) || estPleinExt(m, i - 1, j + 1, false)) {  if (verifContrainteCoin(c, 0, 2)) return true;  }  /* Coin bas gauche (sud ouest) */  /* Si la boucle arrive sur ce coin (trait horizontal à gauche ou vertical en-dessous) */  if (estPleinExt(m, i + 1, j - 1, true) || estPleinExt(m, i + 1, j, false)) {  if (verifContrainteCoin(c, 3, 1)) return true;  }  /* Coin bas droite (sud est) */  /* Si la boucle arrive sur ce coin (trait horizontal à droite ou vertical en-dessous) */  if (estPleinExt(m, i + 1, j + 1, true) || estPleinExt(m, i + 1, j + 1, false)) {  if (verifContrainteCoin(c, 3, 2)) return true;  }  }  }  }  return false;  }  /**  * Vérifie si, sur un coin donné, un côté est bloqué (croix) et l'autre est encore vide.  *  * @param c La case à analyser (contenant un 2).  * @param dir1 L'index du premier trait formant le sommet.  * @param dir2 L'index du second trait formant le sommet.  * @return vrai si l'un est une croix et l'autre est vide (déduction possible).  */  private boolean verifContrainteCoin(Case c, int dir1, int dir2) {  /* Si le premier chemin est bloqué, le second devient obligatoire (s'il est encore vide) */  if (c.getTrait(dir1).getEtat() == ValeurTrait.CROIX && c.getTrait(dir2).getEtat() == ValeurTrait.VIDE)  return true;  /* Si le second chemin est bloqué, le premier devient obligatoire (s'il est encore vide) */  if (c.getTrait(dir2).getEtat() == ValeurTrait.CROIX && c.getTrait(dir1).getEtat() == ValeurTrait.VIDE)  return true;  return false;  }  /**  * Vérifie l'état d'un trait situé à la périphérie d'une case (potentiellement sur les bords de la grille).  * Cette méthode sécurise l'accès aux traits horizontaux et verticaux en gérant les indices  * limites pour éviter les erreurs de type IndexOutOfBounds.  *  * @param m La matrice de jeu à analyser.  * @param ligne L'indice de ligne du trait.  * @param col L'indice de colonne du trait.  * @param horizontal Vrai si le trait testé est horizontal, faux s'il est vertical.  * @return vrai (true) si le trait existe et qu'il est marqué comme "PLEIN", faux (false) sinon  */  private boolean estPleinExt(Matrice m, int ligne, int col, boolean horizontal) {  if (horizontal) {  if (ligne < 0 || ligne > m.getHauteur() || col < 0 || col >= m.getLargeur()) return false;  /* Accès sécurisé au trait horizontal via la matrice */  return m.getCase(ligne < m.getHauteur() ? ligne : ligne-1, col).getTrait(ligne < m.getHauteur() ? 0 : 3).getEtat() == ValeurTrait.PLEIN;  } else {  if (ligne < 0 || ligne >= m.getHauteur() || col < 0 || col > m.getLargeur()) return false;  return m.getCase(ligne, col < m.getLargeur() ? col : col-1).getTrait(col < m.getLargeur() ? 1 : 2).getEtat() == ValeurTrait.PLEIN;  }  }  /**  * Trouve et retourne une aide basée sur cette technique.  * Charge la description complète depuis le JSON et crée un objet Aide.  *  * @param m la matrice du jeu à analyser  * @return une aide avec le nom et la description de la technique, ou null si non applicable  */  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  /**  * Retourne le nom de cette technique.  *  * @return le nom "Contraintes sur un 2"  */  @Override  public String getNom() {  return NOM;  } } /**  * Technique : Boucle atteignant un 3  * Détecte les situations où un segment de la boucle arrive perpendiculairement sur  * l'un des sommets d'une case '3'. Cette configuration force la boucle à emprunter  * les deux côtés du '3' qui ne touchent pas ce sommet.  * Pattern de base de SlitherLink pour la continuité du chemin.  *  * @author Lucas Abeka-Doth (lucasabeka)  * @version 1.0  */ public static class BoucleSur3 implements StrategieAide {  public BoucleSur3() {}  private static final String NOM = "Boucle atteignant un 3";  /**  * Vérifie si cette technique peut être appliquée sur la matrice.  * Cherche un trait plein arrivant sur le coin d'un 3 depuis l'extérieur,  * ce qui permet de déduire les segments opposés de cette case.  *  * @param m la matrice du jeu à analyser  * @return true si des traits peuvent être déduits, false sinon  */  @Override  public boolean estApplicable(Matrice m) {  for (int i = 0; i < m.getHauteur(); i++) {  for (int j = 0; j < m.getLargeur(); j++) {  Case c = m.getCase(i, j);  /* On cible uniquement les cases contenant un 3 */  if (c != null && c.getNumero() == 3) {  /* Test coin haut-gauche (Nord-Ouest) */  /* Si un trait arrive de la gauche ou du haut vers ce coin */  if (estPlein(m, i, j - 1, true) || estPlein(m, i - 1, j, false)) {  /* Alors les murs opposés (droite : 2 et bas : 3) doivent être tracés */  if (c.getTrait(2).getEtat() == ValeurTrait.VIDE ||  c.getTrait(3).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  /* Test haut-droite (Nord-Est) */  /* Si un trait arrive de la droite ou du haut vers ce coin */  if (estPlein(m, i, j + 1, true) || estPlein(m, i - 1, j + 1, false)) {  /* Alors les murs opposés (gauche : 1 et bas : 3) doivent être tracés */  if (c.getTrait(1).getEtat() == ValeurTrait.VIDE ||  c.getTrait(3).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  /* Test bas-gauche (Sud-Ouest) */  /* Si un trait arrive de la gauche ou du bas vers ce coin */  if (estPlein(m, i + 1, j - 1, true) || estPlein(m, i + 1, j, false)) {  /* Alors les murs opposés (haut : 0 et droite : 2) doivent être tracés */  if (c.getTrait(0).getEtat() == ValeurTrait.VIDE ||  c.getTrait(2).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  /* Test bas-droite (Sud-Est) */  /* Si un trait arrive de la droite ou du bas vers ce coin */  if (estPlein(m, i + 1, j + 1, true) || estPlein(m, i + 1, j + 1, false)) {  /* Alors les murs opposés (haut : 0 et gauche : 1) doivent être tracés */  if (c.getTrait(0).getEtat() == ValeurTrait.VIDE ||  c.getTrait(1).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  }  }  }  return false;  }  /**  * Vérifie si un trait est "Plein" sans sortir des limites de la grille.  *  * @param m la matrice du jeu contenant l'état actuel des traits  * @param ligne l'indice de la ligne où se situe le trait  * @param col l'indice de la colonne où se situe le trait  * @param horizontal vrai (true) si on teste un trait horizontal, faux (false) pour un trait vertical  * @return vrai (true) si le trait existe et qu'il est marqué comme "PLEIN", faux (false) sinon  */  private boolean estPlein(Matrice m, int ligne, int col, boolean horizontal) {  if (horizontal) {  if (ligne < 0 || ligne > m.getHauteur() || col < 0 || col >= m.getLargeur()) return false;  Case c = m.getCase(ligne, col);  return (c != null && c.getTrait(0).getEtat() == ValeurTrait.PLEIN);  } else {  if (ligne < 0 || ligne >= m.getHauteur() || col < 0 || col > m.getLargeur()) return false;  Case c = m.getCase(ligne, col);  return (c != null && c.getTrait(1).getEtat() == ValeurTrait.PLEIN);  }  }  /**  * Trouve et retourne une aide basée sur cette technique.  * Charge la description complète depuis le JSON et crée un objet Aide.  *  * @param m la matrice du jeu à analyser  * @return une aide avec le nom et la description de la technique, ou null si non applicable  */  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  /**  * Retourne le nom de cette technique.  *  * @return le nom "Boucle atteignant un 3"  */  @Override  public String getNom() {  return NOM;  } } /**  * Gestionnaire central de chargement des données du jeu (Singleton).  * Charge et gère toutes les ressources JSON et CSV au démarrage de l'application.  *  * Données gérées:  * - Grilles de jeu (mode libre et aventure)  * - Techniques d'aide  * - Sauvegardes globales  * - Scores CSV  *  * Utilise un système de fallback: fichier système puis ressource embarquée.  */ public static class LoadSave {  private static LoadSave instance;  private SaveGrille grille;  private Map<String, SaveGrille> grilles;  private SaveTechnique technique;  private SaveGlobal saveGlobal;  private List<StructureCSV> scores;  private final String basePath;  /**  * Récupère l'instance unique du gestionnaire de chargement.  * Crée l'instance si elle n'existe pas encore.  *  * @param pathBeforeSave le chemin de base pour les fichiers (vide pour auto-détection)  * @return l'instance unique de LoadSave  */  public static synchronized LoadSave getInstance(String pathBeforeSave) {  if (instance == null) {  instance = new LoadSave(pathBeforeSave);  }  return instance;  }  /**  * Constructeur privé (Singleton).  * Charge toutes les données du jeu au démarrage: grilles, techniques, sauvegardes et scores.  *  * @param pathBeforeSave le chemin de base pour les fichiers  */  private LoadSave(String pathBeforeSave) {  this.basePath = determinerBasePath(pathBeforeSave);  savePartieLienJoueur.setBasePath(this.basePath);  Gson gson = new Gson();  technique = lireJson("/save/technique.json", cheminFichier("save/technique.json"), SaveTechnique.class, gson);  saveGlobal = lireJson("/save/saveGlobal.json", cheminFichier("save/saveGlobal.json"), SaveGlobal.class, gson);  rechercheSave.setSaveGlobalCourant(saveGlobal);  grilles = chargerGrilles(gson);  grille = choisirGrilleParDefaut();  scores = LoadCSV.lire("/save/Score.csv", cheminFichier("save/Score.csv") , StructureCSV.class);  }  /**  * Charge toutes les grilles depuis les dossiers GrilleJson (racine et Aventure).  * Scanne le système de fichiers puis utilise les ressources en fallback.  */  private Map<String, SaveGrille> chargerGrilles(Gson gson) {  Map<String, SaveGrille> resultat = new LinkedHashMap<>();    /* Liste des sous-dossiers à scanner dans GrilleJson */  String[] sousDossiers = {"", "Aventure"}; /* "" pour la racine (Libre), "Aventure" */    for (String sousDir : sousDossiers) {  /* Construction des chemins physiques possibles */  Path[] cheminsPossibles = {  Paths.get(System.getProperty("user.dir"), "src/main/resources/GrilleJson", sousDir),  Paths.get(basePath, "GrilleJson", sousDir),  Paths.get("src/main/resources/GrilleJson", sousDir)  };    boolean dossierTrouveSurDisque = false;  for (Path dossier : cheminsPossibles) {  if (Files.isDirectory(dossier)) {  try (var fichiers = Files.list(dossier)) {  fichiers  .filter(Files::isRegularFile)  .filter(path -> path.getFileName().toString().toLowerCase().endsWith(".json"))  .forEach(path -> {  String nom = retirerExtension(path.getFileName().toString());  /* On utilise lireJson pour bénéficier de la double sécurité (Fichier puis Ressource) */  SaveGrille g = lireJson("/GrilleJson/" + (sousDir.isEmpty() ? "" : sousDir + "/") + path.getFileName().toString(),   path.toString(), SaveGrille.class, gson);  if (g != null) {  resultat.put(nom, g);  }  });  dossierTrouveSurDisque = true;  } catch (IOException e) {  System.err.println("Erreur lors du scan du dossier : " + dossier);  }  break; /* On a trouvé le dossier physique, on passe au sous-dossier suivant */  }  }    /* Si le scan disque a échoué pour ce dossier (cas du JAR), on peut tenter un chargement manuel */  /* par ressource pour des grilles spécifiques si nécessaire. */  if (!dossierTrouveSurDisque) {  System.out.println("Dossier physique non trouvé pour " + (sousDir.isEmpty() ? "racine" : sousDir) + ", utilisation des ressources.");  /* Note : Lister des fichiers à l'intérieur d'un JAR est complexe sans bibliothèque tierce. */  /* Si tu es dans un JAR, assure-toi que tes chemins de ressources sont corrects. */  }  }    return resultat;  }  /**  * Extrait les noms de grilles depuis les sauvegardes globales.  */  private Set<String> extraireNomsGrillesDepuisSaveGlobal() {  Set<String> noms = new HashSet<>();  if (saveGlobal == null) {  return noms;  }  java.util.function.Consumer<List<savePartieLienJoueur>> collecteur = list -> {  if (list == null) {  return;  }  for (savePartieLienJoueur partie : list) {  if (partie == null || partie.getPath() == null || partie.getPath().isBlank()) {  continue;  }  String fichier = Paths.get(partie.getPath().replace("\\", "/")).getFileName().toString();  if (fichier.toLowerCase().endsWith(".json")) {  noms.add(retirerExtension(fichier));  }  }  };  collecteur.accept(saveGlobal.getSauvegardeLibre());  collecteur.accept(saveGlobal.getSauvegardeAventure());  return noms;  }  /**  * Retire l'extension d'un nom de fichier.  */  private String retirerExtension(String nomFichier) {  int index = nomFichier.lastIndexOf('.');  if (index <= 0) {  return nomFichier;  }  return nomFichier.substring(0, index);  }  /**  * Choisit la grille par défaut (priorité à grilleJeu1, sinon la première disponible).  */  private SaveGrille choisirGrilleParDefaut() {  if (grilles == null || grilles.isEmpty()) {  return null;  }  if (grilles.containsKey("grilleJeu1")) {  return grilles.get("grilleJeu1");  }  return grilles.values().iterator().next();  }  /**  * Détermine le chemin de base pour les fichiers.  * Essaie le chemin fourni, puis le JAR, puis le répertoire courant.  */  private String determinerBasePath(String pathBeforeSave) {  if (pathBeforeSave != null && !pathBeforeSave.isBlank()) {  return Paths.get(pathBeforeSave).toAbsolutePath().normalize().toString();  }  try {  URI location = LoadSave.class.getProtectionDomain().getCodeSource().getLocation().toURI();  Path codeSourcePath = Paths.get(location).toAbsolutePath().normalize();  if (Files.isRegularFile(codeSourcePath) && codeSourcePath.toString().endsWith(".jar")) {  Path parent = codeSourcePath.getParent();  if (parent != null) {  return parent.toString();  }  }  } catch (Exception ignored) {  }  return Paths.get(System.getProperty("user.dir", ".")).toAbsolutePath().normalize().toString();  }  /**  * Construit un chemin de fichier absolu à partir du basePath et d'un chemin relatif.  */  private String cheminFichier(String cheminRelatif) {  return Paths.get(basePath, cheminRelatif).toString();  }  /**  * Lit un fichier JSON avec fallback sur les ressources embarquées.  * Essaie d'abord de lire depuis le système de fichiers, puis depuis les ressources.  */  private <T> T lireJson(String cheminRessource, String cheminFichier, Class<T> type, Gson gson) {  if (cheminFichier != null) {  Path path = Paths.get(cheminFichier);  if (Files.exists(path)) {  try (Reader reader = Files.newBufferedReader(path, StandardCharsets.UTF_8)) {  return gson.fromJson(reader, type);  } catch (IOException e) {  e.printStackTrace();  }  }  }  InputStream is = LoadSave.class.getResourceAsStream(cheminRessource);  if (is == null) {  System.err.println("Ressource introuvable: " + cheminRessource);  return null;  }  try (Reader reader = new InputStreamReader(is, StandardCharsets.UTF_8)) {  return gson.fromJson(reader, type);  } catch (IOException e) {  e.printStackTrace();  return null;  }  }  /**  * Recharge le SaveGlobal depuis le fichier JSON .  * Permet de récupérer les dernières modifications après une sauvegarde.  */  public void rechargerSaveGlobal() {  Gson gson = new Gson();  saveGlobal = lireJson("/save/saveGlobal.json", cheminFichier("save/saveGlobal.json"), SaveGlobal.class, gson);  rechercheSave.setSaveGlobalCourant(saveGlobal);  }  /**  * Affiche toutes les techniques chargées (debug).  */  public void afficherTechn() {  if (technique != null && technique.getStockageLangague() != null) {  for (languageContenue langcont : technique.getStockageLangague()) {  if (langcont == null) continue;  System.out.println("Langage: " + langcont.getLangage());  List<contenuTechnique> contenus = langcont.getContenu();  if (contenus == null) continue;  for (contenuTechnique contenu : contenus) {  if (contenu == null) continue;  System.out.println("----------------\nNiveau: " + contenu.getNv());  List<stockageTechnique> techs = contenu.getTechniqueParsNv();  if (techs == null) {  System.out.println("Aucune technique disponible pour ce niveau.");  continue;  }  for (stockageTechnique tech : techs) {  if (tech == null) continue;  System.out.println("----------------\nNom de la technique: " + tech.getName());  System.out.println("----------------Description----------------\n" + tech.getDescription());  }  }  }  } else {  System.out.println("Aucune technique disponible.");  }  }  /**  * Affiche une grille spécifique (debug).  */  public void afficherGrille(String nomGrille, SaveGrille grille) {  if (grille != null) {  System.out.println("Nom de la grille: " + nomGrille);  System.out.println("Taille de la grille: " + grille.getTailleGrille());  List<positionGrille> cases = grille.getNumeroCases();  if (cases != null) {  for (positionGrille posgrille : cases) {  if (posgrille == null) continue;  System.out.println("----------------\nPosition: " + posgrille.getPositionGrille());  System.out.println("Valeur: " + posgrille.getValeurGrille());  }  } else {  System.out.println("Aucune case disponible dans la grille.");  }  } else {  System.out.println("Aucune grille disponible.");  }  }  /**  * Affiche la grille et les techniques en JSON (debug).  */  public void affichertoJson() {  Gson gson = new Gson();  String jsonGrille = gson.toJson(grille);  String jsonTechnique = gson.toJson(technique);  System.out.println("Grille en JSON:\n" + jsonGrille);  System.out.println("Technique en JSON:\n" + jsonTechnique);  }  /**  * Récupère la liste des traits d'une grille spécifique.  *  * @param nomGrille le nom de la grille  * @return la liste des positions de traits  */  public List<PositionTrait> getListeTrait(String nomGrille) {  return this.grilles.get(nomGrille).getListePositionTrait();  }  /**  * @return la grille par défaut  */  public SaveGrille getGrille() {  return grille;  }  /**  * @return la map de toutes les grilles (nom -> grille)  */  public Map<String, SaveGrille> getGrilles() {  return grilles;  }  /**  * @return les techniques chargées  */  public SaveTechnique getTechnique() {  return technique;  }  /**  * @return la sauvegarde globale  */  public SaveGlobal getSaveGlobal() {  return saveGlobal;  }  /**  * @return le chemin de base des fichiers  */  public String getBasePath() {  return basePath;  }  /**  * @return la liste des scores CSV  */  public List<StructureCSV> getScores() {  return scores == null ? Collections.emptyList() : scores;  }  /**  * Ajoute un score à la liste.  *  * @param score le score à ajouter  */  public void ajouterScore(StructureCSV score) {  if (score == null) {  return;  }  if (scores == null || scores == Collections.<StructureCSV>emptyList()) {  scores = new ArrayList<>();  }  scores.add(score);  }  /**  * Affiche le contenu d'une sauvegarde par son ID (debug).  *  * @param idUtilisateur l'identifiant de la sauvegarde  */  public void afficherContenuUtilisateurParId(int idUtilisateur) {  savePartieLienJoueur partie = chercherSauvegardeParId(idUtilisateur);  if (partie == null) {  System.out.println("Aucune sauvegarde trouvée pour l'id: " + idUtilisateur);  return;  }  System.out.println("Sauvegarde trouvée pour l'id: " + idUtilisateur);  System.out.println("Pseudo: " + partie.getPseudo());  System.out.println("Grille: " + partie.getPath());  var detaille = partie.getDetailleSave();  if (detaille == null) {  System.out.println("Aucun détail de partie disponible.");  return;  }  System.out.println("Chronometre: " + detaille.getChronometre());  System.out.println("Nb aides: " + detaille.getNbAides());  List<PositionTrait> etatGrille = detaille.getEtatGrille();  if (etatGrille == null || etatGrille.isEmpty()) {  System.out.println("Etat de grille vide.");  return;  }  System.out.println("Etat de grille:");  for (PositionTrait trait : etatGrille) {  if (trait == null) {  continue;  }  System.out.println("- position=" + trait.getPositionTrait() + ", etat=" + trait.getEtatTrait());  }  }  /**  * Recherche une sauvegarde par son identifiant.  *  * @param idUtilisateur l'identifiant de la sauvegarde  * @return la sauvegarde trouvée, ou null  */  public savePartieLienJoueur chercherSauvegardeParId(int idUtilisateur) {  return rechercheSave.chercherSauvegardeParId(saveGlobal, idUtilisateur);  }  /**  * Affiche toutes les données chargées (debug).  */  @Override  public String toString() {  this.afficherGrille(this.grilles.keySet().stream().findFirst().orElse("Grille par défaut"), this.grilles.values().stream().findFirst().orElse(grille));  this.afficherTechn();  System.out.println("\n\nAffichage en JSON:");  this.affichertoJson();  return "Affichage de la grille et des techniques terminé.";  }  /**  * Récupère toutes les grilles d'un niveau de difficulté donné.  *  * @param nvDifficulte le niveau de difficulté (0=facile, 1=moyen, 2=difficile)  * @return la liste des grilles correspondantes  */  public List<SaveGrille> getGrillesNv(int nvDifficulte) {  return grilles.entrySet().stream()  .filter(entry -> entry.getValue() != null && entry.getValue().getNvGrille() == nvDifficulte)  .map(Map.Entry::getValue)  .toList();  } } /**  * Singleton qui charge et gère les descriptions détaillées des techniques depuis un fichier JSON.  * Ce chargeur permet d'accéder rapidement aux descriptions complètes des techniques de résolution  * pour affichage dans l'interface utilisateur ou le menu "Techniques".  *  * @author Enzo Desfaudais (B0rno)  * @version 1.0  */ public static class LoadTechniqueJson {  private static LoadTechniqueJson instance;  private Map<String, String> techniqueDescriptions;  private LoadTechniqueJson() {  techniqueDescriptions = new HashMap<>();  chargerJson();  }  /**  * Retourne l'instance unique du chargeur de techniques.  * Si l'instance n'existe pas encore, elle est créée et le JSON est chargé automatiquement.  *  * @return l'instance unique de LoadTechniqueJson  */  public static LoadTechniqueJson getInstance() {  if (instance == null) {  instance = new LoadTechniqueJson();  }  return instance;  }  /**  * Charge le fichier JSON contenant toutes les techniques et remplit la Map techniqueDescriptions.  * Le fichier doit se trouver dans /technique.json avec la structure :  * stockage_langague > contenu > techniqueParsNv > techniques.  * En cas d'erreur de lecture, la stacktrace est affichée.  */  private void chargerJson() {  try (InputStreamReader reader = new InputStreamReader(getClass()  .getResourceAsStream("/technique.json"))) {  Gson gson = new Gson();  JsonObject root = gson.fromJson(reader, JsonObject.class);  JsonArray stockage_langague = root.getAsJsonArray("stockage_langague");  JsonObject firstJsonObject = stockage_langague.get(0).getAsJsonObject();  JsonArray contenu = firstJsonObject.getAsJsonArray("contenu");  for (int i = 0; i < contenu.size(); i++) {  JsonObject nvDificulte = contenu.get(i).getAsJsonObject();  JsonArray techniqueParsNv = nvDificulte.getAsJsonArray("techniqueParsNv");  for(int j = 0; j< techniqueParsNv.size();j++){  JsonObject technique = techniqueParsNv.get(j).getAsJsonObject();  String nom = technique.get("name").getAsString();  String description = technique.get("description").getAsString();  techniqueDescriptions.put(nom, description);  }  }  } catch (Exception e) {  e.printStackTrace();  }  }  /**  * Récupère la description détaillée d'une technique à partir de son nom.  *  * @param nomTechnique le nom exact de la technique tel qu'il apparaît dans le JSON  * @return la description complète de la technique, ou "Description non disponible" si non trouvée  */  public String getDescription(String nomTechnique) {  return techniqueDescriptions.getOrDefault(nomTechnique, "Description non disponible");  } } /**  * Technique : Boucle atteignant un 1  * Détecte les situations où un segment de la boucle arrive perpendiculairement sur  * l'un des sommets d'une case '1'. Cette configuration force la boucle à ne pas emprunter  * les deux côtés du '1' qui ne touchent pas ce sommet.  * Pattern de base de SlitherLink pour la continuité du chemin.  *  * @author Lucas Abeka-Doth (lucasabeka)  * @version 1.0  */ public static class BoucleSur1 implements StrategieAide {  public BoucleSur1() {}  private static final String NOM = "Boucle atteignant un 1";  /**  * Vérifie si cette technique peut être appliquée sur la matrice.  * Cherche un trait plein arrivant sur le coin d'un 1 depuis l'extérieur,  * ce qui permet de déduire les croix opposés de cette case.  *  * @param m la matrice du jeu à analyser  * @return true si des croix peuvent être déduits, false sinon  */  @Override  public boolean estApplicable(Matrice m) {  for (int i = 0; i < m.getHauteur(); i++) {  for (int j = 0; j < m.getLargeur(); j++) {  Case c = m.getCase(i, j);  /* On cible uniquement les cases contenant un 1 */  if (c != null && c.getNumero() == 1) {  /* Test coin haut-gauche (Nord-Ouest) */  /* Si un trait arrive de la gauche ou du haut vers ce coin */  if (estPlein(m, i, j - 1, true) || estPlein(m, i - 1, j, false)) {  /* Alors les murs opposés (droite : 2 et bas : 3) ne peuvent pas être tracés */  if (c.getTrait(2).getEtat() == ValeurTrait.VIDE ||  c.getTrait(3).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  /* Test haut-droite (Nord-Est) */  /* Si un trait arrive de la droite ou du haut vers ce coin */  if (estPlein(m, i, j + 1, true) || estPlein(m, i - 1, j + 1, false)) {  /* Alors les murs opposés (gauche : 1 et bas : 3) ne peuvent pas être tracés */  if (c.getTrait(1).getEtat() == ValeurTrait.VIDE ||  c.getTrait(3).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  /* Test bas-gauche (Sud-Ouest) */  /* Si un trait arrive de la gauche ou du bas vers ce coin */  if (estPlein(m, i + 1, j - 1, true) || estPlein(m, i + 1, j, false)) {  /* Alors les murs opposés (haut : 0 et droite : 2) ne peuvent pas être tracés */  if (c.getTrait(0).getEtat() == ValeurTrait.VIDE ||  c.getTrait(2).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  /* Test bas-droite (Sud-Est) */  /* Si un trait arrive de la droite ou du bas vers ce coin */  if (estPlein(m, i + 1, j + 1, true) || estPlein(m, i + 1, j + 1, false)) {  /* Alors les murs opposés (haut : 0 et gauche : 1) ne peuvent pas être tracés */  if (c.getTrait(0).getEtat() == ValeurTrait.VIDE ||  c.getTrait(1).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  }  }  }  return false;  }  /**  * Vérifie si un trait est "Plein" sans sortir des limites de la grille.  *  * @param m la matrice du jeu contenant l'état actuel des traits  * @param ligne l'indice de la ligne où se situe le trait  * @param col l'indice de la colonne où se situe le trait  * @param horizontal vrai (true) si on teste un trait horizontal, faux (false) pour un trait vertical  * @return vrai (true) si le trait existe et qu'il est marqué comme "PLEIN", faux (false) sinon  */  private boolean estPlein(Matrice m, int ligne, int col, boolean horizontal) {  if (horizontal) {  if (ligne < 0 || ligne > m.getHauteur() || col < 0 || col >= m.getLargeur()) return false;  Case c = m.getCase(ligne, col);  return (c != null && c.getTrait(0).getEtat() == ValeurTrait.PLEIN);  } else {  if (ligne < 0 || ligne >= m.getHauteur() || col < 0 || col > m.getLargeur()) return false;  Case c = m.getCase(ligne, col);  return (c != null && c.getTrait(1).getEtat() == ValeurTrait.PLEIN);  }  }  /**  * Trouve et retourne une aide basée sur cette technique.  * Charge la description complète depuis le JSON et crée un objet Aide.  *  * @param m la matrice du jeu à analyser  * @return une aide avec le nom et la description de la technique, ou null si non applicable  */  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  /**  * Retourne le nom de cette technique.  *  * @return le nom "Boucle atteignant un 1"  */  @Override  public String getNom() {  return NOM;  } } /**  * Technique: Deux 3 en diagonale  * Parcourt la matrice pour vérifier s'il y a deux '3' en diagonale.  * L'aide est applicable s'il manque encore des traits sur les bords extérieurs de ces deux '3'.  */ public static class Deux3EnDiagonale implements StrategieAide {  public Deux3EnDiagonale() {}  private static final String NOM = "Deux 3 en diagonale";  /**  * Vérifie si l'aide "Deux 3 en diagonale" est applicable.  * @param m La matrice du jeu  * @return true si l'aide est applicable  */  @Override  public boolean estApplicable(Matrice m) {  for (int i = 0; i < m.getHauteur(); i++) {  for (int j = 0; j < m.getLargeur(); j++) {  Case c = m.getCase(i, j);  if (c != null && c.getNumero() == 3) {  /* La diagonale est orientée Haut-Gauche vers Bas-Droite */  Case cDiagBD = m.getCase(i + 1, j + 1);  if (cDiagBD != null && cDiagBD.getNumero() == 3) {  /* Pour la case (i,j), les traits Haut (0) et Gauche (1) doivent être pleins */  /* Pour la case en Bas-Droite, les traits Bas (3) et Droite (2) doivent être pleins */  if (c.getTrait(0).getEtat() == ValeurTrait.VIDE ||   c.getTrait(1).getEtat() == ValeurTrait.VIDE ||  cDiagBD.getTrait(3).getEtat() == ValeurTrait.VIDE ||  cDiagBD.getTrait(2).getEtat() == ValeurTrait.VIDE) {  return true;  }  }  /* La diagonale est orientée Haut-Droite vers Bas-Gauche */  Case cDiagBG = m.getCase(i + 1, j - 1);  if (cDiagBG != null && cDiagBG.getNumero() == 3) {  /* Pour la case (i,j), les traits Haut (0) et Droite (2) doivent être pleins */  /* Pour la case en Bas-Gauche, les traits Bas (3) et Gauche (1) doivent être pleins */  if (c.getTrait(0).getEtat() == ValeurTrait.VIDE ||   c.getTrait(2).getEtat() == ValeurTrait.VIDE ||  cDiagBG.getTrait(3).getEtat() == ValeurTrait.VIDE ||  cDiagBG.getTrait(1).getEtat() == ValeurTrait.VIDE) {  return true;  }  }    }  }  }  return false;  }  @Override  public Aide trouverAide(Matrice m) {  if (estApplicable(m)) {  String technique = LoadTechniqueJson.getInstance().getDescription(NOM);  return new Aide(NOM, technique);  }  return null;  }  @Override  public String getNom() {  return NOM;  } } public static class Partie extends ChangementFenetre implements PartieObserver {  public Partie() {}  protected PartieHelper moteurJeu;  public static String dernierMode = "libre";  private static String grilleEnCours = null;  public static String nomGrille = "tutoriel";  @FXML  private VBox zoneJeu;   protected StackPane[][] matriceCases;  /* --- MÉTHODES STATIQUES (Rétablies pour corriger les erreurs de compilation) --- */    public static String getGrilleEnCours() {  return grilleEnCours;  }  public static void setGrilleEnCours(String grille) {  grilleEnCours = grille;  }  public static void setDernierMode(String mode) {  dernierMode = mode;  }  public static String getDernierMode() {  return dernierMode;  }  /* --- LOGIQUE DE JEU --- */  @Override  public void onVictoire(Score score) {  App.changerVue("finPartieLibre");  }  @Override  public void onEtatChange(EtatPartie etat) {}  @FXML  protected Label labelAide;   @Override  public void onAideUtilisee() {  if (moteurJeu != null) {  Aide aide = moteurJeu.getAideEnCours();  if (aide != null) {  /* Afficher nom + description */  String texte = aide.getNom() + "\n\n" + aide.getTechniqueLiee();  labelAide.setText(texte);  } else {  labelAide.setText("Aucune aide disponible");  }  }  }  @FXML  public void menuPause(ActionEvent event) {  changerFenetre(event, "pause");  }  @FXML  private void aide(ActionEvent event) {  if(moteurJeu != null) {  moteurJeu.utiliserAide();  }  }  public void initialiserPartie(String grille) {  initialiserPartie(grille, false);  }  public void initialiserPartie(String grille, boolean recommencer) {  setDernierMode("libre");  setGrilleEnCours(grille);  Matrice mat = Matrice.loadGrille(grille);  if (mat == null) {  System.err.println("Erreur : la matrice n'a pas pu être chargée pour la grille " + grille);  return;  }  /* Lecture de la sauvegarde ici, si elle n'est pas lu, créer la sauvegarde */  Partie.nomGrille = grille;  if (!recommencer) {  boolean loaded = mat.loadSave(Pseudo.nomJoueur, "./save/saveGrille/" + grille + ".json", false);  if(!loaded){  /* Creer la référence de sauvegarde ici */  SaveHelper saveHelper = SaveHelper.getInstance();  saveHelper.ajouterPartieLibre(LoadSave.getInstance(""), Pseudo.nomJoueur, grille);  SaveManager saveManager = new SaveManager(LoadSave.getInstance(""));  saveManager.actualiserSaveGlobal();  }  } else {  /* Si on recommence, réinitialiser la sauvegarde existante */  LoadSave save = LoadSave.getInstance("");  save.rechargerSaveGlobal();  var sauvegarde = rechercheSave.trouverSauvegardeParPseudoEtPath(  Pseudo.nomJoueur,  "./save/saveGrille/" + grille + ".json"  );  if (sauvegarde != null && sauvegarde.getId() != null) {  /* Réinitialiser le détail de la sauvegarde */  DetailleSavePartie nouveauDetail = DetailleSavePartie.create(new ArrayList<>(), 0, 0);  nouveauDetail.setNameClass(sauvegarde.getId().toString());  sauvegarde.setDetailleSave(nouveauDetail);  SaveManager saveManager = new SaveManager(save);  saveManager.updateSaveFichierId(sauvegarde.getId());  saveManager.actualiserSaveGlobal();  System.out.println("[DEBUG] Sauvegarde réinitialisée pour recommencer (mode libre)");  }  }  this.moteurJeu = new PartieHelper(new Profil(Pseudo.nomJoueur), mat, 3, new Score());  this.moteurJeu.ajouterObserver(this);  chargerMatrice(mat);  this.moteurJeu.demarrer();  }  public void sauvegarderProgressionCourante() {  if (moteurJeu == null || moteurJeu.getScore() == null) {  return;  }  if ("tutoriel".equalsIgnoreCase(getDernierMode())) {  return;  }  String grille = getGrilleEnCours();  if (grille == null || grille.isBlank()) {  grille = nomGrille;  }  if (grille == null || grille.isBlank()) {  return;  }  String pseudo = moteurJeu.getProfil() != null ? moteurJeu.getProfil().getPseudo() : Pseudo.nomJoueur;  if (pseudo == null || pseudo.isBlank()) {  return;  }  int chrono = (int) moteurJeu.getScore().getDureeEnSecondes();  int nbAides = moteurJeu.getScore().getNbAidesUtilisees();  String pathGrille = "./save/saveGrille/" + grille + ".json";  LoadSave save = LoadSave.getInstance("");  SaveManager saveManager = new SaveManager(save);  var sauvegarde = rechercheSave.trouverSauvegardeParPseudoEtPath(pseudo, pathGrille);  if (sauvegarde == null) {  if ("aventure".equalsIgnoreCase(getDernierMode())) {  SaveHelper.ajouterPartieAventure(save, pseudo, grille);  } else {  SaveHelper.ajouterPartieLibre(save, pseudo, grille);  }  sauvegarde = rechercheSave.trouverSauvegardeParPseudoEtPath(pseudo, pathGrille);  }  if (sauvegarde == null || sauvegarde.getDetailleSave() == null) {  return;  }  DetailleSavePartie ancienDetail = sauvegarde.getDetailleSave();  /* Mise à jour uniquement du chrono et des aides */  /* L'état de la grille est déjà sauvegardé par Matrice.saveGrille() à chaque clic */  ancienDetail.setChronometre(chrono);  ancienDetail.setNbAides(nbAides);  Integer id = sauvegarde.getId();  if (id != null) {  saveManager.updateSaveFichierId(id);  saveManager.actualiserSaveGlobal();  }  }  private void genererPlateau(Matrice mat, int taille) {  this.matriceCases = new StackPane[taille][taille];  zoneJeu.getChildren().clear();  GridPane plateau = new GridPane();  plateau.setAlignment(Pos.CENTER);    int nbCellulesFX = taille * 2 + 1;  double tailleGrilleSouhaitee = 600.0;   double tailleUnite = tailleGrilleSouhaitee / (taille * 1.5);  int currentHorizontalDir = 0; /* 0 = NORD */  int currentVerticalDir = 1; /* 1 = OUEST */  for (int l = 0; l < nbCellulesFX; l++) {  /* Changement horizontal UNIQUEMENT quand l change et est pair */  if (l % 2 == 0 && l != 0) {  currentHorizontalDir = (currentHorizontalDir == 0) ? 3 : 0;  }  /* Reset vertical à chaque nouvelle ligne */  currentVerticalDir = 1;  for (int c = 0; c < nbCellulesFX; c++) {  if (l % 2 != 0 && c % 2 != 0) {  /* Case à chiffre */  StackPane caseChiffre = new StackPane();  caseChiffre.setPrefSize(tailleUnite, tailleUnite);   caseChiffre.setMinSize(tailleUnite, tailleUnite);  plateau.add(caseChiffre, c, l);  matriceCases[(l-1)/2][(c-1)/2] = caseChiffre;  } else if ((l % 2 == 0 && c % 2 != 0) || (l % 2 != 0 && c % 2 == 0)) {  /* Trait (Horizontal ou Vertical) */  boolean estHorizontal = (l % 2 == 0);  int ligneCase;  int colonneCase;  int direction;  if (estHorizontal) {  direction = currentHorizontalDir;  colonneCase = (c - 1) / 2;  if (direction == 0) {  /* NORD → case en dessous */  ligneCase = l / 2;  } else {  /* SUD → case au dessus */  ligneCase = (l / 2) - 1;  }  if (ligneCase < 0) ligneCase = 0;  if (ligneCase >= taille) ligneCase = taille - 1;  } else {  direction = currentVerticalDir;  /* alternance verticale à CHAQUE trait */  currentVerticalDir = (currentVerticalDir == 1) ? 2 : 1;  ligneCase = (l - 1) / 2;  if (direction == 1) {  /* OUEST → case à droite */  colonneCase = c / 2;  } else {  /* EST → case à gauche */  colonneCase = (c / 2) - 1;  }  if (colonneCase < 0) colonneCase = 0;  if (colonneCase >= taille) colonneCase = taille - 1;  }  Trait traitLogique = new Trait();  traitLogique.setTrait(mat.getCase(ligneCase, colonneCase).getTrait(direction).getEtat());    /* On récupère le StackPane contenant le rectangle + la croix */  Node traitGraphique = creerTraitGraphique(estHorizontal, traitLogique, tailleUnite, l, c);  plateau.add(traitGraphique, c, l);  } else {  /* Point d'intersection */  Circle point = new Circle(tailleUnite * 0.15, Color.DARKGREY);  plateau.add(point, c, l);  }  }  }  zoneJeu.getChildren().add(plateau);  }  private Node creerTraitGraphique(boolean horizontal, Trait logique, double tailleUnite, int l, int c) {  double longTrait = tailleUnite;   double epaisTrait = tailleUnite * 0.2;     /* 1. Le Rectangle (base cliquable) */  Rectangle rect = new Rectangle(  horizontal ? longTrait : epaisTrait,   horizontal ? epaisTrait : longTrait  );  rect.setFill(Color.TRANSPARENT);  /* 2. La Croix dessinée (2 lignes rouges) */  /* On définit la taille de la croix pour qu'elle soit bien visible */  double tailleC = epaisTrait * 0.4; /* Ajuste ici pour agrandir/réduire la croix */    Line l1 = new Line(-tailleC, -tailleC, tailleC, tailleC);  Line l2 = new Line(tailleC, -tailleC, -tailleC, tailleC);    l1.setStroke(Color.RED);  l1.setStrokeWidth(2.5); /* Épaisseur des traits de la croix */  l2.setStroke(Color.RED);  l2.setStrokeWidth(2.5);  /* On groupe les lignes. Le StackPane les centrera automatiquement. */  Group dessinCroix = new Group(l1, l2);  dessinCroix.setVisible(false);  dessinCroix.setMouseTransparent(true); /* Pour que le clic passe au rectangle */  /* 3. Le conteneur StackPane pour empiler rect + croix */  StackPane conteneur = new StackPane();  conteneur.getChildren().addAll(rect, dessinCroix);  conteneur.setCursor(javafx.scene.Cursor.HAND);    /* Logique de rafraîchissement */  Runnable rafraichirVisuel = () -> {  switch (logique.getEtat()) {  case PLEIN:  rect.setFill(Color.BLACK);  dessinCroix.setVisible(false);  break;  case CROIX:  rect.setFill(Color.TRANSPARENT);  dessinCroix.setVisible(true);  break;  case VIDE:  rect.setFill(Color.TRANSPARENT);  dessinCroix.setVisible(false);  break;  }  };    /* Événements */  conteneur.setOnMousePressed(event -> {  logique.etatSuivant();  rafraichirVisuel.run();  communiquerAuMoteur(l, c, horizontal);  });  conteneur.setOnDragDetected(event -> conteneur.startFullDrag());  conteneur.setOnMouseDragEntered(event -> {  if (logique.getEtat() == ValeurTrait.VIDE) {  logique.etatSuivant();  rafraichirVisuel.run();  communiquerAuMoteur(l, c, horizontal);  }  });  rafraichirVisuel.run();  return conteneur;  }    private void communiquerAuMoteur(int l, int c, boolean horizontal) {  if (moteurJeu != null) {  int ligneM, colM, dir;  if (horizontal) {  ligneM = l / 2;  colM = (c - 1) / 2;  dir = 0;  if (ligneM >= moteurJeu.getMatrice().getHauteur()) { ligneM--; dir = 3; }  } else {  ligneM = (l - 1) / 2;  colM = c / 2;  dir = 1;  if (colM >= moteurJeu.getMatrice().getLargeur()) { colM--; dir = 2; }  }  moteurJeu.jouerCoup(ligneM, colM, dir);  }  }  public Matrice chargerMatrice(Matrice mat){  int taille = mat.getHauteur();  genererPlateau(mat, taille);  for (int ligne = 0; ligne < taille; ligne++) {  for (int col = 0; col < taille; col++) {  int valeur = mat.getCase(ligne, col).getNumero();  if (valeur != -1) {  if (ligne >= 0 && ligne < taille && col >= 0 && col < taille) {  StackPane caseCible = matriceCases[ligne][col];  Label labelChiffre = new Label(String.valueOf(valeur));  labelChiffre.setStyle("-fx-font-size: 20px; -fx-font-weight: bold; -fx-text-fill: #2f2f2f;");  caseCible.getChildren().setAll(labelChiffre);  }   }  }  }  return mat;  } } }